// Saveur N°5 — Recettes Asie (210 recettes)
RECIPES.push(
{id:"AS001",co:"Asie",cat:"Plat",sous:"Bouillon / Soupe – Japon",nom:"Ramen Tonkotsu (Bouillon de Porc Crémeux)",chef:"Tradition Fukuoka / Kyushu – Japon",bp:4,prep:60,cui:300,diff:4,qual:4,ig:[["Os de porc pieds + dos pour bouillon",2000,"g"],["Couenne de porc pour bouillon",500,"g"],["Ail pour bouillon",10,"gousses"],["Oignon brûlé à sec pour bouillon",1,"pièce"],["Gingembre pour bouillon",5,"cm"],["Filet de porc roulé ficelé pour chashu",600,"g"],["Sauce soja pour chashu",10,"cl"],["Mirin pour chashu",10,"cl"],["Sake pour chashu",5,"cl"],["Sucre pour chashu",50,"g"],["Œufs marinés",4,"pièces"],["Nouilles ramen fraîches",400,"g"],["Feuilles nori",4,"pièces"],["Oignons verts ciselés",2,"tiges"],["Huile de sésame grillé",2,"cc"]],et:"Bouillon (J-1) :\n1. Blanchir les os dans l'eau bouillante 10 min, rincer soigneusement.\n2. Recouvrir d'eau froide (4 L) avec ail, oignon brûlé, gingembre. Porter à ébullition FORTE et maintenir à gros bouillon 4–5 h. Le bouillon doit devenir crémeux et blanc comme du lait.\n3. Filtrer. Assaisonner en sel. Réserver.\nChashu :\n4. Faire revenir le rouleau de porc sur toutes les faces.\n5. Mijoter dans soja + mirin + sake + sucre 1 h à feu doux. Refroidir dans la marinade. Trancher finement.\nÅufs ramen :\n6. Mollets 6 min 30, eau froide, écaler. Mariner 12 h dans soja + mirin + eau (2+1+1).\nAssemblage :\n7. Cuire les nouilles 2–3 min. Chauffer le bouillon tonkotsu, verser dans les bols.\n8. Disposer nouilles + tranches de chashu + œuf coupé en 2 + nori + menma + oignons verts. Filet d'huile de sésame.",vin:"Bière Sapporo ou saké junmai ginjo ; thé vert gyokuro",notes:"Le tonkotsu exige un bouillon à gros bouillon pour émulsionner les graisses osseuses. Préparer obligatoirement la veille."},
{id:"AS002",co:"Asie",cat:"Plat",sous:"Poisson / Mer – Japon / France",nom:"Sashimi de Thon Rouge à l'Huile de Truffe",chef:"Alain Ducasse (fusion France–Japon)",bp:4,prep:20,cui:0,diff:3,qual:4,ig:[["Thon rouge de ligne qualité sashimi",400,"g"],["Huile de truffe noire",4,"cs"],["Sauce soja Tamari",2,"cs"],["Jus de yuzu",1,"cs"],["Fleur de sel de Guérande",4,"g"],["Poivre de Sichuan moulu",1,"pincée"],["Shiso rouge en chiffonnade",8,"feuilles"],["Gingembre mariné",40,"g"],["Wasabi frais râpé",20,"g"]],et:"1. Placer le thon 30 min au congélateur pour faciliter la découpe (sans le congeler).\n2. Avec un couteau japonais Yanagiba, trancher en sashimi de 5–7 mm en un seul mouvement de traction.\n3. Mélanger : huile de truffe + tamari + jus de yuzu.\n4. Dresser les tranches en éventail ou rosace sur assiette froide.\n5. Napper délicatement du mélange huile-truffe-yuzu.\n6. Assaisonner de fleur de sel et poivre de Sichuan.\n7. Garnir de shiso, wasabi frais façonné, lamelles de gingembre mariné.",vin:"Sancerre blanc Vacheron ou Champagne Blanc de Blancs Grand Cru du Mesnil",notes:"La qualité du thon est absolument déterminante. Le couteau doit être parfaitement affûté. Ne jamais acheter du thon congelé industriel."},
{id:"AS003",co:"Asie",cat:"Plat",sous:"Tempura / Fritures – Japon",nom:"Tempura de Crevettes et Légumes",chef:"Tradition japonaise",bp:4,prep:30,cui:20,diff:3,qual:4,ig:[["Grosses crevettes tigrées décortiquées queue intacte",8,"pièces"],["Courgettes",2,"pièces"],["Patates douces en tranches fines",2,"pièces"],["Champignons shiitake",4,"pièces"],["Feuilles de shiso",4,"pièces"],["Jaune d'œuf pour pâte tempura",1,"pièce"],["Eau glacée pour pâte tempura",24,"cl"],["Farine T45 tamisée pour pâte tempura",120,"g"],["Dashi pour sauce tentsuyu",20,"cl"],["Sauce soja pour sauce tentsuyu",5,"cl"],["Mirin pour sauce tentsuyu",5,"cl"]],et:"1. Préparer la sauce tentsuyu, réserver au chaud.\n2. Inciser légèrement le ventre des crevettes. Sécher tous les ingrédients sur papier absorbant.\n3. Pâte tempura : mélanger jaune d'œuf + eau glacée d'un geste. Ajouter la farine en une fois, mélanger 3–4 fois SEULEMENT avec des baguettes (des grumeaux doivent rester). Garder sur glace.\n4. Chauffer l'huile à 180°C. Tremper chaque ingrédient dans la pâte et plonger dans l'huile. Frire par petites quantités.\n5. Les légumes : 2–3 min, les crevettes : 2 min.\n6. Égoutter sur grille. Servir IMMÉDIATEMENT avec sauce tentsuyu + daikon râpé + gingembre.",vin:"Saké junmai daiginjo très frais ou Muscadet de Sèvre et Maine sur Lie",notes:"Le secret de la pâte tempura : eau GLACÉE + ne jamais trop mélanger. Les grumeaux sont normaux et souhaitables."},
{id:"AS004",co:"Asie",cat:"Plat",sous:"Canard / Volaille – Chine",nom:"Canard Laqué de Pékin",chef:"Tradition de Pékin (Beijing) – Chine",bp:6,prep:1440,cui:90,diff:4,qual:4,ig:[["Canard de Pékin entier",2500,"g"],["Sirop de maltose ou miel pour laque",4,"cs"],["Sauce soja pour laque",2,"cs"],["Vinaigre de riz pour laque",1,"cs"],["Shaoxing vin de riz pour laque",1,"cs"],["Farine T45 pour crêpes",200,"g"],["Eau bouillante pour crêpes",10,"cl"],["Huile de sésame pour crêpes",2,"cc"],["Pâte hoisin pour service",6,"cs"],["Oignons verts en julienne pour service",4,"tiges"],["Concombre en bâtonnets pour service",1,"pièce"]],et:"1. Gonfler le canard : desserrer la peau de la poitrine avec les doigts ou souffler de l'air entre peau et chair pour les séparer.\n2. Blanchir le canard entier dans l'eau bouillante 1 min. Égoutter. Sécher soigneusement.\n3. Badigeonner le canard de laque (maltose + soja + vinaigre + Shaoxing). Répéter 2–3 fois toutes les 6 h.\n4. Suspendre le canard dans un endroit aéré ou réfrigérateur sans couvrir pendant 24 h minimum (jusqu'à 48 h). La peau doit être complètement sèche avant la cuisson.\n5. Enfourner à 220°C pendant 20 min, puis réduire à 180°C pendant 50–60 min en retournant à mi-cuisson.\n6. Crêpes chinoises : mélanger farine + eau bouillante + huile de sésame, pétrir jusqu'à pâte lisse, reposer 30 min, étaler très finement, cuire à sec à la poêle 1 min par face.\n7. Service : trancher la peau croustillante séparément de la chair. Servir dans les crêpes avec pâte hoisin + oignons verts + concombre.",vin:"Thé pu-erh aged ou bière Tsingtao fraîche",notes:"Le séchage de la peau pendant 24–48 h est l'étape la plus critique. La peau doit être parfaitement sèche avant la cuisson pour obtenir le croustillant légendaire."},
{id:"AS005",co:"Asie",cat:"Plat",sous:"Curry / Masala – Inde",nom:"Poulet Tikka Masala",chef:"Tradition indienne Punjab",bp:4,prep:30,cui:35,diff:3,qual:4,ig:[["Poulet blancs et cuisses désossées",800,"g"],["Yaourt entier pour marinade",150,"g"],["Garam masala pour marinade",2,"cc"],["Curcuma pour marinade",1,"cc"],["Paprika fumé pour marinade",1,"cc"],["Cumin en poudre pour marinade",1,"cc"],["Jus de citron pour marinade",2,"cs"],["Oignons pour sauce",2,"pièces"],["Ail pour sauce",4,"gousses"],["Gingembre frais pour sauce",3,"cm"],["Tomates concassées pour sauce",400,"g"],["Beurre ghee pour sauce",2,"cs"],["Crème fraîche pour sauce",15,"cl"],["Garam masala pour sauce",1,"cc"],["Coriandre fraîche",1,"bouquet"]],et:"1. Mariner le poulet découpé en cubes dans le mélange yaourt + épices au moins 4 h (idéalement 12 h).\n2. Faire griller le poulet mariné sous le gril du four ou à la poêle très chaude jusqu'à belle coloration (tikka). Réserver.\n3. Sauce masala : faire fondre le ghee dans une casserole à fond épais. Faire revenir les oignons finement hachés jusqu'à coloration blonde (12–15 min). Ajouter ail + gingembre râpés, cuire 2 min.\n4. Ajouter les tomates concassées + garam masala + cumin. Frémir 10–12 min jusqu'à concentration. Mixer si désiré.\n5. Ajouter la crème fraîche, frémir 5 min. Incorporer les morceaux de poulet grillé. Frémir encore 5 min.\n6. Servir parsemé de coriandre fraîche avec du riz basmati ou du pain naan.",vin:"Riesling Alsace Grand Cru ou bière Cobra indienne ; lassi à la mangue",notes:"La cuisson du poulet en 2 temps (grillade puis sauce) est la clé du tikka masala authentique. Le ghee (beurre clarifié indien) est plus aromatique que le beurre normal."},
{id:"AS006",co:"Asie",cat:"Entrée",sous:"Raviolis / Dim Sum – Chine",nom:"Wonton Soupe (Raviolis de Porc au Bouillon)",chef:"Tradition cantonaise – Chine",bp:4,prep:45,cui:15,diff:3,qual:4,ig:[["Feuilles de wonton",24,"pièces"],["Porc haché pour farce",300,"g"],["Crevettes décortiquées hachées pour farce",150,"g"],["Sauce soja pour farce",2,"cs"],["Huile de sésame pour farce",1,"cs"],["Sucre pour farce",1,"cc"],["Blanc d'œuf pour farce",1,"pièce"],["Gingembre râpé pour farce",2,"cm"],["Oignons verts pour farce",2,"tiges"],["Bouillon de poule maison",100,"cl"],["Gingembre tranché pour bouillon",3,"cm"],["Étoiles de badiane pour bouillon",2,"pièces"],["Sauce soja pour bouillon",2,"cs"],["Huile de sésame pour bouillon",1,"cs"]],et:"1. Farce : mélanger porc haché + crevettes hachées + sauce soja + huile de sésame + sucre + blanc d'œuf + gingembre râpé + oignons verts ciselés. Mélanger vigoureusement dans un seul sens jusqu'à consistance collante et élastique.\n2. Poser 1 cc de farce au centre de chaque feuille de wonton. Humidifier les bords, replier en triangle, puis ramener les deux coins vers le haut et coller ensemble en forme de bonnet.\n3. Bouillon : porter à frémissement le bouillon de poule avec gingembre + badiane. Infuser 10 min. Filtrer. Assaisonner avec sauce soja + huile de sésame.\n4. Plonger les wontons dans le bouillon frémissant 3–4 min (ils remontent à la surface quand ils sont cuits).\n5. Répartir les wontons dans des bols, verser le bouillon chaud. Garnir d'oignons verts ciselés et de poivre blanc.",vin:"Thé vert chinois Dragonwell Longjing ou thé au jasmin",notes:"Mélanger la farce dans un seul sens est la clé de la texture élastique. Les wontons crus peuvent être congelés 3 mois."},
{id:"AS013",co:"Asie",cat:"Plat",sous:"Curry",nom:"Curry de Crevettes au Lait de Coco",chef:"Tradition sri-lankaise",bp:4,prep:20,cui:20,diff:2,qual:4,ig:[["Crevettes tigrées décortiquées",600,"g"],["Lait de coco",40,"cl"],["Oignons",2,"pièces"],["Ail gingembre frais",1,"qs"],["Poudre de curry de Madras",2,"cs"],["Piment vert frais",1,"pièce"],["Feuilles de curry fraîches",8,"pièces"],["Tomates cerises",200,"g"],["Huile de coco",3,"cs"]],et:"1. Chauffer l'huile de coco. Frire les feuilles de curry 30 sec.\n2. Ajouter oignons + ail + gingembre + piment. Suer 5 min.\n3. Incorporer la poudre de curry. Cuire 2 min en remuant.\n4. Ajouter lait de coco + tomates cerises. Frémir 8 min.\n5. Ajouter les crevettes. Cuire 4-5 min jusqu'à rosées. Servir avec riz basmati ou pain roti.",vin:"Gewurztraminer demi-sec ou bière de riz",notes:"Les feuilles de curry fraîches sont irremplaçables pour l'arôme authentique."},
{id:"AS014",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Rendang de Boeuf",chef:"Tradition malaise et indonésienne",bp:6,prep:30,cui:120,diff:3,qual:4,ig:[["Boeuf paleron en gros cubes",1000,"g"],["Lait de coco",80,"cl"],["Citronnelle",3,"tiges"],["Galanga",3,"cm"],["Feuilles kaffir lime",6,"pièces"],["Noix de coco râpée grillée (kerisik)",4,"cs"],["Piment rouge sec",6,"pièces"],["Échalotes",8,"pièces"],["Ail",4,"gousses"],["Curcuma",1,"cc"]],et:"1. Pâte aromatique : mixer piments séchés réhydratés + échalotes + ail + galanga + citronnelle + curcuma.\n2. Faire revenir la pâte dans l'huile 10 min jusqu'à très parfumée.\n3. Ajouter le boeuf, bien enrober. Ajouter lait de coco + kaffir lime.\n4. Cuire à feu moyen 1h30-2h en remuant régulièrement. Le liquide doit s'évaporer presque entièrement.\n5. En fin de cuisson, ajouter la noix de coco grillée (kerisik). Cuire encore 15 min jusqu'à la viande soit sèche et caramélisée.",vin:"Riesling Alsace ou bière Bintang froide",notes:"Le rendang authentique est sec, pas en sauce. Plus il cuit, meilleur il est."},
{id:"AS015",co:"Asie",cat:"Entrée",sous:"Dim Sum",nom:"Baozi (Brioches Vapeur Farcies)",chef:"Tradition cantonaise",bp:8,prep:90,cui:20,diff:3,qual:4,ig:[["Farine T55",400,"g"],["Levure sèche",5,"g"],["Sucre",20,"g"],["Lait tiède",20,"cl"],["Huile de sésame",1,"cs"],["Porc haché pour farce",300,"g"],["Chou chinois haché essoré",100,"g"],["Sauce soja",2,"cs"],["Sauce hoisin",2,"cs"],["Gingembre ail pour farce",1,"qs"]],et:"Pâte :\n1. Mélanger levure + sucre + lait tiède. Laisser mousser 10 min. Ajouter farine + huile sésame. Pétrir 10 min. Lever 1h.\nFarce :\n2. Mélanger porc + chou + soja + hoisin + gingembre + ail.\nAssemblage :\n3. Diviser la pâte en 16 boules. Étaler en disques. Déposer 1cs de farce au centre. Pincer en 15 plis pour former un dôme. Lever 20 min.\n4. Cuire à la vapeur sur papier sulfurisé 15-18 min.",vin:"Thé au jasmin ou thé pu-erh",notes:"Les plis nombreux et réguliers sont le signe du savoir-faire. La cuisson vapeur est indispensable."},
{id:"AS016",co:"Asie",cat:"Plat",sous:"Noodles",nom:"Bún Bò Huế (Soupe de Boeuf Épicée)",chef:"Tradition de Huế",bp:4,prep:30,cui:120,diff:3,qual:4,ig:[["Os de boeuf et porc",1500,"g"],["Jarret de boeuf",400,"g"],["Citronnelle",3,"tiges"],["Pâte de crevettes fermentées (mắm ruốc)",2,"cs"],["Piment rouge",3,"pièces"],["Vermicelles de riz épais",300,"g"],["Pousses de soja oignons verts herbes fraîches",1,"bouquet"],["Sauce de poisson",3,"cs"]],et:"1. Blanchir les os. Rincer soigneusement. Placer dans grande marmite avec 3L eau froide + citronnelle écrasée + sel.\n2. Frémir 2h à feu doux. Écumer régulièrement.\n3. Retirer le jarret, effilocher la viande.\n4. Assaisonner le bouillon : pâte de crevettes + sauce de poisson + sel + huile de piment.\n5. Cuire les vermicelles. Dans chaque bol : vermicelles + viande effilochée. Verser bouillon bouillant. Garnir de pousses de soja + herbes.",vin:"Bière 333 froide ou thé oolong",notes:"Plus relevé que le pho, le bún bò Huế est la fierté de la cuisine de Huế."},
{id:"AS017",co:"Asie",cat:"Plat",sous:"Riz",nom:"Nasi Goreng (Riz Frit Indonésien)",chef:"Tradition indonésienne",bp:4,prep:15,cui:15,diff:1,qual:4,ig:[["Riz cuit de la veille",600,"g"],["Crevettes ou poulet cuit",200,"g"],["Oeufs",4,"pièces"],["Oignons rouges",3,"pièces"],["Ail",3,"gousses"],["Kecap manis (sauce soja sucrée)",3,"cs"],["Pâte de chili sambal",2,"cs"],["Sauce de soja",2,"cs"],["Huile",4,"cs"]],et:"1. Chauffer le wok très chaud. Faire revenir oignons + ail dans l'huile.\n2. Ajouter crevettes ou poulet. Saisir rapidement.\n3. Pousser sur les côtés. Brouiller les oeufs au centre.\n4. Ajouter le riz froid (il doit grésiller). Mélanger énergiquement.\n5. Assaisonner kecap manis + sambal + sauce soja. Servir avec chips de crevettes (krupuk) + concombre.",vin:"Bière Bintang froide ou thé glacé",notes:"Le riz de la veille froid est indispensable - le riz frais donnerait une bouillie."},
{id:"AS018",co:"Asie",cat:"Plat",sous:"Agneau",nom:"Kabuli Pulao (Riz Afghaniez Pilaf)",chef:"Tradition afghane",bp:6,prep:30,cui:90,diff:3,qual:4,ig:[["Riz basmati",500,"g"],["Épaule d'agneau en gros morceaux",800,"g"],["Oignons",3,"pièces"],["Carottes en julienne",4,"pièces"],["Raisins secs",80,"g"],["Cardamome",6,"gousses"],["Cumin",1,"cc"],["Cannelle",1,"bâton"],["Bouillon d'agneau",80,"cl"],["Amandes effilées",60,"g"],["Eau de rose",1,"cs"]],et:"1. Dorer l'agneau dans l'huile. Ajouter oignons jusqu'à dorés. Ajouter épices + bouillon. Cuire 45 min. Retirer l'agneau, réserver le bouillon.\n2. Faire revenir carottes en julienne dans l'huile + raisins secs. Réserver.\n3. Cuire le riz à mi-cuisson dans le bouillon d'agneau.\n4. Dans une grande casserole : riz + agneau + carottes + raisins. Ajouter eau de rose.\n5. Couvrir hermétiquement. Cuire à feu très doux 20 min (dum cooking).",vin:"Thé afghan ou eau de rose diluée",notes:"Le dum cooking (cuisson à la vapeur fermée) est le secret du pulao parfumé."},
{id:"AS019",co:"Asie",cat:"Dessert",sous:"Mochi",nom:"Mochi Glacé Maison",chef:"Tradition japonaise",bp:8,prep:30,cui:5,diff:2,qual:4,ig:[["Farine de riz gluant (mochiko)",200,"g"],["Sucre",80,"g"],["Eau",18,"cl"],["Colorant alimentaire rose ou vert (optionnel)",1,"qs"],["Amidon de maïs pour le plan de travail",50,"g"],["Glace à la vanille ou matcha",400,"g"]],et:"1. Mélanger farine de riz + sucre + eau. Cuire au micro-ondes 3 min en remuant toutes les minutes jusqu'à pâte translucide et élastique (ou 15 min au bain-marie).\n2. Travailler la pâte sur surface abondamment saupoudrée d'amidon. Étaler à 3mm d'épaisseur.\n3. Découper des cercles de 10cm. Travailler vite (la pâte refroidit).\n4. Poser une boule de glace au centre de chaque cercle. Refermer en pinçant.\n5. Congeler 1h minimum.",vin:"Thé vert matcha frais",notes:"Travailler la pâte mochi quand elle est encore chaude. Elle est difficile à travailler froide."},
{id:"AS020",co:"Asie",cat:"Plat",sous:"Porc",nom:"Adobo de Porc Philippin",chef:"Tradition philippine",bp:6,prep:15,cui:60,diff:1,qual:4,ig:[["Porc échine en gros cubes",1000,"g"],["Sauce soja",8,"cs"],["Vinaigre de riz blanc",8,"cs"],["Ail",8,"gousses"],["Feuilles de laurier",4,"pièces"],["Poivre noir en grains",1,"cs"],["Sucre de canne",1,"cs"],["Huile",2,"cs"]],et:"1. Mélanger porc + sauce soja + vinaigre + ail écrasé + laurier + poivre + sucre dans une cocotte. Mariner 30 min minimum.\n2. Porter à ébullition à feu vif. Réduire à feu moyen-doux. Cuire à couvert 40 min.\n3. Retirer le couvercle. Cuire encore 15-20 min jusqu'à sauce réduite et sirupeuse.\n4. Optionnel : retirer la viande, la faire dorer dans l'huile pour la caraméliser.\n5. Servir sur riz blanc cuit à la vapeur.",vin:"Bière San Miguel froide ou vin de canne à sucre",notes:"L'adobo philippin est le plat national. La combinaison vinaigre + soja est sa signature unique."},
{id:"AS021",co:"Asie",cat:"Plat",sous:"Sushi",nom:"Chirashi Sushi (Riz Sushi Garni)",chef:"Tradition japonaise",bp:4,prep:40,cui:15,diff:2,qual:4,ig:[["Riz à sushi",400,"g"],["Vinaigre de riz",6,"cs"],["Sucre",2,"cs"],["Sel",1,"cc"],["Saumon sashimi qualité",150,"g"],["Thon sashimi qualité",150,"g"],["Oeufs de saumon ikura",60,"g"],["Concombre",1,"pièce"],["Avocat",1,"pièce"],["Nori en lamelles",2,"feuilles"],["Wasabi sauce soja",1,"qs"]],et:"1. Cuire le riz. Préparer le vinaigre de sushi : mélanger vinaigre + sucre + sel jusqu'à dissolution.\n2. Incorporer le vinaigre au riz chaud à l'aide d'une spatule en éventant. Laisser tiédir.\n3. Trancher le saumon et le thon en fines lamelles. Couper concombre et avocat.\n4. Répartir le riz dans des bols. Disposer artistiquement les garnitures par dessus.\n5. Parsemer de lamelles de nori + ikura. Servir avec wasabi + sauce soja.",vin:"Saké junmai ou thé vert sencha",notes:"Chirashi signifie dispersé - la beauté vient du soin apporté à la disposition des ingrédients."},
{id:"AS022",co:"Asie",cat:"Plat",sous:"Wok",nom:"Boeuf Sauté aux Brocolis",chef:"Tradition cantonaise",bp:4,prep:20,cui:10,diff:1,qual:4,ig:[["Boeuf filet en lanières",400,"g"],["Brocoli",600,"g"],["Ail",3,"gousses"],["Gingembre",2,"cm"],["Sauce hoisin",2,"cs"],["Sauce soja",3,"cs"],["Huile de sésame",1,"cs"],["Fécule de maïs",1,"cs"],["Sucre",1,"cc"],["Huile de wok",4,"cs"]],et:"1. Mariner le boeuf : sauce soja + fécule + huile sésame + sucre 15 min.\n2. Blanchir le brocoli en fleurettes 2 min. Rafraîchir à l'eau froide. Égoutter.\n3. Chauffer le wok à feu très vif. Saisir le boeuf très rapidement (1-2 min). Réserver.\n4. Saisir ail + gingembre dans le wok. Ajouter le brocoli. Sauter 2 min.\n5. Remettre le boeuf + sauce hoisin + un filet d'eau. Mélanger rapidement. Huile sésame finale.",vin:"Bière Tsingtao ou thé oolong glacé",notes:"Le wok doit être fumant. Chaque ingrédient se cuit séparément et rapidement."},
{id:"AS023",co:"Asie",cat:"Plat",sous:"Curry",nom:"Japanese Curry Rice",chef:"Tradition japonaise moderne",bp:4,prep:20,cui:40,diff:1,qual:4,ig:[["Épaule de porc ou poulet en cubes",600,"g"],["Oignons",3,"pièces"],["Pommes de terre",4,"pièces"],["Carottes",3,"pièces"],["Roux de curry japonais (boîte S&B)",1,"boîte"],["Eau",80,"cl"],["Huile",3,"cs"],["Riz blanc cuit",600,"g"]],et:"1. Suer oignons dans l'huile jusqu'à très tendres et légèrement caramélisés (20 min).\n2. Ajouter la viande. Dorer légèrement.\n3. Ajouter pommes de terre + carottes en morceaux. Verser l'eau. Frémir 15 min.\n4. Hors feu : dissoudre les blocs de roux de curry dans la casserole.\n5. Remettre sur feu doux. Cuire encore 10-15 min jusqu'à sauce épaisse et lisse. Servir sur riz.",vin:"Bière japonaise froide",notes:"Le curry japonais est doux et légèrement sucré, très différent des currys indiens. Les oignons caramélisés sont la clé."},
{id:"AS024",co:"Asie",cat:"Entrée",sous:"Dumplings",nom:"Shao Mai (Dim Sum Ouverts)",chef:"Tradition cantonaise dim sum",bp:6,prep:40,cui:15,diff:3,qual:4,ig:[["Pâte à wonton ronde",24,"pièces"],["Porc haché",300,"g"],["Crevettes hachées",150,"g"],["Châtaignes d'eau hachées",50,"g"],["Sauce soja",2,"cs"],["Huile de sésame",1,"cs"],["Gingembre râpé",1,"cc"],["Oignons verts",2,"tiges"],["Oeufs de saumon ou petits pois pour décorer",1,"qs"]],et:"1. Mélanger porc + crevettes + châtaignes d'eau + oignons verts + sauce soja + huile sésame + gingembre.\n2. Placer une feuille de pâte dans le creux de la main. Déposer la farce au centre.\n3. Refermer en coupelle en plissant les bords mais en laissant le dessus ouvert.\n4. Décorer d'un oeuf de saumon ou petit pois au centre.\n5. Cuire à la vapeur dans un panier bambou 15 min.",vin:"Thé au chrysanthème ou thé pu-erh",notes:"Les shao mai ne sont jamais complètement fermés - c'est leur caractéristique."},
{id:"AS025",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Sukiyaki",chef:"Tradition japonaise",bp:4,prep:20,cui:15,diff:2,qual:4,ig:[["Bœuf tranché très fin (wagyu idéalement)",400,"g"],["Tofu ferme",200,"g"],["Champignons shiitake",100,"g"],["Poireaux ou oignons verts",2,"pièces"],["Chou chinois",200,"g"],["Harusame (vermicelles)",100,"g"],["Sauce soja",8,"cs"],["Mirin",6,"cs"],["Sake",5,"cs"],["Sucre",2,"cs"],["Œufs crus",4,"pièces"]],et:"1. Préparer le warishita (bouillon) : soja + mirin + sake + sucre. Chauffer jusqu'à ébullition.\n2. Dans une grande poêle ou casserole sukiyaki à table : faire revenir le bœuf dans un peu de graisse bovine.\n3. Ajouter le warishita. Ajouter les légumes + tofu + vermicelles prétrempés.\n4. Cuire 5-7 min jusqu'à légumes tendres.\n5. Chaque convive trempe les ingrédients dans un bol d'œuf cru battu avant de manger.",vin:"Saké junmai chaud ou bière japonaise",notes:"Le sukiyaki est un plat convivial cuisiné à table. L'œuf cru est obligatoire selon la tradition."},
{id:"AS026",co:"Asie",cat:"Plat",sous:"Poisson",nom:"Dorade Entière Vapeur au Gingembre et Soja",chef:"Tradition cantonaise",bp:4,prep:15,cui:12,diff:2,qual:4,ig:[["Dorade ou bar entier",1200,"g"],["Gingembre frais",5,"cm"],["Oignons verts",4,"tiges"],["Sauce soja légère",4,"cs"],["Huile de sésame",1,"cs"],["Sucre",1,"cc"],["Huile arachide très chaude",4,"cs"],["Coriandre fraîche",0.5,"bouquet"]],et:"1. Inciser le poisson en biais des deux côtés. Glisser des tranches de gingembre dans les incisions et la cavité.\n2. Cuire à la vapeur sur assiette 10-12 min selon la taille. Le poisson est cuit quand la chair se détache facilement.\n3. Pendant la cuisson : chauffer la sauce soja + sucre + huile sésame.\n4. Retirer l'eau accumulée sous le poisson. Napper de sauce.\n5. Parsemer d'oignons verts + coriandre + julienne de gingembre. Verser l'huile d'arachide brûlante dessus : elle grésille et cuit légèrement les herbes.",vin:"Riesling Alsace ou thé oolong",notes:"Le secret : l'huile brûlante versée sur les herbes juste avant de servir révèle tous les arômes."},
{id:"AS027",co:"Asie",cat:"Plat",sous:"Agneau",nom:"Biryani de Mouton (Dum Biryani)",chef:"Tradition moghole de Hyderabad",bp:6,prep:60,cui:60,diff:3,qual:4,ig:[["Riz basmati",500,"g"],["Mouton en morceaux",1000,"g"],["Yaourt entier",200,"g"],["Oignons",3,"pièces"],["Ail gingembre",1,"qs"],["Épices entières (cardamome cannelle clou étoile)",1,"qs"],["Garam masala",2,"cc"],["Safran",0.2,"g"],["Lait chaud",5,"cs"],["Ghee",6,"cs"],["Menta menthe + coriandre",1,"bouquet"],["Eau de rose",1,"cs"]],et:"1. Mariner mouton dans yaourt + épices + ail + gingembre 4h.\n2. Suer oignons dans ghee jusqu'à bruns croustillants (birista). Réserver la moitié.\n3. Cuire mouton dans la cocotte avec les oignons 30 min. La viande doit être à mi-cuisson.\n4. Cuire le riz à 75%. Égoutter.\n5. Dum : alterner dans la cocotte couches de viande + riz + oignons frits + menthe + safran dilué + eau de rose. Couvrir hermétiquement. Cuire à feu très doux 30 min.",vin:"Bière Kingfisher ou lassi à la rose",notes:"Le dum biryani est cuisiné hermétiquement (en lutant le couvercle) pour que les arômes ne s'échappent pas."},
{id:"AS028",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Samgyetang (Soupe de Poulet au Ginseng)",chef:"Tradition coréenne de santé",bp:4,prep:15,cui:90,diff:2,qual:4,ig:[["Petits poulets de Cornouailles ou coquelet",4,"pièces"],["Riz glutineux",120,"g"],["Ginseng frais ou séché",2,"racines"],["Ail",8,"gousses"],["Jujubes (dattes chinoises)",8,"pièces"],["Oignons verts",4,"tiges"],["Sel poivre blanc",1,"qs"]],et:"1. Rincer le riz glutineux. Farcir chaque poulet avec riz + ginseng + ail + 2 jujubes.\n2. Ficeler les cuisses pour maintenir la farce.\n3. Placer les poulets dans une marmite. Couvrir d'eau froide. Porter à ébullition en écumant.\n4. Frémir à couvert 1h30 à feu doux.\n5. Servir chaque poulet dans un bol individuel avec son bouillon. Sel et poivre blanc à part.",vin:"Thé vert coréen (nokcha) ou eau de prunelle coréenne (maesil-cha)",notes:"Le samgyetang est le plat de santé traditionnel consommé les jours de grande chaleur. Paradoxalement, chaud contre chaud !"},
{id:"AS029",co:"Asie",cat:"Plat",sous:"Dim Sum",nom:"Cheung Fun (Rouleaux de Riz Vapeur)",chef:"Tradition cantonaise dim sum",bp:4,prep:20,cui:15,diff:3,qual:4,ig:[["Farine de riz",200,"g"],["Fécule de tapioca",40,"g"],["Fécule de blé",20,"g"],["Eau",50,"cl"],["Crevettes décortiquées",200,"g"],["Char siu (porc BBQ) ou bœuf haché",200,"g"],["Sauce soja sucrée",4,"cs"],["Huile de sésame",2,"cs"],["Oignons verts ciboulette",3,"tiges"]],et:"1. Mélanger farine de riz + fécules + eau jusqu'à pâte liquide sans grumeaux.\n2. Graisser légèrement un plateau plat. Verser fine couche de pâte (2-3mm).\n3. Déposer la garniture (crevettes ou char siu) sur la moitié.\n4. Cuire à la vapeur 3-4 min jusqu'à translucide.\n5. Rouler délicatement avec une spatule. Découper. Napper sauce soja sucrée + huile sésame.",vin:"Thé au jasmin ou thé chrysanthème",notes:"La pâte doit être aussi fine et translucide que du papier de riz."},
{id:"AS030",co:"Asie",cat:"Entrée",sous:"Salade",nom:"Som Tum (Salade de Papaye Verte)",chef:"Tradition thaïlandaise et laotienne",bp:4,prep:20,cui:0,diff:2,qual:4,ig:[["Papaye verte",600,"g"],["Tomates cerises",100,"g"],["Haricots longs ou verts",100,"g"],["Ail",3,"gousses"],["Piment oiseau",3,"pièces"],["Cacahuètes grillées",50,"g"],["Sauce de poisson nuoc-mâm",3,"cs"],["Jus de lime",4,"cs"],["Sucre de palme",2,"cs"],["Crevettes séchées",2,"cs"]],et:"1. Peler la papaye verte. La râper en fine julienne avec une râpe à mandoline ou dans un mortier.\n2. Dans un mortier : piler ail + piment. Ajouter haricots, écraser légèrement.\n3. Ajouter crevettes séchées + tomates cerises + papaye. Mélanger en pilant doucement.\n4. Assaisonner avec sauce de poisson + lime + sucre de palme. Goûter : doit être acide + salé + sucré + pimenté.\n5. Parsemer de cacahuètes. Servir avec riz gluant.",vin:"Bière Singha très froide ou thé glacé macha",notes:"Le som tum se prépare dans un mortier en pilant doucement. Ne pas mixer - la texture est essentielle."},
{id:"AS031",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Shabu Shabu",chef:"Tradition japonaise",bp:4,prep:20,cui:15,diff:1,qual:4,ig:[["Bœuf wagyu ou entrecôte tranché très fin",400,"g"],["Tofu soyeux",200,"g"],["Légumes (chou chinois champignons shiitake poireaux)",400,"g"],["Kombu",10,"g"],["Sauce ponzu",1,"qs"],["Sauce sésame",1,"qs"],["Riz blanc cuit",400,"g"]],et:"1. Bouillon : faire chauffer eau + kombu sur réchaud de table. Retirer le kombu à frémissement.\n2. Chaque convive plonge individuellement une tranche de bœuf dans le bouillon frémissant 10-20 sec (shabu shabu = le bruit de l'eau).\n3. Plonger ensuite les légumes + tofu dans le bouillon 2-5 min.\n4. Tremper dans sauce ponzu (agrumes soja) ou sauce sésame selon goût.\n5. En fin de repas : cuire le riz dans le bouillon enrichi de tous les sucs.",vin:"Saké junmai ginjo très frais ou bière Asahi",notes:"Le shabu shabu est un repas rituel convivial. La qualité du bœuf est absolument déterminante."},
{id:"AS032",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Soto Ayam (Soupe de Poulet Javanaise)",chef:"Tradition javanaise",bp:6,prep:25,cui:60,diff:2,qual:4,ig:[["Poulet entier",1600,"g"],["Curcuma frais",4,"cm"],["Galanga",3,"cm"],["Citronnelle",2,"tiges"],["Feuilles kaffir lime",4,"pièces"],["Oignons",2,"pièces"],["Ail",4,"gousses"],["Noix de macadamia ou kemiri",4,"pièces"],["Vermicelles de riz",200,"g"],["Oeufs durs",4,"pièces"],["Beansprouts germes de soja",100,"g"],["Kerupuk chips de crevettes",1,"qs"]],et:"1. Pocher le poulet entier dans l'eau avec citronnelle + kaffir lime + galanga 45 min. Effilocher. Filtrer le bouillon.\n2. Pâte : mixer oignons + ail + curcuma + galanga + noix kemiri.\n3. Faire revenir la pâte dans l'huile 5 min. Verser dans le bouillon. Frémir 10 min.\n4. Cuire vermicelles séparément.\n5. Dans chaque bol : vermicelles + poulet effiloché + œuf dur + germes. Verser bouillon bouillant. Garnir de chips de crevettes.",vin:"Thé de jasmin glacé ou bière Bintang",notes:"Le curcuma frais donne au bouillon sa couleur jaune dorée caractéristique."},
{id:"AS033",co:"Asie",cat:"Dessert",sous:"Thaïlande",nom:"Khao Niao Mamuang (Riz Gluant Mangue)",chef:"Tradition thaïlandaise",bp:4,prep:15,cui:30,diff:1,qual:4,ig:[["Riz gluant",300,"g"],["Lait de coco",40,"cl"],["Sucre",80,"g"],["Sel",1,"cc"],["Mangues fraîches mûres",2,"pièces"],["Graines de sésame",1,"cs"],["Feuilles de pandan (optionnel)",2,"pièces"]],et:"1. Tremper le riz gluant 4h dans l'eau froide. Égoutter.\n2. Cuire à la vapeur 20-25 min jusqu'à translucide.\n3. Sauce coco sucrée : chauffer lait de coco + sucre + sel + pandan jusqu'à dissolution. Ne pas bouillir.\n4. Verser 2/3 de la sauce coco sur le riz cuit. Mélanger. Laisser absorber 15 min.\n5. Servir avec mangues tranchées. Napper du reste de sauce coco. Sésame.",vin:"Thé au jasmin ou eau de coco fraîche",notes:"La mangue doit être parfaitement mûre. Ce dessert est la définition de la perfection thaïlandaise."},
{id:"AS034",co:"Asie",cat:"Plat",sous:"Légumes",nom:"Agedashi Tofu",chef:"Tradition japonaise izakaya",bp:4,prep:15,cui:10,diff:2,qual:4,ig:[["Tofu soyeux",400,"g"],["Fécule de pomme de terre ou katakuriko",60,"g"],["Dashi",25,"cl"],["Sauce soja Mirin",1,"qs"],["Gingembre râpé",2,"cc"],["Oignons verts",2,"tiges"],["Daikon râpé",60,"g"],["Huile pour frire",1,"L"]],et:"1. Sécher soigneusement le tofu avec du papier absorbant 30 min.\n2. Couper en cubes de 4cm. Rouler dans la fécule.\n3. Frire dans l'huile à 175°C 2-3 min jusqu'à croûte légère et croustillante.\n4. Bouillon tentsuyu : dashi + sauce soja + mirin. Chauffer.\n5. Servir les cubes de tofu dans le bouillon chaud. Garnir de daikon râpé + gingembre râpé + oignons verts.",vin:"Saké junmai ou thé vert chaud",notes:"La croûte de fécule doit être très fine et délicate. Ne pas laisser trop frire."},
{id:"AS035",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Bún Chả (Porc Grillé et Vermicelles)",chef:"Tradition hanoïenne",bp:4,prep:30,cui:15,diff:2,qual:4,ig:[["Porc haché",400,"g"],["Ventrèche de porc en tranches",300,"g"],["Sauce de poisson",4,"cs"],["Sucre",2,"cs"],["Ail oignon vert",1,"qs"],["Vermicelles de riz",300,"g"],["Salade romaine herbes fraîches",1,"bouquet"],["Sauce nuoc cham",1,"qs"],["Carottes en julienne marinées",2,"pièces"]],et:"1. Mariner porc haché (en boulettes) + ventrèche dans sauce poisson + sucre + ail + oignon vert 30 min.\n2. Griller au charbon de bois ou plancha jusqu'à caramélisation parfaite des deux côtés.\n3. Sauce nuoc cham : nuoc-mâm + eau + sucre + lime + ail + piment. Diluer selon goût.\n4. Servir le bouillon de sauce nuoc cham tiède dans un bol avec la viande grillée.\n5. Tremper les vermicelles et salade dans la sauce. Manger en assemblant.",vin:"Bière Hanoi froide ou thé vert",notes:"Obama a mangé ce plat avec Anthony Bourdain à Hanoï en 2016, le rendant célèbre mondialement."},
{id:"AS036",co:"Asie",cat:"Plat",sous:"Agneau",nom:"Yang Rou Chuan (Brochettes d'Agneau Xinjiang)",chef:"Tradition ouïghoure du Xinjiang",bp:4,prep:20,cui:15,diff:1,qual:4,ig:[["Épaule d'agneau en cubes de 2cm",600,"g"],["Cumin moulu",2,"cs"],["Piment rouge séché moulu",1,"cs"],["Sel",1,"cc"],["Ail en poudre",1,"cc"],["Huile",2,"cs"],["Pain naan ou pita",4,"pièces"]],et:"1. Assembler les cubes d'agneau sur des brochettes fines en métal ou bambou.\n2. Mélanger cumin + piment + sel + ail. Réserver la moitié.\n3. Badigeonner légèrement les brochettes d'huile. Saupoudrer de moitié des épices.\n4. Griller sur braise très vive 3-4 min en retournant et saupoudrant du reste d'épices à mi-cuisson.\n5. Servir immédiatement avec pain naan chaud.",vin:"Bière tsingtao ou thé noir fort",notes:"Ces brochettes font partie de la cuisine ouïghoure du Xinjiang. Le cumin est l'épice maîtresse - utilisé généreusement."},
{id:"AS037",co:"Asie",cat:"Plat",sous:"Tofu",nom:"Hiyayakko (Tofu Froid Garni)",chef:"Tradition japonaise d'été",bp:4,prep:10,cui:0,diff:1,qual:4,ig:[["Tofu soyeux très frais",400,"g"],["Gingembre frais râpé",3,"cc"],["Oignons verts",3,"tiges"],["Bonite séchée katsuobushi",3,"cs"],["Sauce soja qualité",4,"cs"],["Huile de sésame",1,"cc"],["Ciboulette",1,"cs"],["Daikon râpé",60,"g"]],et:"1. Placer le tofu au réfrigérateur jusqu'au moment de servir (il doit être très froid).\n2. Couper délicatement en cubes ou en tranches épaisses sans briser.\n3. Disposer dans assiettes froides.\n4. Garnir généreusement : gingembre râpé + oignons verts ciselés + daikon râpé + katsuobushi.\n5. Verser un filet de sauce soja + quelques gouttes d'huile sésame. Servir immédiatement.",vin:"Bière japonaise très froide ou thé sencha glacé",notes:"La simplicité absolue. La qualité du tofu est tout. Manger en été sur tatami."},
{id:"AS038",co:"Asie",cat:"Plat",sous:"Crevettes",nom:"Pad Kra Pao (Porc ou Crevettes au Basilic Thaï)",chef:"Tradition de la cuisine de rue thaïlandaise",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Porc haché ou crevettes",500,"g"],["Basilic sacré thaï (kra pao)",1,"bouquet"],["Piment oiseau",4,"pièces"],["Ail",6,"gousses"],["Sauce huître",3,"cs"],["Sauce soja",2,"cs"],["Nuoc-mâm",1,"cs"],["Sucre",1,"cc"],["Huile",3,"cs"],["Oeufs au plat côté ensoleillé",4,"pièces"]],et:"1. Écraser grossièrement ail + piment dans le mortier.\n2. Chauffer wok très vif. Saisir ail + piment dans l'huile 30 sec.\n3. Ajouter la viande ou crevettes. Saisir à feu très vif en brisant les grumeaux.\n4. Assaisonner sauce huître + soja + nuoc-mâm + sucre.\n5. Hors feu : incorporer le basilic sacré d'un coup (il doit se faner légèrement). Servir sur riz avec œuf au plat.",vin:"Bière Singha ou Chang fraîche",notes:"Le basilic sacré (kra pao) est différent du basilic thaï ordinaire. Plus pimenté et épicé. Ce plat est le comfort food national thaïlandais."},
{id:"AS039",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Satsivi (Poulet Sauce aux Noix)",chef:"Tradition géorgienne",bp:6,prep:20,cui:60,diff:2,qual:4,ig:[["Poulet entier poché effiloché",1,"pièce"],["Noix de Grenoble",300,"g"],["Oignons",2,"pièces"],["Ail",4,"gousses"],["Bouillon de poulet",40,"cl"],["Vinaigre de vin blanc",2,"cs"],["Coriandre moulue",1,"cc"],["Safran en poudre",0.5,"cc"],["Cannelle clou cardamome",1,"qs"],["Piment rouge",0.5,"cc"]],et:"1. Pocher le poulet entier. Effilocher. Conserver le bouillon.\n2. Mixer finement les noix avec ail + épices jusqu'à pâte.\n3. Suer oignons dans l'huile. Incorporer la pâte de noix. Cuire 5 min à feu doux.\n4. Délayer progressivement avec le bouillon de poulet jusqu'à sauce crémeuse.\n5. Incorporer le poulet effiloché + vinaigre. Laisser refroidir. Servir froid ou à T° ambiante.",vin:"Rkatsiteli géorgien ou Mtsvane",notes:"Le satsivi se sert froid - la sauce aux noix se solidifie légèrement au réfrigérateur."},
{id:"AS040",co:"Asie",cat:"Plat",sous:"Agneau",nom:"Khorovats (Barbecue Arménien)",chef:"Tradition arménienne",bp:6,prep:30,cui:20,diff:2,qual:4,ig:[["Épaule d'agneau en cubes",1000,"g"],["Oignons râpés",2,"pièces"],["Paprika",2,"cs"],["Sumac",1,"cs"],["Thym",1,"cs"],["Piment rouge",0.5,"cc"],["Sel poivre",1,"qs"],["Pain lavash",4,"pièces"],["Tomates oignons grillés",1,"qs"]],et:"1. Mariner l'agneau avec oignons râpés + épices 4h minimum. Les oignons attendrissent la viande.\n2. Enfiler sur brochettes en alternant viande + oignon.\n3. Griller sur braise de sarment de vigne de préférence, en tournant régulièrement 15-20 min.\n4. Servir sur pain lavash qui absorbe les jus.\n5. Accompagner de tomates et oignons grillés + herbes fraîches.",vin:"Ararat (brandy arménien) très froid ou vin rouge arménien",notes:"Le khorovats est le symbole de la convivialité arménienne. Le lavash absorbe les jus précieux."},
{id:"AS041",co:"Asie",cat:"Plat",sous:"Riz",nom:"Ghormeh Sabzi (Ragoût d'Herbes Iranien)",chef:"Tradition persane",bp:6,prep:30,cui:120,diff:2,qual:4,ig:[["Agneau en cubes",600,"g"],["Épinards persil ciboulette methi fenugrec frais",800,"g"],["Haricots rouges cuits",200,"g"],["Citrons secs (limu omani)",3,"pièces"],["Oignons",2,"pièces"],["Curcuma",1,"cc"],["Huile",4,"cs"],["Sel poivre",1,"qs"]],et:"1. Hacher très finement tous les herbes. Les faire sauter dans l'huile à feu moyen 30-40 min jusqu'à foncées et très parfumées (c'est long mais essentiel).\n2. Dorer l'agneau + oignons. Ajouter curcuma.\n3. Incorporer les herbes sautées + haricots rouges + citrons secs percés + eau.\n4. Frémir à couvert 1h30-2h jusqu'à viande très tendre et sauce foncée.\n5. Servir avec riz basmati tah dig.",vin:"Thé noir iranien ou doogh (yaourt gazéifié)",notes:"Les herbes sautées longuement sont l'âme du ghormeh sabzi. Ne pas raccourcir cette étape."},
{id:"AS042",co:"Asie",cat:"Dessert",sous:"Corée",nom:"Hotteok (Crêpes Farcies Coréennes)",chef:"Tradition coréenne",bp:8,prep:90,cui:15,diff:2,qual:4,ig:[["Farine T55",300,"g"],["Levure fraîche",10,"g"],["Sucre",20,"g"],["Eau tiède",20,"cl"],["Huile",2,"cs"],["Sel",1,"cc"],["Cassonade",100,"g"],["Cannelle",1,"cc"],["Noix mélangées hachées",60,"g"]],et:"1. Diluer levure + sucre dans eau tiède. Mélanger avec farine + sel + huile. Lever 1h.\n2. Farce : mélanger cassonade + cannelle + noix hachées.\n3. Diviser la pâte en 8 boules. Aplatir, déposer 1cs de farce au centre, refermer en boule.\n4. Dans poêle huilée à feu moyen, poser la boule, aplatir avec spatule plate.\n5. Cuire 2-3 min/face jusqu'à dorée. La farce caramélise et coule légèrement.",vin:"Thé vert coréen chaud ou café",notes:"Les hotteok se mangent brûlants dans la rue coréenne. Attention au caramel très chaud."},
{id:"AS043",co:"Asie",cat:"Plat",sous:"Poisson",nom:"Fish Curry de Goa",chef:"Tradition de Goa (Inde)",bp:4,prep:20,cui:25,diff:2,qual:4,ig:[["Darnes de poisson ferme (vivaneau ou thon)",600,"g"],["Lait de coco",40,"cl"],["Tamarin concentré",2,"cs"],["Oignons",2,"pièces"],["Tomates concassées",200,"g"],["Ail gingembre",1,"qs"],["Piment vert frais",2,"pièces"],["Cumin coriandre turmeric paprika",1,"qs"],["Huile de coco",3,"cs"],["Coriandre fraîche",1,"bouquet"]],et:"1. Mariner le poisson dans tamarin + sel + turmeric 15 min.\n2. Suer oignons dans l'huile de coco. Ajouter ail + gingembre + épices. Cuire 3 min.\n3. Ajouter tomates + piment vert. Cuire 5 min.\n4. Verser le lait de coco. Frémir 5 min.\n5. Ajouter le poisson mariné. Cuire 10-12 min. Coriandre fraîche. Servir avec riz blanc.",vin:"Bière Kingfisher ou feni (alcool de cajou goannais)",notes:"Le tamarin apporte l'acidité caractéristique du curry de Goa."},
{id:"AS044",co:"Asie",cat:"Plat",sous:"Bouillon",nom:"Mongolian Hot Pot",chef:"Tradition mongole et chinoise",bp:6,prep:30,cui:20,diff:1,qual:4,ig:[["Boeuf en fines tranches",400,"g"],["Mouton en fines tranches",400,"g"],["Tofu ferme",200,"g"],["Champignons enoki shiitake",200,"g"],["Légumes variés",400,"g"],["Vermicelles de verre",100,"g"],["Bouillon os boeuf",200,"cl"],["Sauce sésame",1,"qs"],["Sauce soja",1,"qs"]],et:"1. Porter le bouillon à frémissement dans un récipient central sur réchaud de table.\n2. Préparer sauces individuelles : sésame + soja + ail + oignon vert.\n3. Chaque convive plonge individuellement viandes + légumes + tofu dans le bouillon.\n4. La viande se cuit en 10-30 sec. Les légumes en 1-3 min.\n5. Tremper dans les sauces avant de manger. En fin, cuire les nouilles dans le bouillon enrichi.",vin:"Bière Chinggis ou thé au sel beurre mongol",notes:"Le hot pot est le repas social et convivial par excellence de l'Asie de l'Est."},
{id:"BD001",co:"Asie",cat:"Plat",sous:"Poisson",nom:"Ilish Bhapa (Hilsa au Four à la Moutarde)",chef:"Tradition bengalie",bp:4,prep:15,cui:20,diff:2,qual:5,ig:[["Hilsa (ou maquereau en substitut)",800,"g"],["Moutarde noire",3,"cs"],["Moutarde jaune",2,"cs"],["Noix de coco fraîche râpée",4,"cs"],["Piment vert",3,"pièces"],["Curcuma",1,"cc"],["Huile de moutarde",3,"cs"],["Sel",1,"cc"]],et:"1. Moudre les graines de moutarde avec un peu d'eau en pâte.\n2. Mélanger pâte de moutarde + noix de coco + piment haché + curcuma + sel + huile de moutarde.\n3. Enduire généreusement le poisson de ce mélange dans ses deux faces et ses incisions.\n4. Mettre dans récipient hermétique (ou papillote).\n5. Cuire à la vapeur ou au four 180°C 20 min. Ouvrir à table.",vin:"Thé bangladeshi ou eau fraîche",notes:"L'hilsa (ilish) est le poisson national du Bangladesh — d'une richesse incomparable. La moutarde est l'âme de la cuisine bengalie."},
{id:"BD002",co:"Asie",cat:"Plat",sous:"Lentilles",nom:"Dal Bhaat (Lentilles et Riz du Bangladesh)",chef:"Tradition bengalie quotidienne",bp:4,prep:10,cui:30,diff:1,qual:4,ig:[["Lentilles rouges",300,"g"],["Riz basmati",400,"g"],["Oignons",2,"pièces"],["Tomates",2,"pièces"],["Ail gingembre",1,"qs"],["Moutarde noire graines",1,"cc"],["Piment vert",2,"pièces"],["Curcuma",1,"cc"],["Huile de moutarde",3,"cs"],["Coriandre",1,"bouquet"]],et:"1. Cuire le riz séparément.\n2. Faire revenir graines de moutarde dans huile jusqu'à éclater. Ajouter oignons.\n3. Ail + gingembre + piment + tomates + curcuma. Cuire 10 min.\n4. Ajouter lentilles + eau à hauteur. Cuire 20 min jusqu'à fondantes.\n5. Tempering final : verser dans un bol puis y plonger une cuillerée d'huile de moutarde fumante.",vin:"Thé bengali ou eau fraîche",notes:"Le dal bhaat (lentilles et riz) est le plat quotidien du Bangladesh et du Bengal. L'huile de moutarde est indispensable."},
{id:"BD003",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Mishti Doi (Yaourt Sucré Bengali)",chef:"Tradition bengalie",bp:6,prep:10,cui:40,diff:1,qual:5,ig:[["Lait entier",100,"cl"],["Sucre roux",150,"g"],["Yaourt nature",3,"cs"],["Eau de rose",2,"cs"],["Cardamome moulue",0.5,"cc"]],et:"1. Caraméliser 50g de sucre roux en caramel doré. Ajouter le lait chaud avec précaution.\n2. Ajouter le reste du sucre. Cuire à feu doux en remuant jusqu'à lait réduit de 30%.\n3. Refroidir jusqu'à 40°C. Incorporer yaourt + eau de rose + cardamome.\n4. Verser dans des petits pots en terre (cultchi) ou ramequins.\n5. Ferment à T° ambiante 6-8h puis réfrigérer 4h.",vin:"Seul ou avec sweets bengalis",notes:"La cuisson du lait avec le caramel donne au mishti doi sa couleur brune caractéristique et son goût de caramel."},
{id:"CN001",co:"Asie",cat:"Plat",sous:"Tofu / Sichuan",nom:"Mapo Doufu Original au Poivre du Sichuan (Recette Chen Kenmin/Kenichi)",chef:"Chen Kenichi (★ Iron Chef Chinois — Shisen Hanten Tokyo)",bp:4,prep:15,cui:18,diff:3,qual:5,ig:[["Tofu soyeux frais kinugoshi",450,"g"],["Bœuf haché 25% MG",150,"g"],["Doubanjiang Pixian (pâte fève fermentée Sichuan — la signature)",2,"cs"],["Douchi (haricots noirs fermentés)",1,"cs"],["Ail râpé",6,"gousses"],["Gingembre frais râpé",3,"cm"],["Bouillon de volaille",25,"cl"],["Sauce soja foncée",2,"cs"],["Sucre",1,"cc"],["Poivre du Sichuan moulu fraîchement (Hua Jiao)",2,"cc"],["Piments rouges séchés émiettés",1,"cs"],["Huile de Sichuan piquante (rāyu)",2,"cs"],["Huile végétale neutre",3,"cs"],["Oignons verts (cigué chinoise)",4,"tiges"],["Fécule maïs",1,"cs"],["Eau",2,"cs"]],et:"PRÉPARATION DU TOFU (étape critique) :\n1. Couper le tofu soyeux en cubes 2 cm avec délicatesse.\n2. Plonger 2 min dans eau salée frémissante (jamais bouillante — fragile). Égoutter délicatement à l'écumoire.\nBASE PIQUANTE SICHUAN (la magie 'mā lā' — engourdissement-piquant) :\n3. Préchauffer wok à feu MAX. Verser huile végétale.\n4. Saisir bœuf haché 3 min jusqu'à brun foncé (croustillant — signature 'sui zui rou').\n5. Pousser sur le côté. Au centre : ajouter doubanjiang Pixian + douchi écrasés. Cuire 90 sec — l'huile devient ROUGE PROFOND (l'âme du Sichuan).\n6. Ajouter ail + gingembre + piments séchés. 30 sec.\n7. Verser bouillon + soja + sucre. Porter à frémissement.\nCUISSON DU TOFU :\n8. Plonger délicatement les cubes de tofu (technique : faire glisser, jamais remuer — casse).\n9. Frémir 5 min en agitant doucement le wok (pas de spatule).\nLIAISON ET FINITION (signature 'mā lā') :\n10. Délayer fécule dans 2 cs eau froide. Verser dans le wok en remuant délicatement. Cuire 90 sec — la sauce épaissit en nappe brillante.\n11. Hors feu : ajouter le poivre du Sichuan moulu + huile rāyu Sichuan + 2 cs oignons verts ciselés.\n12. Le poivre du Sichuan donne la sensation \"mā\" (engourdissement) caractéristique — DIFFÉRENT du piquant brûlant.\nDRESSAGE :\n13. Servir directement dans bols sur riz blanc nature.\n14. Garnir : oignons verts en bouquet + 1 cc poivre Sichuan supplémentaire en finition + filet d'huile rāyu.",vin:"Bière chinoise Tsingtao ou thé pu-erh foncé",notes:"Chen Kenichi (★ Shisen Hanten Tokyo — fils du chef qui a popularisé le mapo doufu hors Chine) : \"Le poivre du Sichuan (Hua Jiao) est l'élément capital. Sa sensation 'mā' (engourdissement) est unique au monde et différente du piquant. Le doubanjiang Pixian (Chengdu) est obligatoire — toute autre pâte fève donne un mapo médiocre.\""},
{id:"CN002",co:"Asie",cat:"Plat",sous:"Poulet / Sichuan",nom:"Kung Pao Gong Bao (Poulet aux Cacahuètes Sichuanais Authentique)",chef:"Tradition Sichuan (Madame Chiang)",bp:4,prep:25,cui:10,diff:3,qual:5,ig:[["Blanc de poulet en dés 1,5 cm",600,"g"],["Cacahuètes grillées non salées (signature)",80,"g"],["Piments séchés Tianjin (les rouges en S)",10,"pièces"],["Poivre du Sichuan en grains entiers",2,"cc"],["Ail",4,"gousses"],["Gingembre frais",3,"cm"],["Oignons verts (parties blanches)",4,"tiges"],["Huile végétale",4,"cs"],["Sauce soja foncée",2,"cs"],["Vinaigre de riz Chinkiang (signature)",2,"cs"],["Vin de Shaoxing",2,"cs"],["Sucre brun",2,"cc"],["Bouillon de volaille",4,"cs"],["Fécule maïs",1,"cs"],["Sel, poivre blanc",1,"qs"]],et:"MARINADE EXPRESS DU POULET (technique velveting chinoise) :\n1. Mariner le poulet : 1 cs soja + 1 cs Shaoxing + 1 cc fécule + 1 pincée sel + 1 cc huile sésame. 15 min — la fécule + huile crée le \"velvet\" chinois (poulet ultra-tendre).\nSAUCE GONG BAO (préparée à l'avance) :\n2. Mélanger : 1 cs soja + 2 cs vinaigre Chinkiang (la signature noire, jamais le rice) + 1 cs Shaoxing + 2 cc sucre brun + 4 cs bouillon + 1 cc fécule. C'est la sauce \"sucrée-salée-aigre\" caractéristique.\nWOK ULTRA-CHAUD (technique \"chao\" Sichuan) :\n3. Préchauffer wok à feu MAX (le métal doit fumer). Verser 2 cs huile.\n4. Saisir piments séchés + poivre du Sichuan en grains 30 sec — ils libèrent leurs arômes dans l'huile (puis on les laisse dedans, ils font partie du plat).\n5. Ajouter ail + gingembre + oignons verts blancs en tronçons de 2 cm. 15 sec.\n6. Verser le poulet en une seule fois. Saisir 90 sec en sautant constamment — il blanchit et caramélise.\nFINITION :\n7. Verser la sauce préparée. Mélanger 90 sec — elle nappe et brille immédiatement.\n8. Hors feu, ajouter les cacahuètes grillées entières — elles restent CROUSTILLANTES (jamais cuites avec — ramolliraient).\nDRESSAGE :\n9. Dresser dans grand bol. Garnir d'un peu de poivre du Sichuan moulu fraîchement.\n10. Servir avec riz vapeur jasmine + concombre lacto-fermenté + thé jasmin.",vin:"Bière Tsingtao ou Riesling Mosel sec",notes:"Tradition Sichuan (Mme Chiang — autorité du Sichuan moderne) : le Kung Pao authentique est PIQUANT-AIGRE-DOUX-SALÉ en équilibre. Cacahuètes ajoutées HORS feu pour rester croustillantes. Le vinaigre Chinkiang noir est non négociable. Différencier de la version américanisée trop sucrée."},
{id:"CN003",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Hong Shao Rou (Porc Braisé à la Sauce Rouge)",chef:"Tradition du Hunan et Zhejiang",bp:6,prep:15,cui:90,diff:2,qual:4,ig:[["Poitrine de porc",1200,"g"],["Sauce soja foncée",4,"cs"],["Sauce soja claire",3,"cs"],["Shaoxing (vin de riz)",8,"cs"],["Sucre roux",3,"cs"],["Gingembre",4,"cm"],["Anis étoilé",3,"pièces"],["Cannelle bâton",1,"pièce"],["Eau",30,"cl"]],et:"1. Blanchir la poitrine 5 min. Égoutter, couper en cubes 4cm.\n2. Faire fondre le sucre roux dans la casserole jusqu'à caramel. Ajouter les cubes de porc, bien enrober.\n3. Ajouter les deux sauces soja + vin de riz + gingembre + épices + eau.\n4. Porter à ébullition. Frémir à couvert à feu très doux 1h30.\n5. Découvrir, monter le feu pour réduire la sauce jusqu'à sirupeuse et brillante.",vin:"Bière Tsingtao ou vin de riz Shaoxing",notes:"Le hong shao rou (viande rouge braisée) était le plat préféré de Mao Zedong, originaire du Hunan. La peau de porc gélatineuse est sa signature."},
{id:"CN004",co:"Asie",cat:"Entrée",sous:"Dim Sum",nom:"Har Gow (Raviolis aux Crevettes Cantonais)",chef:"Tradition cantonaise dim sum",bp:4,prep:60,cui:10,diff:4,qual:4,ig:[["Fécule de blé (wheat starch)",150,"g"],["Fécule de tapioca",30,"g"],["Eau bouillante",18,"cl"],["Crevettes décortiquées hachées",300,"g"],["Pousse de bambou",60,"g"],["Huile de sésame",1,"cs"],["Sel blanc",1,"cc"],["Sucre",0.5,"cc"]],et:"Pâte :\n1. Mélanger fécules dans un bol. Verser eau bouillante. Pétrir rapidement jusqu'à pâte lisse. Couvrir, reposer 15 min.\nFarce :\n2. Mélanger crevettes + bambou haché + sésame + sel + sucre.\nAssemblage :\n3. Former 20 boules de pâte. Aplatir finement avec lame d'un grand couteau huilé (pâte translucide).\n4. Déposer farce. Plier en demi-lune. Faire 7 plis serrés sur un côté (marque du savoir-faire).\n5. Cuire à la vapeur 8-9 min. Servir immédiatement.",vin:"Thé pu-erh ou thé chrysanthème",notes:"Les 7 plis du har gow sont la marque du cuisinier expérimenté. La pâte doit être translucide comme du parchemin après cuisson."},
{id:"CN005",co:"Asie",cat:"Plat",sous:"Canard",nom:"Canard Laqué Pékinois Impérial",chef:"Tradition impériale de Pékin",bp:4,prep:60,cui:90,diff:4,qual:4,ig:[["Canard entier",2000,"g"],["Miel",4,"cs"],["Sauce soja",3,"cs"],["Vinaigre de riz",2,"cs"],["Cinq-épices",1,"cc"],["Crêpes mandarine",16,"pièces"],["Oignons verts",6,"tiges"],["Concombre",1,"pièce"],["Sauce hoisin",6,"cs"]],et:"1. Sécher la peau du canard à l'air libre 24h au réfrigérateur sur grille (sans couvrir).\n2. Laquage : mélanger miel + soja + vinaigre + cinq-épices. Badigeonner le canard 3 fois à 6h d'intervalle.\n3. Rôtir à 220°C 20 min. Puis 180°C 60-70 min en arrosant.\n4. Laisser reposer 10 min. Découper : peau séparément, chair séparément.\n5. Service : crêpes tièdes + sauce hoisin + julienne de concombre et oignons verts + peau laquée + chair.",vin:"Bière Tsingtao ou saké junmai",notes:"La peau séchée 24h est le secret de la laque croustillante. La découpe est un art : peau et chair séparées."},
{id:"CN006",co:"Asie",cat:"Plat",sous:"Légumes",nom:"Congee (Riz Cantonais au Riz Blanc)",chef:"Tradition cantonaise du matin",bp:4,prep:5,cui:60,diff:1,qual:4,ig:[["Riz jasmin",100,"g"],["Bouillon de poulet",200,"cl"],["Gingembre frais",3,"cm"],["Oignons verts",4,"tiges"],["Huile de sésame",1,"cs"],["Sauce soja",2,"cs"],["You tiao (beignet frais optionnel)",4,"pièces"],["Oeufs de cent ans (pidan optionnel)",2,"pièces"],["Sel blanc poivre blanc",1,"qs"]],et:"1. Rincer le riz. Placer dans casserole avec bouillon + gingembre tranché + sel.\n2. Porter à ébullition. Réduire à feu doux, couvrir partiellement.\n3. Cuire 45-60 min en remuant régulièrement jusqu'à consistance très crémeuse (le riz se dissout presque).\n4. Assaisonner avec sauce soja + poivre blanc + huile sésame.\n5. Servir avec oignons verts + you tiao (beignet) + oeuf de cent ans si désiré.",vin:"Thé oolong chaud ou thé au gingembre",notes:"Le ratio est 1:10 (riz:bouillon). Plus on cuit longtemps, plus le congee devient soyeux. Le riz disparaît dans la soupe crémeuse."},
{id:"CN007",co:"Asie",cat:"Plat",sous:"Dim sum",nom:"Siu Mai (Dim Sum au Porc et Crevettes)",chef:"Tradition cantonaise",bp:4,prep:30,cui:12,diff:3,qual:5,ig:[["Feuilles de raviolis jaunes",30,"pièces"],["Porc haché",300,"g"],["Crevettes hachées",150,"g"],["Champignons shiitake réhydratés",40,"g"],["Gingembre",20,"g"],["Oignons verts",3,"tiges"],["Sauce soja",2,"cs"],["Huile de sésame",1,"cs"],["Sucre",1,"cc"],["Sel poivre blanc",1,"qs"],["Tobiko (oeufs de poisson)",2,"cs"]],et:"1. Mélanger porc + crevettes + shiitake hachés + gingembre râpé + oignons verts + assaisonnements. Mélanger 5 min jusqu'à pâte élastique.\n2. Poser une cuillère de farce au centre d'une feuille de raviolis.\n3. Rassembler les bords en plis en pressant pour former un cylindre ouvert.\n4. Décorer le dessus avec tobiko.\n5. Cuire à la vapeur 8-10 min.",vin:"Thé Pu-erh ou Oolong",notes:"Mélanger la farce longuement est essentiel pour la texture ferme et juteuse."},
{id:"CN008",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Boeuf Sauté aux Haricots Verts Sichuanais",chef:"Tradition sichuanaise",bp:4,prep:15,cui:10,diff:2,qual:4,ig:[["Filet de boeuf",400,"g"],["Haricots verts fins",500,"g"],["Ail",4,"gousses"],["Gingembre",20,"g"],["Sauce soja",3,"cs"],["Shaoxing",2,"cs"],["Sucre",1,"cc"],["Poivre du Sichuan",1,"cc"],["Piment séché",3,"pièces"],["Fécule de maïs",1,"cs"],["Huile",4,"cs"]],et:"1. Couper boeuf en lamelles contre le fil. Mariner avec fécule + 1cs soja + 1cs vin.\n2. Blanchir les haricots verts 2 min. Égoutter.\n3. Chauffer huile à très vif. Saisir boeuf 1 min. Réserver.\n4. Dans même wok : frire piments + poivre Sichuan + ail + gingembre. Ajouter haricots. Sauter 3 min.\n5. Remettre boeuf + soja restant + vin + sucre. Mélanger 1 min.",vin:"Thé oolong ou bière Tsingtao",notes:"Le poivre du Sichuan donne l'engourdissement caractéristique (ma) de la cuisine sichuanaise."},
{id:"CN009",co:"Asie",cat:"Plat",sous:"Canard",nom:"Canard Laqué de Pékin",chef:"Tradition impériale pékinoise",bp:4,prep:60,cui:90,diff:4,qual:5,ig:[["Canard entier",2000,"g"],["Sirop de malt ou miel",3,"cs"],["Vinaigre de riz",2,"cs"],["Eau bouillante",1,"L"],["Cinq-épices",1,"cc"],["Crêpes mandarine",20,"pièces"],["Sauce hoisin",10,"cs"],["Concombre",1,"pièce"],["Oignons verts",6,"tiges"]],et:"1. Sécher le canard à l'air libre 24h au réfrigérateur — crucial pour la peau croustillante.\n2. Laquage : ébouillanter + badigeonner sirop+vinaigre+cinq-épices. Sécher 12h.\n3. Rôtir au four 180°C 1h30 sur grille au-dessus d'un plat en arrosant.\n4. Découper la peau laquée en losanges. Trancher la chair.\n5. Servir dans crêpes avec hoisin + julienne concombre + oignons verts.",vin:"Baijiu ou bière Tsingtao",notes:"Le séchage à l'air 24h avant cuisson est absolument indispensable pour la peau croustillante."},
{id:"CN010",co:"Asie",cat:"Plat",sous:"Porc",nom:"Porc Aigre-Doux Cantonais",chef:"Tradition cantonaise",bp:4,prep:20,cui:15,diff:2,qual:4,ig:[["Échine de porc en cubes",500,"g"],["Ananas frais",300,"g"],["Poivrons rouges verts",2,"pièces"],["Oignons",1,"pièce"],["Ketchup",4,"cs"],["Vinaigre de riz",4,"cs"],["Sucre roux",3,"cs"],["Sauce soja",2,"cs"],["Fécule de maïs",4,"cs"],["Oeuf",1,"pièce"],["Huile pour friture",1,"L"]],et:"1. Mariner porc avec soja + oeuf + 2cs fécule 15 min.\n2. Paner chaque cube dans fécule restante. Frire à 170°C jusqu'à dorés. Égoutter.\n3. Sauce : ketchup + vinaigre + sucre + 10cl eau. Porter à frémissement.\n4. Sauter oignons + poivrons + ananas 3 min dans peu d'huile.\n5. Ajouter sauce + porc frit. Enrober 1 min. Servir immédiatement.",vin:"Thé ou bière Tsingtao",notes:"Servir dans les 5 minutes — la panure perd son croustillant vite."},
{id:"CN011",co:"Asie",cat:"Entrée",sous:"Dumplings",nom:"Jiaozi (Raviolis au Porc et Chou)",chef:"Tradition du Nord de la Chine",bp:6,prep:60,cui:10,diff:3,qual:5,ig:[["Farine T55",400,"g"],["Eau tiède",20,"cl"],["Porc haché",400,"g"],["Chou chinois",300,"g"],["Gingembre",20,"g"],["Oignons verts",4,"tiges"],["Sauce soja",3,"cs"],["Huile de sésame",2,"cs"],["Sel",1,"cc"],["Vinaigre noir pour tremper",1,"qs"]],et:"1. Pâte : farine + eau + sel. Pétrir 10 min. Reposer 30 min.\n2. Chou haché + sel. Presser pour éliminer l'eau.\n3. Farce : porc + chou + gingembre + oignons verts + soja + huile sésame. Mélanger énergiquement.\n4. Petites boules de pâte. Étaler en disque de 8cm. Déposer farce. Plier en plis.\n5. Version vapeur : 8 min. Version poêlée : huile + raviolis + 10cl eau, couvrir 6 min puis dorer.",vin:"Thé ou vin de riz Shaoxing",notes:"Les jiaozi poêlés (guotie) ont un fond doré croustillant caractéristique."},
{id:"CN012",co:"Asie",cat:"Plat",sous:"Poisson",nom:"Poisson Entier à la Vapeur Cantonais",chef:"Tradition cantonaise",bp:4,prep:10,cui:12,diff:2,qual:5,ig:[["Poisson entier (dorade ou bar)",1,"pièce"],["Gingembre frais",40,"g"],["Oignons verts",6,"tiges"],["Sauce soja claire",3,"cs"],["Sauce soja foncée",1,"cs"],["Sucre",1,"cc"],["Huile d'arachide chaude",4,"cs"],["Coriandre fraîche",1,"bouquet"]],et:"1. Inciser le poisson des deux côtés. Saler légèrement.\n2. Placer gingembre tranché sous et dans le poisson.\n3. Cuire à la vapeur vive 10-12 min selon épaisseur.\n4. Verser sauce soja + sucre chauffée dessus.\n5. Oignons verts en julienne fine sur le poisson. Verser huile fumante dessus. Coriandre.",vin:"Thé oolong ou Riesling sec",notes:"L'huile fumante versée sur les oignons verts libère tous les arômes en crépitant spectaculairement."},
{id:"CN013",co:"Asie",cat:"Plat",sous:"Tofu",nom:"Mapo Tofu Authentique",chef:"Tradition sichuanaise",bp:4,prep:15,cui:15,diff:2,qual:5,ig:[["Tofu soyeux",500,"g"],["Porc haché",200,"g"],["Doubanjiang (pâte haricots-piment)",3,"cs"],["Ail",5,"gousses"],["Gingembre",20,"g"],["Oignons verts",4,"tiges"],["Sauce soja",2,"cs"],["Shaoxing",2,"cs"],["Poivre du Sichuan",2,"cc"],["Fécule de maïs",1,"cs"],["Bouillon",15,"cl"]],et:"1. Couper tofu en cubes. Plonger dans eau bouillante salée 3 min. Égoutter délicatement.\n2. Chauffer huile. Griller poivre Sichuan jusqu'à fragrant. Ajouter viande.\n3. Ajouter doubanjiang + ail + gingembre. Cuire 2 min.\n4. Ajouter bouillon + soja + vin. Frémir. Ajouter tofu délicatement.\n5. Lier avec fécule délayée. Oignons verts + poivre Sichuan en poudre.",vin:"Bière Tsingtao ou thé oolong",notes:"Le doubanjiang de Pixian est indispensable. Le poivre du Sichuan donne la sensation engourdissante (ma la)."},
{id:"CN014",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Mango Pomelo Sago",chef:"Tradition hong-kongaise",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Mangues mûres",3,"pièces"],["Pomelo",1,"pièce"],["Perles de sagou",100,"g"],["Lait de coco",40,"cl"],["Lait concentré sucré",4,"cs"],["Sucre",50,"g"],["Eau",40,"cl"]],et:"1. Cuire le sagou dans eau bouillante 15-20 min jusqu'à translucide. Rincer à l'eau froide.\n2. Mixer 2 mangues avec 15cl eau + sucre jusqu'à purée lisse.\n3. Couper la 3e mangue en petits cubes. Séparer le pomelo en suprêmes.\n4. Mélanger purée mangue + lait de coco + lait concentré + sagou. Réfrigérer 2h.\n5. Servir en coupelles avec cubes mangue + segments pomelo.",vin:"Dessert rafraîchissant unique",notes:"Le sagou doit être complètement translucide. Le pomelo apporte l'amertume qui équilibre la douceur."},
{id:"CN015",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Hot and Sour Soup (Soupe Aigre-Épicée)",chef:"Tradition du Nord de la Chine",bp:4,prep:15,cui:15,diff:2,qual:4,ig:[["Porc maigre en lanières",150,"g"],["Tofu ferme",150,"g"],["Champignons shiitake réhydratés",50,"g"],["Champignons noirs réhydratés",30,"g"],["Pousses de bambou",100,"g"],["Bouillon de poulet",100,"cl"],["Vinaigre noir chinois",4,"cs"],["Sauce soja",3,"cs"],["Poivre blanc",1,"cc"],["Oeufs",2,"pièces"],["Fécule",2,"cs"],["Huile sésame",1,"cs"]],et:"1. Couper tofu + champignons + bambou en lanières fines.\n2. Frémir porc + champignons + bambou dans bouillon 10 min.\n3. Ajouter tofu + vinaigre + soja + poivre blanc.\n4. Lier avec fécule délayée en fouettant.\n5. Verser oeuf battu en filet en spirale pour créer les filaments. Huile sésame + oignons verts.",vin:"Thé chinois chaud",notes:"Le vinaigre noir de Zhenjiang est le meilleur. L'oeuf en filet se crée en fouettant pendant l'ajout."},
{id:"CN016",co:"Asie",cat:"Plat",sous:"Riz",nom:"Riz Frit Yangzhou",chef:"Tradition de Yangzhou",bp:4,prep:10,cui:15,diff:2,qual:4,ig:[["Riz cuit refroidi",600,"g"],["Oeufs",3,"pièces"],["Jambon ou char siu",150,"g"],["Crevettes décortiquées",150,"g"],["Petits pois surgelés",100,"g"],["Oignons verts",4,"tiges"],["Sauce soja",3,"cs"],["Huile",4,"cs"],["Sel poivre blanc",1,"qs"]],et:"1. Le riz doit être cuit la veille et refroidi — du riz frais serait pâteux.\n2. Chauffer l'huile à très vif. Cuire crevettes 1 min. Réserver.\n3. Faire une omelette brouillée dans le même wok. Réserver.\n4. Ajouter riz. Sauter à feu très vif 2 min en cassant les grumeaux.\n5. Ajouter jambon + petits pois + crevettes + oeuf + oignons verts + soja. Sauter 2 min.",vin:"Thé ou bière Tsingtao",notes:"Wok brûlant (wok hei = souffle du wok). Riz froid obligatoire pour des grains séparés."},
{id:"CN017",co:"Asie",cat:"Entrée",sous:"Dim sum",nom:"Char Siu Bao (Brioches Vapeur au Porc Laqué)",chef:"Tradition cantonaise",bp:12,prep:60,cui:15,diff:3,qual:5,ig:[["Farine à bao",400,"g"],["Levure fraîche",10,"g"],["Sucre",40,"g"],["Lait tiède",20,"cl"],["Saindoux",3,"cs"],["Levure chimique",1,"cc"],["Char siu (porc laqué cuit)",300,"g"],["Sauce hoisin",3,"cs"],["Sauce d'huîtres",2,"cs"],["Sucre pour farce",1,"cs"],["Fécule",1,"cc"]],et:"1. Pâte : farine + levure + sucre + lait + saindoux. Pétrir 10 min. Lever 1h.\n2. Farce : couper char siu en petits dés. Sauter avec hoisin + huîtres + sucre + fécule délayée.\n3. Ajouter levure chimique à la pâte. Diviser en 12 boules.\n4. Étaler chaque boule. Farcir. Rassembler les bords en pinçant. Sur carrés de papier.\n5. Lever 30 min. Vapeur 12-15 min. Ne pas ouvrir immédiatement.",vin:"Thé jasmin ou oolong",notes:"La levure chimique ajoutée après la pousse donne la blancheur et le gonflement caractéristiques du bao."},
{id:"CN018",co:"Asie",cat:"Plat",sous:"Volaille",nom:"Poulet Kung Pao Traditionnel",chef:"Tradition sichuanaise",bp:4,prep:15,cui:10,diff:2,qual:5,ig:[["Blanc de poulet",500,"g"],["Cacahuètes non salées",100,"g"],["Piments rouges séchés",6,"pièces"],["Poivre du Sichuan",1,"cc"],["Oignons verts",4,"tiges"],["Ail gingembre haché",1,"qs"],["Sauce soja claire",3,"cs"],["Sauce soja foncée",1,"cs"],["Vinaigre noir",2,"cs"],["Sucre",2,"cc"],["Shaoxing",2,"cs"],["Fécule",2,"cc"]],et:"1. Couper poulet en dés de 1.5cm. Mariner avec 1cs soja + 1cs vin + 1cc fécule 15 min.\n2. Sauce : soja x2 + vinaigre + sucre + vin + 1cc fécule + 4cs eau.\n3. Sauter cacahuètes à sec jusqu'à dorées. Réserver.\n4. Huile très chaude. Sauter piments + poivre Sichuan + ail + gingembre 30 sec. Ajouter poulet. Sauter 3 min.\n5. Ajouter cacahuètes + oignons verts + sauce. Mélanger 1 min.",vin:"Bière Tsingtao",notes:"Les cacahuètes et le poulet doivent avoir la même taille de dés — règle de la cuisine chinoise."},
{id:"CN019",co:"Asie",cat:"Sauce / Base",sous:"Condiment",nom:"Sauce XO de Hong Kong",chef:"Tradition hong-kongaise luxueuse",bp:10,prep:30,cui:60,diff:3,qual:5,ig:[["Crevettes séchées",100,"g"],["Noix de Saint-Jacques séchées",80,"g"],["Jambon chinois",60,"g"],["Ail",6,"gousses"],["Échalotes",10,"pièces"],["Piments séchés",5,"pièces"],["Sauce d'huîtres",2,"cs"],["Shaoxing",3,"cs"],["Sucre",1,"cs"],["Huile d'arachide",30,"cl"]],et:"1. Réhydrater crevettes et Saint-Jacques 30 min. Hacher finement.\n2. Hacher ail + échalotes + jambon + piments finement.\n3. Chauffer huile. Frire échalotes + ail jusqu'à dorés.\n4. Ajouter crevettes + Saint-Jacques + jambon + piments. Cuire 15 min à feu doux.\n5. Ajouter sauce d'huîtres + shaoxing + sucre. Cuire 20 min. Conserver 3 mois au froid sous huile.",vin:"Usage : riz, pâtes, légumes, poissons — tout",notes:"Créée à Hong Kong dans les années 1980. Le nom XO est inspiré du cognac haut de gamme."},
{id:"CN020",co:"Asie",cat:"Plat",sous:"Nouilles",nom:"Dan Dan Mian (Nouilles Sichuanaises)",chef:"Tradition de Chengdu",bp:4,prep:15,cui:10,diff:2,qual:4,ig:[["Nouilles chinoises aux oeufs",400,"g"],["Porc haché",250,"g"],["Huile pimentée chinoise",4,"cs"],["Sauce soja noire",3,"cs"],["Vinaigre noir",2,"cs"],["Poivre du Sichuan",2,"cc"],["Tahin",2,"cs"],["Ail haché",3,"gousses"],["Ya cai (légumes conservés)",60,"g"],["Oignons verts",3,"tiges"],["Cacahuètes concassées",3,"cs"]],et:"1. Faire revenir porc + ya cai jusqu'à croustillant.\n2. Sauce dans les bols : huile pimentée + soja + vinaigre + poivre Sichuan + tahin + ail.\n3. Cuire les nouilles al dente. Conserver un peu d'eau de cuisson.\n4. Verser les nouilles dans les bols. Mélanger avec sauce + eau de cuisson.\n5. Garnir de porc + cacahuètes + oignons verts. Mélanger à table.",vin:"Thé ou bière Tsingtao",notes:"Le ya cai (légume fermenté sichuanais) donne le goût fermenté caractéristique."},
{id:"CN021",co:"Asie",cat:"Accompagnement",sous:"Légumes",nom:"Bok Choy Sauté à l'Ail",chef:"Tradition cantonaise",bp:4,prep:5,cui:5,diff:1,qual:4,ig:[["Bok choy (pak-choi)",600,"g"],["Ail",6,"gousses"],["Huile d'arachide",3,"cs"],["Sauce d'huîtres",2,"cs"],["Shaoxing",1,"cs"],["Sel",1,"pincée"],["Sucre",1,"pincée"]],et:"1. Séparer les feuilles de bok choy. Laver soigneusement.\n2. Chauffer l'huile à très vif dans le wok.\n3. Faire revenir l'ail émincé quelques secondes.\n4. Ajouter bok choy. Sauter 2 min à feu maximum jusqu'à tendre-croquant.\n5. Ajouter sauce d'huîtres + vin + sel + sucre. Mélanger 30 sec.",vin:"Accompagnement universel de la cuisine chinoise",notes:"Cuisson ultra-rapide à feu maximum — le bok choy doit rester vert vif et légèrement croquant."},
{id:"CN022",co:"Asie",cat:"Dessert",sous:"Biscuit",nom:"Biscuits aux Amandes Chinois",chef:"Tradition chinoise",bp:20,prep:20,cui:15,diff:1,qual:4,ig:[["Farine T55",250,"g"],["Sucre glace",150,"g"],["Saindoux ou beurre",150,"g"],["Oeuf",1,"pièce"],["Poudre d'amandes",50,"g"],["Extrait d'amande amère",0.5,"cc"],["Levure chimique",0.5,"cc"],["Amandes entières",20,"pièces"],["Jaune pour dorure",1,"pièce"]],et:"1. Crémer saindoux + sucre glace. Ajouter oeuf + extrait d'amande.\n2. Incorporer farine + poudre d'amandes + levure.\n3. Former 20 boules. Aplatir légèrement. Presser 1 amande au centre.\n4. Badigeonner de jaune d'oeuf.\n5. Four 175°C 15 min jusqu'à dorés. Laisser refroidir complètement avant de toucher.",vin:"Thé jasmin ou oolong",notes:"Traditionnellement offerts au Nouvel An chinois. Le saindoux donne la texture friable caractéristique."},
{id:"ID001",co:"Asie",cat:"Plat",sous:"Riz frit",nom:"Nasi Goreng Spécial",chef:"Tradition indonésienne",bp:4,prep:10,cui:10,diff:1,qual:5,ig:[["Riz cuit refroidi",600,"g"],["Oeufs",4,"pièces"],["Crevettes",200,"g"],["Oignons",1,"pièce"],["Ail",4,"gousses"],["Kecap manis",4,"cs"],["Sauce soja",2,"cs"],["Pâte de crevettes (terasi)",1,"cc"],["Piment",2,"pièces"],["Huile",3,"cs"],["Oignons verts concombre tomate",1,"qs"]],et:"1. Chauffer huile à très vif. Frire terasi + ail + piment 30 sec.\n2. Ajouter crevettes. Sauter 1 min. Ajouter oignons.\n3. Pousser sur les bords. Brouiller les oeufs au centre.\n4. Ajouter riz. Sauter vivement 3 min en mélangeant tout.\n5. Kecap manis + soja. Sauter encore 2 min. Garnir oignons verts + concombre + tomate + oeuf au plat.",vin:"Thé glacé ou bière Bintang",notes:"Le kecap manis (soja sucré épais) est indispensable — c'est lui qui donne la couleur brune et le goût caractéristique."},
{id:"ID002",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Rendang de Boeuf (Rendang Sapi)",chef:"Tradition Minangkabau de Sumatra",bp:6,prep:30,cui:180,diff:2,qual:5,ig:[["Boeuf à braiser en cubes",1000,"g"],["Lait de coco",80,"cl"],["Citronnelle",4,"tiges"],["Galanga",40,"g"],["Feuilles de combava",10,"pièces"],["Feuilles de curcuma",3,"pièces"],["Piment rouge",6,"pièces"],["Échalotes",8,"pièces"],["Ail",6,"gousses"],["Curcuma frais",20,"g"],["Coriandre cumin",1,"qs"]],et:"1. Mixer piments + échalotes + ail + galanga + curcuma en pâte.\n2. Faire revenir la pâte dans un peu d'huile 5 min.\n3. Ajouter boeuf + lait de coco + citronnelle écrasée + combava + toutes épices.\n4. Cuire à feu moyen 2h en mélangeant régulièrement — le lait de coco s'évapore progressivement.\n5. Continuer à feu doux encore 1h jusqu'à viande enrobée d'une pâte sèche brun-noir. C'est prêt.",vin:"Thé de Java ou eau fraîche",notes:"Le rendang est complètement différent d'un curry — le lait de coco s'évapore totalement et la viande se retrouve frite dans les huiles résiduelles."},
{id:"ID003",co:"Asie",cat:"Entrée",sous:"Salade",nom:"Gado Gado (Salade de Légumes Sauce Cacahuète)",chef:"Tradition javanaise",bp:4,prep:20,cui:10,diff:1,qual:4,ig:[["Légumes blanchis mélangés",600,"g"],["Tofu frit",200,"g"],["Oeufs durs",4,"pièces"],["Beurre de cacahuète",5,"cs"],["Lait de coco",10,"cl"],["Kecap manis",2,"cs"],["Jus citron vert",2,"cs"],["Ail",2,"gousses"],["Piment",1,"pièce"],["Crackers crevettes (krupuk)",1,"qs"]],et:"1. Blanchir haricots verts + pousses de soja + chou + carottes séparément. Rafraîchir.\n2. Frire le tofu jusqu'à croustillant.\n3. Sauce : beurre de cacahuète + lait de coco + kecap + lime + ail + piment. Chauffer en fouettant.\n4. Disposer légumes + tofu + oeufs coupés dans l'assiette.\n5. Napper de sauce chaude. Krupuk.",vin:"Thé glacé au jasmin",notes:"La sauce cacahuète chaude versée sur les légumes froids est la signature du gado gado. Krupuk = chips de crevettes."},
{id:"ID004",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Soto Ayam Javanais (Soupe de Poulet Épicée)",chef:"Tradition javanaise",bp:4,prep:20,cui:60,diff:2,qual:4,ig:[["Poulet entier",1500,"g"],["Curcuma frais",20,"g"],["Galanga",30,"g"],["Citronnelle",3,"tiges"],["Ail",6,"gousses"],["Échalotes",5,"pièces"],["Feuilles de combava",5,"pièces"],["Vermicelles de riz",200,"g"],["Oeufs durs",4,"pièces"],["Oignons frits crispy",3,"cs"],["Sel",1,"qs"]],et:"1. Cuire le poulet dans eau avec toutes les épices entières (sauf vermicelles). Frémir 45 min.\n2. Retirer poulet. Effilocher la chair. Filtrer et clarifier le bouillon.\n3. Cuire les vermicelles. Égoutter.\n4. Bols : vermicelles + poulet effiloché + oeuf coupé.\n5. Verser bouillon chaud. Oignons frits + oignons verts + kecap manis si désiré.",vin:"Thé de Java chaud",notes:"La couleur jaune du soto vient du curcuma frais — incomparable avec le curcuma en poudre."},
{id:"ID005",co:"Asie",cat:"Plat",sous:"Brochettes",nom:"Satay de Poulet Sauce Cacahuète",chef:"Tradition indonésienne",bp:4,prep:20,cui:10,diff:1,qual:5,ig:[["Blanc de poulet",700,"g"],["Curcuma",1,"cc"],["Coriandre moulue",1,"cc"],["Kecap manis",3,"cs"],["Huile",2,"cs"],["Beurre de cacahuète",6,"cs"],["Lait de coco",10,"cl"],["Ail",2,"gousses"],["Sauce soja",2,"cs"],["Lime",1,"pièce"],["Sucre de palme",1,"cs"]],et:"1. Couper poulet en dés. Mariner avec curcuma + coriandre + kecap + huile 1h.\n2. Enfiler sur brochettes en bois (préalablement trempées).\n3. Sauce : beurre de cacahuète + lait de coco + ail + soja + sucre + lime. Chauffer en mélangeant.\n4. Griller les satays sur braise vive 3-4 min par face jusqu'à légèrement brûlés.\n5. Servir avec sauce cacahuète + concombre + oignons rouges.",vin:"Bière Bintang ou thé glacé",notes:"Les brochettes doivent être grillées sur braise de charbon de bois pour le goût fumé authentique."},
{id:"ID006",co:"Asie",cat:"Accompagnement",sous:"Légumes",nom:"Tempe Goreng (Tempeh Frit Épicé)",chef:"Tradition javanaise",bp:4,prep:10,cui:10,diff:1,qual:4,ig:[["Tempeh",400,"g"],["Ail",4,"gousses"],["Galanga",10,"g"],["Curcuma",1,"cc"],["Piment rouge",2,"pièces"],["Kecap manis",2,"cs"],["Huile pour friture",1,"L"],["Sel",1,"qs"]],et:"1. Couper le tempeh en tranches ou dés.\n2. Mixer ail + galanga + curcuma + piment + sel en pâte.\n3. Frotter le tempeh avec la pâte d'épices. Mariner 30 min.\n4. Frire à 170°C jusqu'à doré et croustillant 4-5 min.\n5. Égoutter. Arroser de kecap manis.",vin:"Accompagnement de riz javanais",notes:"Le tempeh est du soja fermenté indonésien — plus nutritif que le tofu, avec un goût de champignon et de noisette."},
{id:"ID007",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Es Teler (Dessert Glacé Indonésien)",chef:"Tradition indonésienne",bp:4,prep:20,cui:0,diff:1,qual:4,ig:[["Avocat mûr",2,"pièces"],["Jackfruit en boîte",200,"g"],["Noix de coco râpée jeune",150,"g"],["Lait concentré sucré",6,"cs"],["Lait de coco",20,"cl"],["Sirop de sucre de palme",4,"cs"],["Glace pilée",1,"qs"],["Perles de sagou roses cuites",100,"g"]],et:"1. Couper avocat en dés. Égoutter jackfruit, couper en morceaux.\n2. Mélanger lait de coco + lait concentré sucré + sirop de palme.\n3. Dans de grands verres : couche de glace pilée.\n4. Disposer avocat + jackfruit + noix de coco jeune + sagou.\n5. Verser la sauce coco sucrée. Servir immédiatement.",vin:"Rafraîchissement de street food indonésienne",notes:"L'avocat sucré est une spécialité indonésienne — en Asie du Sud-Est, l'avocat est un fruit pour dessert."},
{id:"ID008",co:"Asie",cat:"Plat",sous:"Agneau",nom:"Gulai Kambing (Curry d'Agneau à l'Aceh)",chef:"Tradition d'Aceh - Sumatra",bp:4,prep:20,cui:90,diff:2,qual:4,ig:[["Agneau en cubes",800,"g"],["Lait de coco",60,"cl"],["Oignons",2,"pièces"],["Ail",5,"gousses"],["Galanga gingembre",1,"qs"],["Citronnelle",3,"tiges"],["Curcuma piment coriandre",1,"qs"],["Cardamome étoile de badiane",1,"qs"],["Sel",1,"qs"]],et:"1. Mixer oignons + ail + galanga + gingembre + curcuma + piment en pâte.\n2. Faire revenir la pâte 5 min. Ajouter épices entières.\n3. Ajouter agneau. Dorer 10 min.\n4. Verser lait de coco + citronnelle + 10cl eau. Frémir.\n5. Mijoter 1h30 à feu doux jusqu'à viande fondante et sauce réduite.",vin:"Thé d'Aceh très fort",notes:"Le gulai est plus liquide que le rendang — il conserve une sauce crémeuse au lait de coco."},
{id:"ID009",co:"Asie",cat:"Sauce / Base",sous:"Condiment",nom:"Sambal Oelek Maison",chef:"Tradition indonésienne universelle",bp:8,prep:10,cui:5,diff:1,qual:5,ig:[["Piments rouges frais",200,"g"],["Ail",4,"gousses"],["Vinaigre blanc",2,"cs"],["Sel",1,"cc"],["Sucre",1,"cc"],["Huile d'arachide",2,"cs"]],et:"1. Retirer les graines des piments si moins de piquant désiré.\n2. Mixer piments + ail grossièrement — ne pas réduire en purée lisse.\n3. Chauffer l'huile. Faire revenir le mélange 3-4 min.\n4. Ajouter vinaigre + sel + sucre. Cuire encore 2 min.\n5. Refroidir. Se conserve 2 semaines au froid.",vin:"Condiment universel de la cuisine indonésienne",notes:"Le sambal oelek authentique garde des morceaux — pas une sauce lisse. C'est le condiment de base de toute la cuisine archipel."},
{id:"ID010",co:"Asie",cat:"Entrée",sous:"Soupe",nom:"Bakso (Soupe de Boulettes de Boeuf)",chef:"Tradition indonésienne",bp:4,prep:30,cui:30,diff:2,qual:4,ig:[["Boeuf haché très fin",400,"g"],["Fécule de tapioca",4,"cs"],["Ail",3,"gousses"],["Sel poivre blanc",1,"qs"],["Bouillon de boeuf",150,"cl"],["Nouilles jaunes cuites",300,"g"],["Bok choy",200,"g"],["Oignons frits",2,"cs"],["Sauce soja kecap manis sambal",1,"qs"]],et:"1. Boulettes : mixer boeuf + fécule + ail + sel + poivre jusqu'à pâte lisse et élastique.\n2. Former des boulettes de 3cm en humidifiant les mains.\n3. Cuire dans eau bouillante salée 8-10 min jusqu'à remonter à la surface.\n4. Bouillon : chauffer bouillon de boeuf + sel + poivre.\n5. Bols : nouilles + bok choy blanchi + boulettes. Bouillon chaud. Oignons frits + sauce soja + kecap + sambal.",vin:"Thé javanais ou eau fraîche",notes:"La fécule de tapioca est essentielle pour la texture rebondissante caractéristique des bakso. Plus élastique que la maïzena."},
{id:"IN001",co:"Asie",cat:"Plat",sous:"Dal",nom:"Dal Makhani Ghee (Cuisson 24 h, Recette Vivek Singh — Cinnamon Club)",chef:"Vivek Singh (★, Cinnamon Club, Londres)",bp:6,prep:20,cui:240,diff:3,qual:5,ig:[["Lentilles noires entières (urad dal sabut)",300,"g"],["Haricots rouges rajma",80,"g"],["Ghee maison ou Khoormy",100,"g"],["Oignon doux",2,"pièces"],["Tomates pelées San Marzano",400,"g"],["Ail",6,"gousses"],["Gingembre frais",4,"cm"],["Piment vert",2,"pièces"],["Garam masala maison",2,"cs"],["Cumin moulu",2,"cc"],["Cumin en graines",1,"cc"],["Coriandre moulue",2,"cs"],["Curcuma",1,"cc"],["Piment Kashmiri",2,"cc"],["Crème fraîche fluide",15,"cl"],["Beurre demi-sel",60,"g"],["Méthi feuilles séchées (kasuri méthi — signature)",2,"cc"],["Charbon (technique \"dhungar\")",1,"morceau"]],et:"TREMPAGE PROLONGÉ (J-1) :\n1. La VEILLE : tremper urad dal + rajma dans 2 L d'eau froide salée 12 H minimum. Égoutter, rincer.\nCUISSON LONGUE (la magie 24 h Vivek Singh) :\n2. Dans une cocotte en fonte épaisse, mettre lentilles + haricots + 2 L eau + 1 cc sel. Porter à frémissement.\n3. Frémir À FEU TRÈS DOUX 4 H minimum (Vivek Singh recommande 8 H). Les lentilles doivent fondre, créer un liquide crémeux naturellement.\n4. Écraser légèrement à la cuillère pour libérer plus d'amidon. Continuer 30 min de plus.\nTARKA (la signature indienne — base aromatique) :\n5. Dans une grande poêle, faire fondre 60 g de ghee à feu moyen. Ajouter cumin en graines, faire crépiter 30 sec.\n6. Ajouter oignon haché finement. Frire 12 min jusqu'à brun doré profond (caramélisation = âme de la sauce).\n7. Ajouter ail râpé + gingembre râpé + piment vert haché. 2 min en remuant.\n8. Ajouter cumin moulu + coriandre + curcuma + Kashmiri. Cuire 1 min.\n9. Ajouter tomates écrasées. Frémir 12 min en remuant jusqu'à séparation de l'huile (signature \"baghara\" — quand la graisse remonte = tomates cuites).\nFUSION TARKA + DAL :\n10. Verser la tarka dans le dal cuit. Mélanger. Frémir 30 min de plus à feu doux — les saveurs fusionnent.\n11. Ajouter crème fraîche + beurre + garam masala + 1 cc kasuri méthi écrasé entre les paumes (libère son arôme).\nFINITION DHUNGAR (la signature Vivek Singh — fumage au charbon) :\n12. Faire chauffer un morceau de charbon de bois sur la flamme jusqu'à incandescent rouge.\n13. Poser un petit ramequin en métal au centre du dal. Y placer le charbon. Verser 1 cc ghee sur le charbon — la fumée s'élève instantanément.\n14. COUVRIR HERMÉTIQUEMENT 8 minutes — la fumée infuse profondément le dal, donnant le parfum tandoor authentique. Geste signature Cinnamon Club.\n15. Découvrir, retirer le ramequin de charbon. Mélanger.\nSERVICE :\n16. Servir dans bols traditionnels indiens, garni de coriandre fraîche + filet de crème fluide + 1 cc kasuri méthi sec en finition.\n17. Accompagner OBLIGATOIREMENT de riz basmati Khichdi + naan kulcha au beurre + raita de concombre + papadum croustillant + lassi salé.",vin:"Lassi salé épicé ou bière indienne Kingfisher Premium",notes:"Vivek Singh (★ Cinnamon Club Londres) : \"Le dal makhani est l'un des plats les plus complexes de l'Inde — sa cuisson lente sur 8-24 h libère naturellement les amidons des lentilles, créant l'onctuosité unique. La technique 'dhungar' (fumage au charbon) est la signature des grandes maisons du Punjab. Préparer la veille, manger le lendemain — encore meilleur.\""},
{id:"IN002",co:"Asie",cat:"Entrée",sous:"Pain naan / Inde",nom:"Naan au Beurre, Ail et Coriandre (Tandoor à 500°C — Recette Atul Kochhar)",chef:"Atul Kochhar (★ Benares, Londres)",bp:8,prep:120,cui:8,diff:3,qual:5,ig:[["Farine T55 forte (atta préférable)",500,"g"],["Levure de boulanger fraîche",10,"g"],["Yaourt grec entier 10%",150,"g"],["Lait entier tiède",15,"cl"],["Sucre",1,"cs"],["Sel fin",10,"g"],["Œuf entier",1,"pièce"],["Beurre clarifié ghee",80,"g"],["Ail râpé fin",4,"gousses"],["Coriandre fraîche ciselée",1,"bouquet"],["Graines de nigelle (kalonji)",1,"cs"]],et:"PRÉ-FERMENTATION (technique tandoor) :\n1. Délayer levure + sucre dans lait tiède 38°C, attendre 10 min jusqu'à mousse.\n2. Mélanger farine + sel + nigelle. Faire un puits.\n3. Ajouter yaourt + œuf + ghee fondu + levure activée. Pétrir 10 min — pâte souple, lisse, légèrement collante.\n4. Bouler, huiler, couvrir d'un film. Lever 90 min à 25°C jusqu'à doublé.\nFAÇONNAGE TRADITIONNEL :\n5. Diviser en 8 boules de 100 g. Bouler, laisser détendre 15 min sous torchon.\n6. Étaler chaque boule en goutte ou ovale de 25 cm sur 4 mm — la signature naan est cette forme allongée caractéristique du tandoor.\nCUISSON SIMULATION TANDOOR (technique Atul Kochhar pour cuisine domestique) :\n7. Préchauffer une PIERRE RÉFRACTAIRE au four 250°C MAX 45 min — recrée la chaleur du tandoor.\n8. Mouiller un côté du naan (geste sacré qui donne l'humidité tandoor authentique). Coller sur la pierre brûlante.\n9. Cuire 90 secondes — le naan gonfle, fait des poches, marquage tâcheté.\n10. Passer 30 sec sous le grill maximum — le dessus prend des taches noires (signature tandoor).\nFINITION :\n11. À la sortie, badigeonner GÉNÉREUSEMENT de ghee fondu + ail râpé + coriandre. Sel.\n12. Plier en éventail dans torchon. Servir CHAUD avec curry, dal makhani, raita.",vin:"Lassi salé ou bière indienne Kingfisher",notes:"Atul Kochhar (★ Benares Londres — premier chef indien étoilé en Europe) : la pierre réfractaire 250°C + mouillage du naan = approximation domestique du tandoor 500°C. Le mouillage est crucial — c'est la vapeur qui fait gonfler. Ghee + ail au sortir, jamais avant cuisson."},
{id:"IN003",co:"Asie",cat:"Plat",sous:"Curry / Delhi",nom:"Butter Chicken Murgh Makhani Authentique (Recette Kundan Lal Jaggi 1948)",chef:"Kundan Lal Jaggi (créateur 1948, Moti Mahal Delhi)",bp:4,prep:30,cui:50,diff:3,qual:5,ig:[["Cuisses de poulet désossées",800,"g"],["Yaourt entier (marinade)",150,"g"],["Garam masala",2,"cc"],["Curcuma",1,"cc"],["Piment Kashmiri (couleur sans piquant excessif)",2,"cc"],["Cumin",1,"cc"],["Citron (jus)",2,"cs"],["Ail râpé",6,"gousses"],["Gingembre râpé",4,"cm"],["Beurre demi-sel",100,"g"],["Ghee",30,"g"],["Tomates Roma mûres",1000,"g"],["Cardamome verte",4,"pièces"],["Cannelle bâton",1,"pièce"],["Crème fleurette 35%",25,"cl"],["Miel de fleurs",2,"cs"],["Kasuri méthi (méthi séché)",2,"cc"],["Coriandre fraîche",1,"bouquet"]],et:"MARINADE 4 H (étape capitale) :\n1. Mélanger : yaourt + 1 cs ail râpé + 1 cs gingembre râpé + 1 cc garam masala + curcuma + Kashmiri + cumin + jus de citron + sel.\n2. Enrober les cuisses de poulet (entières ou en gros morceaux). Filmer, réfrigérer 4-12 h.\nGRILLAGE TIKKA (technique Moti Mahal) :\n3. Préchauffer four 250°C avec grille du haut.\n4. Enfiler le poulet sur brochettes ou disposer sur grille au-dessus de plaque. Cuire sous grill 8-10 min jusqu'à colorations brûlées (effet tandoor maison). Effilocher en gros morceaux.\nSAUCE MAKHANI (la signature 1948 — onctuosité légendaire) :\n5. Faire bouillir les tomates entières dans 50 cl d'eau + cardamome + cannelle + 2 gousses ail + 1 cm gingembre 25 min jusqu'à éclatées.\n6. Mixer, filtrer 2 fois au chinois étamine — texture velours obligatoire.\n7. Dans une cocotte, fondre 80 g beurre + ghee. Ajouter le reste d'ail + gingembre. Cuire 2 min.\n8. Verser la purée de tomates filtrée. Frémir 15 min jusqu'à concentration.\n9. Ajouter crème + miel + 1 cc Kasuri méthi écrasé. Frémir 5 min — la sauce devient orange-rouge brillante.\n10. Incorporer le poulet grillé. Frémir 8 min pour imprégner.\n11. Hors feu, ajouter 20 g beurre froid (montage final — onctuosité signature) + 1 cc Kasuri méthi.\nSERVICE :\n12. Garnir de coriandre + filet de crème + Kasuri méthi.\n13. Accompagner de riz basmati + naan kulcha + raita.",vin:"Lassi mangue ou Riesling Mosel demi-sec",notes:"Kundan Lal Jaggi (Moti Mahal Delhi — créateur 1948) : il a inventé le butter chicken pour réutiliser le poulet tandoori invendu en le réchauffant dans une sauce tomate-beurre. La technique : double cuisson (tikka grillé puis bain dans makhani). Le Kasuri méthi en finition est non négociable. La sauce doit être ORANGE BRILLANT, jamais brun-rouge."},
{id:"IN004",co:"Asie",cat:"Plat",sous:"Végétarien",nom:"Chana Masala (Pois Chiches Épicés)",chef:"Tradition punjabi",bp:6,prep:15,cui:40,diff:1,qual:4,ig:[["Pois chiches cuits",800,"g"],["Oignons",2,"pièces"],["Tomates concassées",400,"g"],["Ail gingembre",1,"qs"],["Cumin graines",1,"cc"],["Garam masala",2,"cc"],["Coriandre en poudre",1,"cc"],["Curcuma piment de Cayenne",1,"qs"],["Huile ou ghee",3,"cs"],["Coriandre fraîche",1,"bouquet"],["Citron",1,"pièce"]],et:"1. Chauffer l'huile. Faire crépiter les graines de cumin 30 sec. Ajouter oignons hachés, suer 10 min jusqu'à dorés.\n2. Ajouter ail + gingembre râpés. Cuire 2 min. Ajouter tomates + épices. Cuire 10 min.\n3. Incorporer les pois chiches. Mélanger. Ajouter un peu d'eau si nécessaire.\n4. Frémir 15-20 min en écrasant légèrement quelques pois chiches pour épaissir.\n5. Jus de citron + coriandre fraîche ciselée. Servir avec riz basmati ou chapati.",vin:"Bière Kingfisher ou lassi salé au cumin",notes:"Écraser quelques pois chiches contre les parois de la casserole épaissit naturellement la sauce."},
{id:"IN005",co:"Asie",cat:"Plat",sous:"Agneau",nom:"Rogan Josh (Curry d'Agneau du Cachemire)",chef:"Tradition cachemirie",bp:6,prep:20,cui:80,diff:2,qual:4,ig:[["Épaule d'agneau en cubes",1000,"g"],["Yaourt entier",200,"g"],["Oignons",3,"pièces"],["Tomates concassées",300,"g"],["Ail gingembre",1,"qs"],["Paprika kashmir (Kashmiri mirch)",3,"cs"],["Garam masala",1,"cs"],["Cardamome clou girofle cannelle",1,"qs"],["Ghee",4,"cs"],["Coriandre fraîche",1,"bouquet"]],et:"1. Fondre le ghee. Faire crépiter les épices entières (cardamome + clou + cannelle). Suer oignons hachés 15 min jusqu'à très dorés.\n2. Ajouter ail + gingembre. Cuire 2 min. Incorporer le paprika kashmiri (donne la couleur rouge).\n3. Ajouter l'agneau. Dorer sur toutes les faces. Incorporer le yaourt cuillère par cuillère en remuant.\n4. Ajouter tomates + garam masala + sel. Un peu d'eau si nécessaire. Cuire à couvert 1h à feu doux.\n5. Parsemer de coriandre fraîche.",vin:"Riesling Alsace ou Gewurztraminer ; bière Kingfisher",notes:"Le paprika kashmiri donne une couleur rouge intense sans trop piquer - ne pas le remplacer par du piment ordinaire."},
{id:"IN006",co:"Asie",cat:"Dessert",sous:"Kheer",nom:"Kheer (Riz au Lait Indien)",chef:"Tradition indienne",bp:6,prep:10,cui:60,diff:1,qual:4,ig:[["Riz basmati",60,"g"],["Lait entier",150,"cl"],["Sucre",80,"g"],["Cardamome moulue",0.5,"cc"],["Eau de rose",2,"cs"],["Pistaches effilées",40,"g"],["Amandes effilées",30,"g"],["Safran",0.1,"g"],["Lait chaud pour le safran",2,"cs"]],et:"1. Rincer le riz. Cuire dans le lait à feu doux en remuant souvent pendant 45-50 min jusqu'à riz très tendre et lait épaissi.\n2. Ajouter le sucre. Cuire encore 10 min.\n3. Infuser le safran dans 2cs de lait chaud. Incorporer dans le kheer avec cardamome + eau de rose.\n4. Refroidir ou servir tiède selon préférence.\n5. Garnir de pistaches + amandes effilées.",vin:"Chai (thé indien masala) ou lassi mangue",notes:"Le kheer est le dessert de fête par excellence en Inde. Une longue cuisson lente est indispensable pour le concentrer."},
{id:"IN007",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Chicken Tikka Masala",chef:"Tradition britannique d'origine indienne",bp:4,prep:30,cui:30,diff:2,qual:4,ig:[["Poulet en cubes",700,"g"],["Yaourt entier",150,"g"],["Pâte tikka (gingembre ail piment curcuma)",3,"cs"],["Beurre ghee",40,"g"],["Oignons",2,"pièces"],["Tomates concassées",400,"g"],["Crème fraîche",20,"cl"],["Paprika fumé",1,"cc"],["Garam masala",1,"cc"],["Coriandre fraîche",1,"bouquet"]],et:"1. Mariner poulet dans yaourt + pâte tikka 4h. Griller sous le gril très chaud jusqu'à légèrement carbonisé. Réserver.\n2. Suer oignons dans ghee jusqu'à dorés. Ajouter paprika + garam masala.\n3. Ajouter tomates. Frémir 10 min. Mixer la sauce. Filtrer si désiré.\n4. Ajouter crème fraîche. Porter à frémissement.\n5. Ajouter le poulet grillé. Cuire 10 min. Parsemer coriandre.",vin:"Bière Cobra ou Riesling demi-sec",notes:"Techniquement né en Grande-Bretagne dans les restaurants indiens, c'est le plat le plus commandé du monde anglophone."},
{id:"IN008",co:"Asie",cat:"Plat",sous:"Végétarien",nom:"Palak Paneer (Épinards au Fromage)",chef:"Tradition punjabi et north-indienne",bp:4,prep:20,cui:25,diff:1,qual:4,ig:[["Épinards frais",800,"g"],["Paneer (fromage indien)",300,"g"],["Oignons",2,"pièces"],["Tomates",2,"pièces"],["Ail gingembre",1,"qs"],["Cumin graines",1,"cc"],["Garam masala curcuma piment",1,"qs"],["Crème fraîche",6,"cs"],["Ghee",3,"cs"]],et:"1. Blanchir les épinards 2 min. Mixer en purée lisse.\n2. Dorer les cubes de paneer dans ghee jusqu'à dorés. Réserver.\n3. Faire crépiter cumin dans ghee. Suer oignons + ail + gingembre.\n4. Ajouter tomates + épices. Cuire 8 min. Incorporer purée d'épinards. Cuire 5 min.\n5. Ajouter paneer + crème fraîche. Chauffer doucement 3 min. Servir avec naan.",vin:"Bière Kingfisher ou lassi salé au cumin",notes:"Le paneer maison est simple : faire cailler du lait chaud avec du jus de citron, filtrer dans une étamine."},
{id:"IN009",co:"Asie",cat:"Dessert",sous:"Douceur",nom:"Gulab Jamun",chef:"Tradition moghol et indienne",bp:20,prep:30,cui:30,diff:2,qual:4,ig:[["Lait entier en poudre",200,"g"],["Farine T55",30,"g"],["Beurre",20,"g"],["Lait pour pétrir",6,"cs"],["Levure chimique",0.5,"cc"],["Sucre pour sirop",400,"g"],["Eau pour sirop",40,"cl"],["Eau de rose",2,"cs"],["Cardamome",4,"gousses"],["Safran",0.1,"g"],["Huile pour frire",1,"L"]],et:"Sirop :\n1. Bouillir sucre + eau + cardamome + safran 5 min. Ajouter eau de rose. Maintenir tiède.\nBoulettes :\n2. Mélanger lait en poudre + farine + levure + beurre. Ajouter lait progressivement jusqu'à pâte souple non collante.\n3. Former 20 petites boules lisses sans craquelures.\n4. Frire à 160°C (feu doux) 8-10 min en remuant doucement. Ils doivent dorer uniformément.\n5. Plonger les boulettes chaudes dans le sirop tiède. Laisser absorber 2h.",vin:"Thé masala chai très sucré",notes:"Les boulettes doivent être frites à basse température pour cuire uniformément. Dans le sirop chaud elles gonflent et deviennent spongieuses."},
{id:"IN010",co:"Asie",cat:"Plat",sous:"Légumineuses",nom:"Rajma Masala (Haricots Rouges Épicés)",chef:"Tradition du Punjab",bp:6,prep:15,cui:60,diff:1,qual:4,ig:[["Haricots rouges cuits",600,"g"],["Oignons",2,"pièces"],["Tomates concassées",400,"g"],["Ail gingembre",1,"qs"],["Cumin graines",1,"cc"],["Coriandre moulue",2,"cc"],["Garam masala",1,"cc"],["Curcuma piment",1,"qs"],["Huile ghee",3,"cs"],["Coriandre fraîche beurre",1,"qs"]],et:"1. Faire crépiter cumin dans l'huile. Suer oignons jusqu'à dorés (15 min).\n2. Ajouter ail + gingembre râpés. Cuire 2 min. Ajouter tomates + épices. Cuire 10 min.\n3. Incorporer les haricots rouges + 20cl eau. Écraser légèrement quelques haricots.\n4. Frémir à couvert 20-25 min jusqu'à sauce dense.\n5. Finir avec noix de beurre + coriandre. Servir avec riz basmati.",vin:"Bière Kingfisher ou lassi",notes:"Le rajma chawal (haricots rouges + riz) est l'un des plats végétariens les plus réconfortants du Punjab."},
{id:"IN011",co:"Asie",cat:"Plat",sous:"Curry",nom:"Saag Paneer (Épinards au Fromage Indien)",chef:"Tradition du Pendjab",bp:4,prep:15,cui:25,diff:2,qual:4,ig:[["Épinards frais",800,"g"],["Paneer en cubes",300,"g"],["Oignons",2,"pièces"],["Tomates",2,"pièces"],["Ail gingembre pâte",3,"cs"],["Cumin",1,"cc"],["Garam masala",1,"cc"],["Coriandre moulue",2,"cc"],["Crème fraîche",4,"cs"],["Huile ghee",3,"cs"],["Sel",1,"qs"]],et:"1. Blanchir les épinards 2 min. Égoutter. Mixer en purée grossière.\n2. Frire le paneer dans ghee jusqu'à doré. Réserver.\n3. Dans la même poêle : cumin dans huile jusqu'à crépitement. Ajouter oignons. Dorer 8 min.\n4. Ail-gingembre + épices + tomates. Cuire 10 min.\n5. Ajouter purée d'épinards + paneer. Cuire 5 min. Crème fraîche. Rectifier.",vin:"Bière Kingfisher ou lassi à la mangue",notes:"Le paneer frit est incomparable — il développe une légère croûte dorée tout en restant souple à l'intérieur."},
{id:"IN012",co:"Asie",cat:"Plat",sous:"Riz",nom:"Biryani de Poulet Hyderabadi",chef:"Tradition de Hyderabad",bp:6,prep:30,cui:60,diff:3,qual:5,ig:[["Poulet en morceaux",1200,"g"],["Riz basmati",500,"g"],["Yaourt",150,"g"],["Oignons frits croustillants",100,"g"],["Safran",0.3,"g"],["Lait tiède",5,"cs"],["Ghee",4,"cs"],["Menthe fraîche",1,"bouquet"],["Garam masala",2,"cc"],["Ail gingembre pâte",3,"cs"],["Piment rouge",1,"cs"],["Huile",4,"cs"]],et:"1. Mariner poulet dans yaourt + ail-gingembre + épices + piment 2h.\n2. Cuire riz basmati à 70%. Égoutter.\n3. Dans grande cocotte : couche de poulet mariné. Couche de riz. Safran dans lait tiède. Oignons frits. Ghee. Menthe.\n4. Répéter les couches. Sceller hermétiquement avec pâte de farine ou couvercle lourd.\n5. Cuire Dum (basse T°) : 20 min à feu vif puis 30 min à très doux. Ouvrir à table.",vin:"Lassi nature ou Kingfisher",notes:"Le dum (cuisson à l'étouffée scellée) est l'essence du biryani — la vapeur circulante cuit uniformément."},
{id:"IN013",co:"Asie",cat:"Entrée",sous:"Pain",nom:"Naan au Beurre et à l'Ail au Four",chef:"Tradition du Pendjab",bp:8,prep:30,cui:10,diff:2,qual:4,ig:[["Farine T45",500,"g"],["Yaourt",150,"g"],["Lait tiède",15,"cl"],["Levure fraîche",15,"g"],["Sucre",1,"cc"],["Sel",1,"cc"],["Ghee ou beurre",60,"g"],["Ail haché",4,"gousses"],["Coriandre fraîche",3,"cs"]],et:"1. Dissoudre levure + sucre dans lait tiède 10 min.\n2. Mélanger farine + sel + yaourt + levure. Pétrir 10 min jusqu'à pâte souple. Lever 1h.\n3. Diviser en 8 boules. Étaler en ovals de 3mm.\n4. Cuire au four préchauffé à 250°C sur pierre ou plaque brûlante 3-4 min jusqu'à cloqués.\n5. Badigeonner de ghee + ail + coriandre immédiatement.",vin:"Lassi ou thé chai",notes:"La plaque ou pierre brûlante est critique — elle simule le tandoor. Préchauffer 30 min au minimum."},
{id:"IN014",co:"Asie",cat:"Plat",sous:"Agneau",nom:"Rogan Josh Authentique du Cachemire",chef:"Tradition cachemirie",bp:4,prep:20,cui:75,diff:2,qual:5,ig:[["Gigot d'agneau en cubes",800,"g"],["Yaourt",150,"g"],["Oignons",3,"pièces"],["Ail gingembre",1,"qs"],["Cardamome noire",3,"pièces"],["Cannelle bâton",2,"pièces"],["Clous de girofle",5,"pièces"],["Piment du Cachemire (Kashmiri)",2,"cs"],["Graines de fenouil",1,"cc"],["Huile de moutarde",4,"cs"],["Sel",1,"qs"]],et:"1. Chauffer huile de moutarde jusqu'à fumer. Y mettre épices entières jusqu'à crépitement.\n2. Dorer oignons émincés 15 min jusqu'à profondément colorés.\n3. Ail-gingembre + Kashmiri piment. Cuire 5 min.\n4. Ajouter agneau. Dorer 10 min. Ajouter yaourt cuillère par cuillère en mélangeant constamment.\n5. Ajouter eau à hauteur. Mijoter 1h jusqu'à viande fondante. Fenouil en finition.",vin:"Kingfisher ou lassi salé",notes:"Le piment du Cachemire (Kashmiri) donne la couleur rouge caractéristique sans piquant excessif."},
{id:"IN015",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Gulab Jamun (Beignets dans le Sirop)",chef:"Tradition indienne",bp:20,prep:20,cui:20,diff:2,qual:4,ig:[["Lait en poudre",200,"g"],["Farine T55",60,"g"],["Levure chimique",0.5,"cc"],["Beurre fondu",30,"g"],["Lait",8,"cs"],["Sucre pour sirop",400,"g"],["Eau pour sirop",35,"cl"],["Eau de rose",2,"cs"],["Cardamome moulue",0.5,"cc"],["Safran",1,"pincée"],["Huile pour friture",1,"L"]],et:"1. Sirop : bouillir eau + sucre + eau de rose + cardamome + safran 5 min. Réserver chaud.\n2. Pâte : lait en poudre + farine + levure + beurre + lait. Mélanger jusqu'à pâte douce et non collante.\n3. Former des boulettes lisses de 2cm.\n4. Frire à 140°C (feu très doux) 6-8 min en retournant jusqu'à brun acajou uniformément.\n5. Plonger immédiatement dans le sirop chaud. Laisser tremper 30 min minimum.",vin:"Thé chai ou café indien",notes:"La friture doit être très douce — les beignets doivent cuire uniformément à coeur avant de brunir à l'extérieur."},
{id:"IN016",co:"Asie",cat:"Plat",sous:"Vegetarien",nom:"Chana Masala Épicé (Pois Chiches)",chef:"Tradition du Pendjab",bp:4,prep:15,cui:30,diff:1,qual:4,ig:[["Pois chiches cuits",600,"g"],["Oignons",2,"pièces"],["Tomates",3,"pièces"],["Ail gingembre pâte",2,"cs"],["Coriandre moulue",2,"cc"],["Cumin",1,"cc"],["Garam masala",1,"cc"],["Amchur (mangue séchée)",1,"cc"],["Piment rouge",1,"cc"],["Huile",4,"cs"],["Coriandre fraîche",1,"bouquet"]],et:"1. Dorer oignons 10 min dans huile. Ajouter ail-gingembre. Cuire 3 min.\n2. Tomates + toutes les épices sauf garam masala. Cuire 10 min jusqu'à masala condensée.\n3. Écraser légèrement les pois chiches (30%) pour épaissir.\n4. Ajouter pois chiches + 10cl eau. Cuire 15 min.\n5. Garam masala + amchur en finition. Coriandre fraîche.",vin:"Lassi à la mangue ou Kingfisher",notes:"L'amchur (poudre de mangue verte) apporte l'acidité fruitée caractéristique du chana masala du Pendjab."},
{id:"IN017",co:"Asie",cat:"Plat",sous:"Curry",nom:"Korma d'Agneau aux Noix de Cajou",chef:"Tradition moghole",bp:4,prep:20,cui:60,diff:2,qual:5,ig:[["Agneau en cubes",700,"g"],["Yaourt",200,"g"],["Noix de cajou",80,"g"],["Oignons",2,"pièces"],["Crème fraîche",10,"cl"],["Eau de rose",1,"cs"],["Cardamome verte",5,"pièces"],["Safran",0.2,"g"],["Garam masala",1,"cc"],["Ghee",4,"cs"],["Sel",1,"qs"]],et:"1. Mixer noix de cajou avec un peu d'eau en pâte lisse.\n2. Dorer oignons dans ghee jusqu'à profondément caramel. Mixer en purée.\n3. Dans la cocotte : ghee + cardamome. Ajouter agneau. Dorer.\n4. Ajouter purée d'oignons + yaourt cuillère par cuillère + pâte de cajou + safran.\n5. Mijoter 45 min. Crème + eau de rose en finition. Ne plus bouillir.",vin:"Champagne demi-sec ou Riesling moelleux",notes:"Le korma moghole est la cuisine de la cour impériale — doux, crémeux, sans piment. La pâte de cajou est son secret."},
{id:"IN018",co:"Asie",cat:"Accompagnement",sous:"Pain",nom:"Paratha aux Pommes de Terre (Aloo Paratha)",chef:"Tradition du Pendjab",bp:4,prep:30,cui:15,diff:2,qual:4,ig:[["Farine complète (atta)",400,"g"],["Eau tiède",20,"cl"],["Pommes de terre cuites écrasées",400,"g"],["Piment vert haché",2,"pièces"],["Gingembre râpé",1,"cs"],["Coriandre fraîche",3,"cs"],["Cumin",1,"cc"],["Sel",1,"cs"],["Ghee ou beurre",60,"g"]],et:"1. Pâte : farine + sel + eau. Pétrir 8 min. Reposer 30 min.\n2. Farce : pommes de terre + piment + gingembre + coriandre + cumin + sel. Bien mélanger.\n3. Boules de pâte. Étaler en disque. Déposer farce. Refermer comme une bourse. Étaler délicatement.\n4. Cuire sur tawa ou poêle à sec 2 min/face jusqu'à légèrement dorée.\n5. Badigeonner généreusement de ghee sur les deux faces.",vin:"Lassi salé ou chai masala",notes:"L'aloo paratha se mange au petit-déjeuner dans tout le Pendjab avec yaourt et pickle de mangue."},
{id:"IN019",co:"Asie",cat:"Plat",sous:"Mer",nom:"Fish Curry de Goa",chef:"Tradition catholique de Goa",bp:4,prep:15,cui:20,diff:2,qual:4,ig:[["Filets de poisson ferme",700,"g"],["Lait de coco",40,"cl"],["Tomates",2,"pièces"],["Oignons",1,"pièce"],["Ail gingembre pâte",2,"cs"],["Cumin coriandre",1,"qs"],["Curcuma",1,"cc"],["Piment rouge",1,"cc"],["Tamarin",2,"cs"],["Huile de coco",3,"cs"],["Coriandre fraîche",1,"bouquet"]],et:"1. Tremper tamarin dans eau chaude. Filtrer.\n2. Suer oignons dans huile de coco. Ail-gingembre + épices. Cuire 3 min.\n3. Ajouter tomates. Cuire 5 min.\n4. Verser lait de coco + jus de tamarin. Porter à frémissement.\n5. Ajouter le poisson. Cuire 8-10 min à feu très doux. Coriandre.",vin:"Bière Goan King ou Kingfisher",notes:"L'acidité du tamarin équilibre la douceur du lait de coco — signature du curry de Goa d'influence portugaise."},
{id:"IN020",co:"Asie",cat:"Dessert",sous:"Glace",nom:"Kulfi à la Pistache et Cardamome",chef:"Tradition moghole",bp:6,prep:15,cui:30,diff:2,qual:4,ig:[["Lait entier",150,"cl"],["Lait concentré sucré",40,"cl"],["Pistaches non salées",80,"g"],["Cardamome moulue",1,"cc"],["Eau de rose",2,"cs"],["Safran",0.2,"g"],["Sucre",2,"cs"]],et:"1. Faire réduire le lait à feu moyen de moitié en remuant régulièrement (30 min).\n2. Ajouter lait concentré + safran + cardamome + eau de rose. Cuire encore 5 min.\n3. Laisser tiédir. Incorporer pistaches hachées grossièrement.\n4. Verser dans des moules à kulfi ou petits ramequins. Insérer le bâtonnet.\n5. Congeler 6h minimum. Démouler sous eau tiède.",vin:"Thé chai ou café indien épicé",notes:"Le kulfi n'est pas turbiné — il congèle directement et a donc une texture plus dense et crémeuse que la glace."},
{id:"IN021",co:"Asie",cat:"Plat",sous:"Vegetarien",nom:"Dal Tadka (Lentilles au Beurre Clarifié)",chef:"Tradition du Nord de l'Inde",bp:4,prep:10,cui:30,diff:1,qual:4,ig:[["Lentilles corail",300,"g"],["Oignons",2,"pièces"],["Tomates",2,"pièces"],["Ail",5,"gousses"],["Gingembre",20,"g"],["Cumin en graines",1,"cc"],["Curcuma",0.5,"cc"],["Piment rouge",0.5,"cc"],["Ghee",3,"cs"],["Coriandre fraîche",1,"bouquet"],["Sel",1,"qs"]],et:"1. Cuire les lentilles dans 3 fois leur volume d'eau avec curcuma 20 min. Écraser grossièrement.\n2. Tadka : chauffer ghee jusqu'à fumant. Y frire graines de cumin jusqu'à crépitement.\n3. Ajouter ail émincé + gingembre. Dorer 1 min. Ajouter oignons. Cuire 8 min.\n4. Tomates + piment. Cuire 5 min.\n5. Verser le tadka sur les lentilles. Incorporer. Coriandre.",vin:"Lassi nature ou eau fraîche",notes:"Le tadka est l'opération de cuisson rapide des épices dans ghee brûlant qui est ensuite versé sur les lentilles."},
{id:"IN022",co:"Asie",cat:"Entrée",sous:"Friture",nom:"Samosa au Boeuf et Légumes",chef:"Tradition indienne",bp:16,prep:45,cui:20,diff:3,qual:4,ig:[["Farine T55",300,"g"],["Huile",4,"cs"],["Eau froide",15,"cl"],["Boeuf haché",300,"g"],["Pommes de terre cuites dés",200,"g"],["Pois verts",100,"g"],["Oignons",1,"pièce"],["Garam masala",1,"cc"],["Coriandre moulue",1,"cc"],["Gingembre haché",1,"cs"],["Huile pour friture",1,"L"]],et:"1. Pâte : farine + sel + huile (sabler). Eau froide progressivement. Pétrir 5 min. Reposer 30 min.\n2. Farce : dorer oignons + gingembre. Ajouter boeuf. Cuire. Ajouter pommes de terre + pois + épices.\n3. Abaisser pâte en cercles. Couper en demi-lunes. Former cônes. Farcir. Sceller soigneusement.\n4. Frire à 160°C 6-8 min jusqu'à dorés et croustillants.\n5. Servir avec chutney de menthe et chutney de tamarin.",vin:"Thé chai ou bière Kingfisher",notes:"L'eau froide et la pâte courte (pas trop pétrie) sont les secrets d'une pâte à samosa croustillante."},
{id:"IN023",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Murgh Makhani (Butter Chicken Authentique)",chef:"Tradition de Delhi",bp:4,prep:20,cui:40,diff:2,qual:5,ig:[["Poulet en morceaux",800,"g"],["Yaourt",150,"g"],["Tomates concassées",400,"g"],["Oignons",2,"pièces"],["Ail gingembre pâte",3,"cs"],["Crème fraîche",20,"cl"],["Beurre",80,"g"],["Cardamome fenouil cumin",1,"qs"],["Piment rouge doux",1,"cs"],["Garam masala",1,"cc"],["Sel sucre",1,"qs"]],et:"1. Mariner poulet dans yaourt + ail-gingembre + épices 4h. Griller ou rôtir.\n2. Sauce makhani : dorer oignons dans beurre. Ail-gingembre + épices. Ajouter tomates. Cuire 20 min.\n3. Mixer finement. Passer au chinois pour sauce ultra-lisse.\n4. Remettre sur feu. Ajouter poulet grillé. Incorporer crème fraîche + beurre froid.\n5. Pincée de sucre. Garam masala. Fenugrec séché (kasuri methi) si disponible.",vin:"Riesling demi-sec ou Gewurztraminer",notes:"La clé est la sauce ultra-lisse passée au chinois. Le kasuri methi (fenugrec séché) est la touche authentique de Delhi."},
{id:"IN024",co:"Asie",cat:"Accompagnement",sous:"Riz",nom:"Riz Basmati au Safran et Cardamome",chef:"Tradition moghole",bp:4,prep:5,cui:20,diff:1,qual:4,ig:[["Riz basmati",300,"g"],["Safran",0.2,"g"],["Lait tiède",3,"cs"],["Cardamome verte",4,"pièces"],["Clous de girofle",3,"pièces"],["Beurre",30,"g"],["Sel",1,"cc"],["Eau",50,"cl"]],et:"1. Rincer le riz 3 fois jusqu'à eau claire. Tremper 20 min. Égoutter.\n2. Infuser safran dans lait tiède 10 min.\n3. Dans casserole : beurre + cardamome + clous 1 min. Ajouter riz. Nacrer 2 min.\n4. Ajouter eau bouillante + sel. Porter à ébullition. Couvrir hermétiquement. Feu minimum 12 min.\n5. Hors feu 5 min. Verser lait safran. Égrener délicatement à la fourchette.",vin:"Accompagnement de tous les plats moghols",notes:"Le trempage 20 min permet aux grains de basmati de s'allonger sans se briser à la cuisson."},
{id:"IN025",co:"Asie",cat:"Sauce / Base",sous:"Condiment",nom:"Chutney à la Menthe et Coriandre",chef:"Tradition indienne",bp:6,prep:10,cui:0,diff:1,qual:4,ig:[["Menthe fraîche",100,"g"],["Coriandre fraîche",100,"g"],["Piment vert",2,"pièces"],["Ail",2,"gousses"],["Gingembre",10,"g"],["Jus de citron vert",3,"cs"],["Cumin en poudre",0.5,"cc"],["Sel",0.5,"cc"],["Sucre",0.5,"cc"]],et:"1. Laver soigneusement herbes. Retirer les tiges épaisses.\n2. Mixer menthe + coriandre + piment + ail + gingembre.\n3. Ajouter jus de citron vert + cumin + sel + sucre.\n4. Mixer jusqu'à sauce verte lisse. Ajouter un peu d'eau si trop épais.\n5. Goûter et ajuster l'équilibre acide-sucré-piquant.",vin:"Accompagnement universel des snacks et friture indiens",notes:"Ce chutney vert accompagne samosa, pakoras, naan et tout kebab. Se conserve 3 jours au froid."},
{id:"JP001",co:"Asie",cat:"Plat",sous:"Bowl / Japon",nom:"Gyudon Premium au Bœuf Wagyu (Style Yoshinoya Tradition)",chef:"Tradition japonaise (Yoshinoya 1899) + technique chef Tetsuya Wakuda",bp:4,prep:15,cui:18,diff:2,qual:5,ig:[["Bœuf entrecôte tranché très fin (3 mm — congelé 30 min facilite)",450,"g"],["Oignon doux",2,"pièces"],["Bouillon dashi (kombu + bonite)",30,"cl"],["Sauce soja Kikkoman shoyu",6,"cs"],["Mirin Hon-Mirin (jamais le sucré industriel)",4,"cs"],["Sake de qualité",4,"cs"],["Sucre de canne brun",2,"cs"],["Gingembre râpé frais",2,"cm"],["Riz japonica court grain (variété Koshihikari premium)",350,"g"],["Œufs frais bio (jaunes coulants — option 'tamago tsuke')",4,"pièces"],["Beni shoga (gingembre mariné rouge)",4,"cs"],["Oignons verts ciselés en biais",4,"tiges"],["Graines de sésame grillé blanc",2,"cs"],["Shichimi togarashi (7 épices japonaises — option)",1,"qs"]],et:"RIZ JAPONAIS (technique sushi traditionnelle) :\n1. Rincer le riz Koshihikari 5 fois à l'eau claire jusqu'à eau translucide. Tremper 30 min.\n2. Cuire dans 42 cl d'eau (ratio 1.2:1), couvert : ébullition + 12 min feu doux + 10 min repos hors feu.\n3. Aérer délicatement à la spatule en bois.\nSAUCE GYUDON DASHI (la signature) :\n4. Dans une grande sauteuse, mélanger : dashi + soja + mirin + sake + sucre + gingembre râpé.\n5. Porter à frémissement, faire réduire 4 min — la sauce doit légèrement épaissir et devenir brillante.\nCUISSON OIGNONS (technique en deux temps) :\n6. Émincer les oignons en demi-rondelles fines.\n7. Plonger dans la sauce frémissante. Cuire 6-7 min jusqu'à fondants et translucides imprégnés de la sauce.\nCUISSON BŒUF (rapidité absolue) :\n8. Ajouter le bœuf tranché très fin. CUIRE 90 SECONDES SEULEMENT — il doit juste cuire, rester nacré et tendre. Sur-cuisson = caoutchouteux.\n9. Goûter, rectifier (sauce soja si nécessaire).\nDRESSAGE GYUDON (signature Yoshinoya) :\n10. Répartir le riz chaud dans 4 grands bols.\n11. Disposer généreusement le bœuf et oignons SUR le riz — verser une louche de sauce dashi pour imbiber le riz (ne pas saturer).\n12. Casser un jaune d'œuf cru au centre (option 'tamago tsuke' — l'œuf cru est la touche traditionnelle Yoshinoya — il se mélange à chaud avec la viande).\n13. Garnir de beni shoga (rouge vibrant), oignons verts ciselés en biais, sésame grillé, shichimi togarashi optionnel.\n14. Servir IMMÉDIATEMENT — le bowl gyudon ne supporte pas l'attente.\n15. Convive : casser le jaune d'œuf, mélanger énergiquement avec le bœuf et le riz.",vin:"Saké junmai daiginjo froid (Hakkaisan, Niigata) ou bière Sapporo Premium",notes:"Tradition Yoshinoya (chaîne fondée 1899 à Tokyo) : le gyudon est le fast-food japonais authentique. La règle : oignons cuits à fond, bœuf cuit 90 sec MAX. La touche Tetsuya Wakuda (chef ★★★ Sydney) est l'utilisation de Wagyu A5 et le jaune d'œuf cru — apportent l'opulence sans trahir la simplicité du plat."},
{id:"JP002",co:"Asie",cat:"Plat",sous:"Nouilles wok / Osaka",nom:"Yakisoba à la Plancha Style Teppanyaki (Recette tradition Osaka)",chef:"Tradition Osaka (yatai street food)",bp:4,prep:20,cui:12,diff:2,qual:5,ig:[["Nouilles soba ou ramen fraîches (variété yakisoba men)",450,"g"],["Porc échine en lamelles (3 mm)",250,"g"],["Chou blanc émincé",250,"g"],["Carottes en julienne",1,"pièce"],["Poivron vert",1,"pièce"],["Pousses de soja fraîches",100,"g"],["Oignons verts",4,"tiges"],["Sauce yakisoba Otafuku (la référence Osaka)",6,"cs"],["Sauce Worcestershire japonaise (Bull-Dog)",2,"cs"],["Sauce d'huître Lee Kum Kee Premium",2,"cs"],["Sauce soja Kikkoman",1,"cs"],["Sucre",1,"cc"],["Mirin",1,"cs"],["Huile végétale neutre",4,"cs"],["Aonori (algue séchée verte — signature)",2,"cs"],["Katsuobushi (flocons bonite — signature dansante)",4,"cs"],["Beni shoga (gingembre rouge mariné)",4,"cs"],["Mayonnaise japonaise Kewpie (signature)",4,"cs"]],et:"PRÉPARATION DES NOUILLES :\n1. Plonger les nouilles fraîches yakisoba 30 sec dans eau bouillante (juste pour les détacher si elles sont en bloc). Égoutter, refroidir à l'eau froide. Égoutter à fond.\nSAUCE YAKISOBA HOMEMADE (signature Osaka) :\n2. Mélanger : sauce Otafuku + Worcestershire + huître + soja + sucre + mirin. Ce mélange est la \"sauce Osaka\" qui imprègne tout.\nWOK ULTRA-CHAUD (technique \"wok hei\" / teppan-yaki) :\n3. Préchauffer un grand wok ou plancha en fonte à feu MAX (le métal doit fumer légèrement). Verser 2 cs d'huile.\n4. Saisir le porc en lamelles 90 sec — coloration profonde, jamais cuit à fond.\n5. Ajouter chou + carottes + poivron. Sauter 2 min en remuant constamment au mouvement de spatule.\n6. Pousser sur les bords du wok. Au centre, ajouter 1 cs huile + nouilles. Faire griller 90 sec sans toucher (caramélisation = signature \"wok hei\").\n7. Mélanger nouilles + légumes + porc. Ajouter pousses de soja + oignons verts ciselés.\nSAUCE FINALE (la magie) :\n8. Verser la sauce yakisoba sur tout. Sauter énergiquement 90 sec — la sauce caramélise sur les nouilles, créant la couleur brun-doré et le parfum signature.\n9. Goûter, rectifier (plus de sauce si pâle).\nDRESSAGE STYLE STREET-FOOD OSAKA :\n10. Dresser dans assiettes plates plates en pyramide ou directement à la plancha (à la teppanyaki).\n11. Garnir GÉNÉREUSEMENT (essentiel) : zigzag de mayonnaise Kewpie, pluie de aonori, flocons de katsuobushi (qui dansent à la chaleur — spectacle), tas de beni shoga rouge sur le côté.\n12. Servir IMMÉDIATEMENT — yakisoba à la plancha, jamais réchauffé.",vin:"Bière japonaise Sapporo Premium ou saké froid Hakkaisan",notes:"Tradition Osaka (yatai street food) : le yakisoba est l'icône du street food d'Osaka — vendu dans les festivals et yatai (chariots ambulants). La règle : wok ULTRA-CHAUD, sauce Otafuku obligatoire, garnitures généreuses (mayo + aonori + katsuobushi + beni shoga). Le katsuobushi qui danse sur la chaleur est le spectacle final."},
{id:"JP003",co:"Asie",cat:"Plat",sous:"Riz / Japon",nom:"Onigiri Triangle au Saumon Grillé Mentaiko (Recette Tokyo Konbini Style)",chef:"Tradition Tokyo (Onigiri Bongo Otsuka — référence Mecque)",bp:4,prep:35,cui:25,diff:2,qual:5,ig:[["Riz Koshihikari court grain premium",450,"g"],["Eau filtrée",54,"cl"],["Sel marin Kuro Yuki (la magie)",1.5,"cc"],["Filet de saumon norvégien sauvage",250,"g"],["Sauce soja",2,"cs"],["Mirin",2,"cs"],["Sake",1,"cs"],["Sucre",1,"cc"],["Mentaiko (œufs cabillaud épicé — signature Tokyo)",80,"g"],["Mayonnaise Kewpie",2,"cs"],["Feuilles nori grillées (yaki nori) format konbini",8,"feuilles"],["Sésame blanc grillé",2,"cs"],["Shiso vert (option)",4,"feuilles"]],et:"CUISSON RIZ ONIGIRI (technique parfaite) :\n1. Rincer le riz Koshihikari 5 fois jusqu'à eau parfaitement claire.\n2. Tremper 30 min.\n3. Cuire dans 54 cl d'eau (ratio 1.2:1) : couvert, ébullition + 12 min feu doux + 12 min repos hors feu (NE PAS OUVRIR le couvercle).\n4. Transférer dans un grand bol. Salaire le riz (1 cc de sel pour 450 g de riz). Aérer.\n5. Refroidir 10 min — le riz doit être TIÈDE pour le moulage (chaud = brûlure mains, froid = grumeaux).\nGARNITURE SAUMON GRILLÉ (signature konbini) :\n6. Mélanger : soja + mirin + sake + sucre. Mariner le saumon 15 min.\n7. Cuire à la plancha ou poêle 4 min par face jusqu'à doré.\n8. Effeuiller en filaments. Réserver tiède.\nGARNITURE MENTAIKO MAYO (signature Tokyo moderne) :\n9. Mélanger mentaiko (sortis de la peau) + mayonnaise Kewpie + 1 cc sésame.\nFAÇONNAGE TRIANGLE (technique professionnelle) :\n10. Préparer un bol d'eau salée pour humidifier les mains (empêche le riz d'adhérer).\n11. Humidifier les paumes, prendre 100 g de riz tiède dans la main creuse.\n12. Avec le pouce, créer un creux au centre. Y déposer 1 cc de garniture (saumon ou mentaiko).\n13. Refermer le riz autour de la garniture.\n14. Former un triangle équilatéral en pressant délicatement entre les paumes en forme de triangle (mains pressées comme pour la prière, riz au milieu). 5-6 mouvements de pression.\nFINITION (les 8 onigiris) :\n15. Pour 4 onigiris saumon : passer 1 face dans graines de sésame.\n16. Pour 4 onigiris mentaiko : envelopper d'1/2 feuille nori.\n17. La signature konbini : nori séparé du riz par film alimentaire pour rester croustillant — au moment de manger, déballer, le nori adhère.\nSERVICE :\n18. Dresser sur planche en bois ou bento japonais.\n19. Accompagner : tsukemono (légumes lacto-fermentés), thé vert sencha chaud, miso shiru léger.",vin:"Thé vert sencha chaud ou saké junmai chaud (kanzake)",notes:"Tradition Tokyo (Onigiri Bongo Otsuka — référence depuis 1960) : l'onigiri est le snack japonais quotidien — on en consomme 6 milliards/an au Japon. La règle : riz Koshihikari, salaison mains, mentaiko ou saumon. Le sel sur les mains au moulage est la signature (parfume + conserve). Triangle parfait grâce à pression entre paumes en \"prière\"."},
{id:"JP004",co:"Asie",cat:"Entrée",sous:"Soupe miso / Japon",nom:"Miso Shiru Dashi Pure aux Algues Wakamé (Recette Mikuni Kiyomi)",chef:"Mikuni Kiyomi (Hôtel Cargill, autorité miso japonaise)",bp:4,prep:15,cui:8,diff:2,qual:5,ig:[["Algue kombu (Hidaka kombu pour finesse)",10,"g"],["Eau filtrée",90,"cl"],["Bonite séchée katsuobushi (flocons frais)",15,"g"],["Pâte miso blanc shiro miso (sourire — Hatcho miso pour version foncée)",4,"cs"],["Tofu soyeux frais (kinugoshi)",250,"g"],["Algues wakamé séchées (à réhydrater)",6,"g"],["Oignons verts (negi) très fins",3,"tiges"],["Sept épices togarashi (option)",1,"qs"]],et:"DASHI \"ICHIBAN\" (le 1er bouillon — la base sacrée) :\n1. Essuyer le kombu avec un torchon humide (jamais le laver — supprime l'umami). Inciser légèrement le kombu pour libérer les arômes.\n2. Plonger dans 1 L d'eau froide. Reposer 30 min à T° ambiante (extraction lente — meilleurs arômes).\n3. Chauffer DOUCEMENT à feu très bas. À 60-65°C maximum, retirer le kombu (passer 65°C = amertume).\n4. Porter à 85°C. Hors feu, ajouter le katsuobushi en pluie. Reposer 5 min — les flocons coulent.\n5. Filtrer délicatement à travers étamine (passer doucement — le bouillon ne doit pas être trouble).\nRÉHYDRATATION WAKAMÉ :\n6. Plonger les wakamé séchées dans eau froide 5 min — elles triplent de volume. Égoutter, retirer les nervures dures, couper en morceaux.\nMISO TECHNIQUE PROFESSIONNELLE (la règle d'or sacrée) :\n7. Chauffer le dashi à 65°C MAXIMUM (jamais plus — le miso PERDRAIT ses bactéries probiotiques et arômes).\n8. Mettre la pâte miso dans une petite passoire (la \"miso koshi\" japonaise — outil pro). Plonger la passoire dans le dashi tiède et émietter le miso à travers — il se diffuse uniformément sans grumeaux.\n9. Ne JAMAIS bouillir après ajout du miso (règle absolue).\nGARNITURES (la touche finale) :\n10. Couper le tofu soyeux en cubes de 1 cm (avec délicatesse — fragile).\n11. Émincer les oignons verts en TRÈS fines rondelles à 30°.\nDRESSAGE (rituel japonais) :\n12. Dans 4 bols japonais en céramique, déposer : tofu en cubes + wakamé réhydratés.\n13. Verser le miso shiru chaud (jamais brûlant — 65°C max).\n14. Saupoudrer d'oignons verts ciselés en bouquet sur le dessus.\n15. Option : pincée de shichimi togarashi pour le piquant.\nSERVICE :\n16. Servir IMMÉDIATEMENT en accompagnement du repas japonais traditionnel (riz + plat principal + tsukemono). On le boit DIRECTEMENT au bol (sans cuillère — tradition).",vin:"Saké junmai (idéalement chaud kanzake) ou thé vert sencha",notes:"Mikuni Kiyomi (autorité japonaise du miso) : \"Le dashi est la fondation de toute la cuisine japonaise — réussir un grand dashi, c'est réussir tout le reste. Le kombu se retire à 65°C, le miso s'incorpore à 65°C, jamais plus. La passoire à miso (miso koshi) est l'outil pro pour éviter les grumeaux. Le miso shiru ne se réchauffe pas — toujours fait à la dernière minute.\""},
{id:"JP005",co:"Asie",cat:"Plat",sous:"Gyoza / Tokyo",nom:"Gyoza Yakí au Porc et Crevettes, Pâte Maison (Recette Yoshihiro Murata)",chef:"Yoshihiro Murata (★★★ Kikunoi, Kyoto)",bp:4,prep:60,cui:15,diff:4,qual:5,ig:[["Farine T55 forte (gyoza wrappers maison)",250,"g"],["Eau bouillante",13,"cl"],["Sel",0.5,"cc"],["Porc haché 25% MG (épaule)",250,"g"],["Crevettes décortiquées hachées (signature Murata)",100,"g"],["Chou chinois finement haché et essoré",150,"g"],["Ciboule chinoise (nira)",2,"tiges"],["Gingembre frais râpé",2,"cm"],["Ail râpé",2,"gousses"],["Sauce soja Kikkoman",1,"cs"],["Huile sésame",1,"cs"],["Sake",1,"cs"],["Sucre",0.5,"cc"],["Sel, poivre blanc",1,"qs"],["Huile végétale (cuisson)",4,"cs"],["Eau bouillante (vapeur)",10,"cl"],["Vinaigre de riz",2,"cs"],["Sauce soja (trempette)",2,"cs"],["Huile pimentée rāyu",1,"cs"]],et:"PÂTE GYOZA MAISON (la signature professionnelle Murata) :\n1. Mélanger farine + sel. Verser eau BOUILLANTE en filet en mélangeant à la baguette — la chaleur cuit l'amidon, donne la souplesse caractéristique.\n2. Pétrir à la main 10 min — pâte lisse et souple. Filmer, reposer 30 min.\n3. Diviser en 24 boules de 14 g. Sur plan fariné, étaler chaque boule en disque de 9 cm sur 1 mm — TRÈS FIN (signature japonaise vs. les épais chinois).\nFARCE GYOZA (technique Kikunoi) :\n4. Saler le chou haché. Laisser dégorger 10 min, presser entre les paumes pour évacuer toute l'eau (essentiel — sinon farce détrempée).\n5. Mélanger : porc + crevettes + chou essoré + ciboule ciselée + gingembre + ail + soja + huile sésame + sake + sucre + sel + poivre.\n6. Pétrir vigoureusement 3 min dans une seule direction — la farce devient cohésive et collante (signature professionnelle).\nROULAGE TRADITIONNEL (technique 13 plis) :\n7. Déposer 1 cc rase de farce au centre de chaque disque.\n8. Humidifier le bord. Plier en demi-lune.\n9. Faire 13 plis (\"juusan-pleats\") sur le bord supérieur — geste japonais traditionnel qui distingue les vrais gyoza.\n10. Poser sur plaque farinée, base aplatie pour que le gyoza tienne debout.\nCUISSON \"YAKI\" (la signature — fond croustillant, dessus vapeur) :\n11. Préchauffer une grande poêle anti-adhésive avec 3 cs huile à feu moyen-vif.\n12. Disposer 12 gyoza serrés en cercle, base plate vers le bas.\n13. Cuire 2-3 min jusqu'à fond doré profond (vérifier en soulevant un — couleur ambré-or).\n14. VERSER eau bouillante (signature \"yaki\" : crée la vapeur instantanément). COUVRIR IMMÉDIATEMENT avec couvercle.\n15. Cuire 5 min à la vapeur — les gyoza cuisent à fond, la pâte devient translucide.\n16. Découvrir, laisser évaporer le reste d'eau 1 min jusqu'à fond ré-croustillant.\nDRESSAGE PROFESSIONNEL (technique \"hanetsuki gyoza\" — gyoza ailes) :\n17. Cuisson optionnelle pro : ajouter 1 cs farine de riz + 5 cs eau dans la poêle au moment de la vapeur — crée une croûte dorée \"d'ailes\" reliant tous les gyoza (signature Tokyo moderne).\n18. Démouler en retournant la poêle sur grand plat — la base croustillante apparaît au-dessus, splendide.\n19. Servir avec sauce trempette : soja + vinaigre de riz + huile pimentée rāyu.",vin:"Saké junmai daiginjo Hakkaisan ou bière Sapporo Premium",notes:"Yoshihiro Murata (★★★ Kikunoi Kyoto — gardien de la cuisine kaiseki) : \"Les gyoza japonais (yaki) diffèrent des chinois (jiaozi) par leur pâte plus fine, leur farce plus subtile, et leur cuisson 'yaki' qui combine fond croustillant et dessus vapeur. Les 13 plis traditionnels sont la signature culturelle. Et la touche moderne 'hanetsuki' (ailes croustillantes) est l'évolution Tokyo.\""},
{id:"JP006",co:"Asie",cat:"Plat",sous:"Teppanyaki",nom:"Okonomiyaki (Galette Japonaise Salée)",chef:"Tradition d'Osaka",bp:4,prep:20,cui:15,diff:2,qual:4,ig:[["Farine T55",200,"g"],["Dashi",25,"cl"],["Oeufs",4,"pièces"],["Chou blanc haché",400,"g"],["Lardons ou bacon",100,"g"],["Oignons verts",4,"tiges"],["Sauce okonomiyaki ou worcestershire",4,"cs"],["Mayonnaise japonaise Kewpie",4,"cs"],["Katsuobushi (bonite séchée)",2,"cs"],["Aonori (algue poudre)",1,"cs"]],et:"1. Mélanger farine + dashi + oeufs. Incorporer chou haché + oignons verts.\n2. Chauffer huile dans grande poêle. Verser la moitié de la pâte. Poser le bacon dessus.\n3. Cuire à feu moyen 5 min. Retourner. Cuire encore 5 min.\n4. Napper de sauce okonomiyaki. Tracer des zébures de mayonnaise. Parsemer de katsuobushi + aonori.\n5. Servir immédiatement.",vin:"Bière Sapporo froide ou saké junmai",notes:"A Osaka, l'okonomiyaki se mange debout au comptoir. Chacun fait le sien."},
{id:"JP007",co:"Asie",cat:"Dessert",sous:"Wagashi",nom:"Matcha Latte et Dorayaki",chef:"Tradition japonaise",bp:4,prep:20,cui:10,diff:1,qual:4,ig:[["Oeufs",2,"pièces"],["Sucre",60,"g"],["Mirin",1,"cs"],["Farine T55",100,"g"],["Levure chimique",1,"cc"],["Pâte d'anko (haricots rouges sucrés)",200,"g"],["Poudre de matcha",2,"cs"],["Lait chaud",30,"cl"],["Lait végétal",15,"cl"],["Sirop de sucre",1,"cs"]],et:"Dorayaki :\n1. Fouetter oeufs + sucre + mirin. Ajouter farine + levure. Reposer 15 min.\n2. Cuire de petites crêpes épaisses (8cm) dans poêle légèrement huilée 2 min/face.\n3. Sandwicher deux crêpes avec une couche généreuse d'anko.\nMatcha latte :\n4. Tamiser le matcha dans un bol. Ajouter 5cl d'eau bouillante. Fouetter au chasen jusqu'à mousse.\n5. Ajouter le lait chaud mousseux.",vin:"Accompagnement dorayaki",notes:"L'anko (pâte de haricots rouges) se trouve en épicerie asiatique. Les dorayaki sont la friandise préférée de Doraemon."},
{id:"JP008",co:"Asie",cat:"Plat",sous:"Udon",nom:"Udon Kake (Soupe d'Udon Simple)",chef:"Tradition de Kagawa (Sanuki)",bp:4,prep:10,cui:15,diff:1,qual:4,ig:[["Udon frais ou secs",400,"g"],["Dashi",120,"cl"],["Sauce soja Tamari",4,"cs"],["Mirin",3,"cs"],["Oignons verts",3,"tiges"],["Tempura de crevettes (optionnel)",4,"pièces"],["Gingembre râpé",2,"cc"]],et:"1. Cuire les udon selon les instructions. Rincer à l'eau froide. Égoutter.\n2. Bouillon : chauffer dashi + sauce soja + mirin. Ne pas faire bouillir.\n3. Réchauffer les udon dans le bouillon chaud 1 min.\n4. Verser dans des bols profonds avec le bouillon bien chaud.\n5. Garnir d'oignons verts ciselés + gingembre râpé + tempura si désiré.",vin:"Thé vert chaud ou thé mugicha (orge torréfiée)",notes:"Le bouillon dashi de qualité est tout. Udon épais + bouillon doux = réconfort absolu."},
{id:"JP009",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Ramen Tonkotsu",chef:"Tradition de Fukuoka",bp:4,prep:30,cui:240,diff:3,qual:4,ig:[["Os de porc (pieds et carcasse)",2000,"g"],["Tranches de porc chashu",200,"g"],["Ramen frais",400,"g"],["Oeufs mollets marinés (ajitsuke tamago)",4,"pièces"],["Bambou mariné (menma)",60,"g"],["Oignons verts",4,"tiges"],["Nori",4,"feuilles"],["Gingembre",3,"cm"],["Ail",6,"gousses"],["Sauce soja mirin sel",1,"qs"]],et:"Bouillon :\n1. Blanchir les os 10 min. Rincer soigneusement.\n2. Cuire dans 3L eau à ébullition vive (pas douce !) 4h en ajoutant de l'eau si nécessaire. Le bouillon doit devenir blanc et opaque.\n3. Filtrer, assaisonner avec sel + sauce soja.\nService :\n4. Cuire les ramen frais 2 min dans l'eau bouillante. Égoutter.\n5. Dans chaque bol : ramen + bouillon bouillant. Garnir de chashu + oeuf mollet coupé en deux + menma + oignons verts + nori.",vin:"Bière Asahi froide ou thé oolong",notes:"Le bouillon tonkotsu devient blanc grâce à l'ébullition forte qui émulsifie le collagène des os."},
{id:"JP010",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Karaage (Poulet Frit Japonais)",chef:"Tradition japonaise izakaya",bp:4,prep:30,cui:15,diff:2,qual:4,ig:[["Cuisses de poulet désossées",800,"g"],["Sauce soja",4,"cs"],["Mirin",2,"cs"],["Sake",2,"cs"],["Gingembre râpé",2,"cc"],["Ail râpé",2,"gousses"],["Fécule de pomme de terre",80,"g"],["Huile pour frire",1,"L"],["Citron vert",2,"pièces"],["Mayonnaise japonaise",4,"cs"]],et:"1. Couper le poulet en morceaux de 3cm. Mariner dans soja + mirin + sake + gingembre + ail 20-30 min.\n2. Bien égoutter la marinade. Enrober chaque morceau de fécule de pomme de terre (pas de farine).\n3. Frire à 160°C 3-4 min. Égoutter. Monter à 180°C, refrire 1 min pour rendre croustillant.\n4. Servir immédiatement avec quartiers de citron vert + mayonnaise kewpie.",vin:"Bière japonaise très froide",notes:"La double friture (sengiri) est le secret du karaage croustillant. La fécule de pomme de terre donne une texture unique."},
{id:"JP011",co:"Asie",cat:"Dessert",sous:"Crème",nom:"Purin (Flan Japonais)",chef:"Tradition japonaise moderne",bp:6,prep:20,cui:30,diff:2,qual:4,ig:[["Lait entier",50,"cl"],["Oeufs",3,"pièces"],["Jaunes d'oeufs",2,"pièces"],["Sucre",80,"g"],["Extrait de vanille",1,"cc"],["Sucre pour caramel",80,"g"],["Eau chaude",2,"cs"]],et:"1. Caramel ambré à sec. Déglacer avec eau chaude (attention projections). Verser dans 6 ramequins.\n2. Chauffer lait avec vanille sans bouillir.\n3. Fouetter oeufs + jaunes + sucre sans faire mousser. Verser lait chaud en filet en mélangeant.\n4. Filtrer l'appareil. Verser dans les ramequins.\n5. Bain-marie au four 150°C 25-30 min. Réfrigérer 4h. Démouler : le caramel coule sur le dessus.",vin:"Thé matcha glacé",notes:"Plus dense et soyeux que la crème caramel française grâce aux jaunes supplémentaires."},
{id:"JP012",co:"Asie",cat:"Plat",sous:"Noodles",nom:"Tsukemen (Ramen à Tremper)",chef:"Tradition tokyoïte",bp:4,prep:20,cui:30,diff:2,qual:4,ig:[["Ramen épais",400,"g"],["Bouillon de porc concentré",80,"cl"],["Sauce tsuyu (dashi soja mirin)",8,"cs"],["Poitrine de porc chashu",200,"g"],["Oeufs mollets",4,"pièces"],["Oignons verts",3,"tiges"],["Nori en triangles",4,"feuilles"],["Menma bambou",50,"g"]],et:"1. Préparer le bouillon de trempage : réduire bouillon + tsuyu jusqu'à très concentré et savoureux.\n2. Cuire les ramen épais 3-4 min. Rincer à l'eau froide pour les rendre fermes et brillants. Disposer sur assiette.\n3. Servir le bouillon de trempage chaud dans un bol séparé.\n4. Garnir les pâtes froides : chashu + oeuf + menma + oignons verts + nori.\n5. Tremper les pâtes dans le bouillon avant chaque bouchée.",vin:"Bière Sapporo ou thé vert glacé",notes:"Dans le tsukemen les pâtes et le bouillon sont servis séparément. On trempe les pâtes froides dans le bouillon chaud concentré."},
{id:"JP013",co:"Asie",cat:"Plat",sous:"Pâtes",nom:"Udon au Curry Japonais",chef:"Tradition japonaise",bp:4,prep:15,cui:20,diff:2,qual:4,ig:[["Udon frais",500,"g"],["Boeuf en fines tranches",200,"g"],["Cubes de curry japonais",100,"g"],["Oignons",1,"pièce"],["Poireau japonais (negi)",1,"pièce"],["Bouillon dashi",80,"cl"],["Sauce soja",2,"cs"],["Mirin",2,"cs"],["Oeufs",4,"pièces"]],et:"1. Préparer le bouillon : dashi + soja + mirin. Porter à frémissement.\n2. Suer oignons. Ajouter boeuf. Dorer rapidement.\n3. Incorporer les cubes de curry. Remuer jusqu'à dissous.\n4. Verser le bouillon. Cuire 10 min.\n5. Cuire les udon 3 min. Servir dans bols avec sauce + negi + oeuf cru par-dessus.",vin:"Thé vert ou bière Asahi",notes:"Le curry japonais est plus doux et plus sucré que le curry indien. Les cubes S&B ou Vermont donnent la saveur authentique."},
{id:"JP014",co:"Asie",cat:"Plat",sous:"Riz",nom:"Oyakodon (Poulet et Oeuf sur Riz)",chef:"Tradition japonaise",bp:4,prep:10,cui:15,diff:2,qual:5,ig:[["Riz japonais cuit",600,"g"],["Cuisses de poulet désossées",400,"g"],["Oeufs",6,"pièces"],["Oignons",2,"pièces"],["Dashi",25,"cl"],["Sauce soja",4,"cs"],["Mirin",3,"cs"],["Sucre",1,"cs"],["Oignons verts",3,"tiges"]],et:"1. Couper poulet en cubes. Émincer oignons finement.\n2. Dans poêle large : dashi + soja + mirin + sucre. Ajouter oignons. Frémir 3 min.\n3. Ajouter poulet. Cuire 6-7 min.\n4. Battre les oeufs légèrement sans homogénéiser complètement.\n5. Verser oeufs en spirale sur le poulet. Couvrir 1 min. Hors feu 1 min. Servir sur riz avec oignons verts.",vin:"Saké froid ou thé hojicha",notes:"Oyakodon = parents (poulet) et enfants (oeufs). Les oeufs doivent rester légèrement coulants."},
{id:"JP015",co:"Asie",cat:"Plat",sous:"Poisson",nom:"Saba no Misoni (Maquereau au Miso)",chef:"Tradition japonaise",bp:4,prep:10,cui:20,diff:2,qual:4,ig:[["Filets de maquereau",800,"g"],["Miso rouge",4,"cs"],["Sauce soja",2,"cs"],["Mirin",3,"cs"],["Saké de cuisine",3,"cs"],["Sucre",2,"cs"],["Gingembre frais",30,"g"],["Eau",15,"cl"]],et:"1. Ébouillanter rapidement les filets pour enlever l'odeur.\n2. Dans sauteuse : eau + saké + mirin + sucre + gingembre en julienne. Porter à frémissement.\n3. Ajouter les filets côté peau vers le haut. Cuire 8-10 min en arrosant.\n4. Délayer miso + soja avec un peu de bouillon. Verser dans la sauteuse.\n5. Cuire encore 5 min jusqu'à sauce épaisse et brillante.",vin:"Saké chaud ou thé genmaicha",notes:"L'ébouillantage initial (shimofuri) est essentiel pour enlever l'odeur du maquereau."},
{id:"JP016",co:"Asie",cat:"Entrée",sous:"Soupe",nom:"Soupe Miso aux Champignons",chef:"Tradition japonaise quotidienne",bp:4,prep:5,cui:10,diff:1,qual:4,ig:[["Dashi",80,"cl"],["Miso blanc",4,"cs"],["Shiitake frais",100,"g"],["Tofu soyeux",200,"g"],["Wakame séché",1,"cs"],["Oignons verts",2,"tiges"]],et:"1. Réhydrater wakame dans eau froide 5 min. Égoutter.\n2. Porter dashi à frémissement. Ajouter shiitake tranchés. Cuire 5 min.\n3. Ajouter tofu en cubes + wakame.\n4. Baisser le feu au minimum. Délayer miso dans un peu de bouillon. Verser dans la soupe.\n5. Ne jamais bouillir après le miso. Oignons verts. Servir immédiatement.",vin:"Thé vert sencha",notes:"Ne jamais faire bouillir la soupe miso après ajout de la pâte — les enzymes bénéfiques sont détruites."},
{id:"JP017",co:"Asie",cat:"Plat",sous:"Porc",nom:"Tonkatsu (Escalope de Porc Panée)",chef:"Tradition japonaise",bp:4,prep:15,cui:10,diff:2,qual:5,ig:[["Escalopes de porc épaisses",800,"g"],["Farine",60,"g"],["Oeufs battus",2,"pièces"],["Chapelure panko",200,"g"],["Huile pour friture",1,"L"],["Sauce tonkatsu",8,"cs"],["Chou blanc",300,"g"],["Riz japonais cuit",600,"g"]],et:"1. Attendrir les escalopes au marteau. Saler, poivrer.\n2. Fariner, tremper dans oeuf battu, enrober de panko en pressant fermement.\n3. Frire dans l'huile à 170°C 4-5 min par face jusqu'à dorées.\n4. Égoutter sur grille. Couper en lanières.\n5. Servir avec chou cru finement émincé + riz + sauce tonkatsu.",vin:"Bière Sapporo ou saké sec",notes:"Le panko (chapelure japonaise) donne une croûte beaucoup plus croustillante que la chapelure européenne."},
{id:"JP018",co:"Asie",cat:"Plat",sous:"Riz",nom:"Chicken Katsudon",chef:"Tradition japonaise",bp:4,prep:15,cui:15,diff:2,qual:4,ig:[["Escalopes de poulet panées",4,"pièces"],["Riz japonais cuit",600,"g"],["Oeufs",4,"pièces"],["Oignons",2,"pièces"],["Dashi",30,"cl"],["Sauce soja",4,"cs"],["Mirin",3,"cs"],["Sucre",1,"cs"],["Oignons verts",2,"tiges"]],et:"1. Préparer les escalopes de poulet panées (tonkatsu de poulet). Couper en tranches.\n2. Bouillon : dashi + soja + mirin + sucre. Ajouter oignons. Frémir 3 min.\n3. Poser les tranches de tonkatsu dans le bouillon.\n4. Battre les oeufs légèrement. Verser en spirale sur le tonkatsu. Couvrir 1 min.\n5. Faire glisser sur le riz. Oignons verts.",vin:"Saké froid ou thé genmaicha",notes:"Le katsudon est le comfort food ultime au Japon — plat des étudiants avant les examens (katsu = vaincre)."},
{id:"JP019",co:"Asie",cat:"Accompagnement",sous:"Légumes",nom:"Kinpira Gobo (Bardane Sautée)",chef:"Tradition japonaise",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Racine de bardane (gobo)",300,"g"],["Carottes",2,"pièces"],["Huile de sésame",2,"cs"],["Sauce soja",3,"cs"],["Mirin",2,"cs"],["Sucre",1,"cs"],["Piment rouge séché",1,"pièce"],["Graines de sésame",1,"cs"]],et:"1. Peler le gobo. Couper en julienne fine. Tremper dans eau vinaigrée 10 min.\n2. Couper les carottes en julienne identique.\n3. Chauffer l'huile de sésame. Sauter gobo + carottes + piment 3-4 min.\n4. Ajouter soja + mirin + sucre. Cuire jusqu'à absorption (6-7 min).\n5. Graines de sésame. Se consomme chaud ou froid.",vin:"Accompagnement des bentos japonais",notes:"La bardane (gobo) est le légume racine fondamental de la cuisine japonaise — croquante et terreuse."},
{id:"JP020",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Matcha Tiramisu",chef:"Tradition fusion japonaise-italienne",bp:8,prep:30,cui:0,diff:2,qual:4,ig:[["Biscuits Savoiardi",200,"g"],["Mascarpone",500,"g"],["Jaunes d'oeufs",4,"pièces"],["Sucre",120,"g"],["Crème fouettée",20,"cl"],["Matcha en poudre",3,"cs"],["Eau chaude",15,"cl"],["Sucre pour sirop",2,"cs"]],et:"1. Sirop matcha : dissoudre 2cs matcha + sucre dans eau chaude. Refroidir.\n2. Fouetter jaunes + sucre au bain-marie jusqu'à ruban. Refroidir.\n3. Incorporer mascarpone. Ajouter crème fouettée délicatement.\n4. Tremper rapidement les biscuits dans sirop matcha. Alterner biscuits + crème.\n5. Saupoudrer généreusement de matcha. Réfrigérer 6h minimum.",vin:"Thé hojicha ou café japonais",notes:"Le matcha de qualité culinaire convient parfaitement. Choisir un matcha vert vif, pas brun."},
{id:"JP021",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Gyudon Amélioré (Boeuf Mijoté sur Riz)",chef:"Tradition japonaise",bp:4,prep:10,cui:15,diff:1,qual:4,ig:[["Boeuf en tranches très fines",500,"g"],["Riz japonais cuit",600,"g"],["Oignons",2,"pièces"],["Dashi",25,"cl"],["Sauce soja",5,"cs"],["Mirin",4,"cs"],["Saké",2,"cs"],["Sucre",2,"cs"],["Gingembre mariné (beni shoga)",4,"cs"]],et:"1. Émincer finement les oignons.\n2. Dans casserole large : dashi + soja + mirin + saké + sucre. Porter à frémissement.\n3. Ajouter oignons. Cuire 5 min jusqu'à tendres.\n4. Ajouter les tranches de boeuf. Cuire 5-7 min à frémissement.\n5. Servir sur riz chaud avec bouillon + gingembre mariné rouge.",vin:"Bière Kirin ou thé houjicha",notes:"La clé du gyudon est le boeuf coupé très finement (2mm) — le demander chez le boucher asiatique."},
{id:"JP022",co:"Asie",cat:"Entrée",sous:"Oeufs",nom:"Tamagoyaki (Omelette Roulée Japonaise)",chef:"Tradition japonaise classique",bp:4,prep:10,cui:10,diff:3,qual:5,ig:[["Oeufs",6,"pièces"],["Dashi",3,"cs"],["Sauce soja",1,"cc"],["Mirin",1,"cs"],["Sucre",1,"cc"],["Sel",1,"pincée"],["Huile végétale",1,"cs"]],et:"1. Battre les oeufs avec dashi + soja + mirin + sucre + sel sans trop incorporer d'air.\n2. Huiler une poêle rectangulaire. Chauffer à feu moyen.\n3. Verser une fine couche d'oeuf. Quand commence à prendre, rouler vers soi.\n4. Pousser le rouleau au bout. Huiler. Verser nouvelle couche en soulevant le rouleau. Rouler par-dessus.\n5. Répéter jusqu'à épuisement. Refroidir. Trancher en portions.",vin:"Thé vert ou saké sec",notes:"Le tamagoyaki parfait montre de fines couches en tranche. La poêle rectangulaire fait une grande différence."},
{id:"JP023",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Nabeyaki Udon (Nouilles en Pot)",chef:"Tradition japonaise d'hiver",bp:2,prep:15,cui:15,diff:2,qual:4,ig:[["Udon frais",400,"g"],["Bouillon dashi",80,"cl"],["Sauce soja",3,"cs"],["Mirin",2,"cs"],["Crevette tempura",2,"pièces"],["Kamaboko",4,"tranches"],["Champignons shiitake",4,"pièces"],["Épinards",50,"g"],["Oeufs",2,"pièces"],["Oignons verts",2,"tiges"]],et:"1. Porter dashi + soja + mirin à frémissement dans des pots en terre individuels.\n2. Ajouter udon + shiitake. Cuire 3 min.\n3. Ajouter épinards + kamaboko + tempura.\n4. Casser un oeuf dans chaque pot.\n5. Couvrir 2 min jusqu'à blanc pris, jaune coulant. Oignons verts.",vin:"Saké chaud ou thé vert",notes:"Nabe = pot. Le nabeyaki se cuit et se sert dans le même pot individuel — très convivial."},
{id:"JP024",co:"Asie",cat:"Sauce / Base",sous:"Condiment",nom:"Ponzu (Sauce Soja-Agrumes)",chef:"Tradition japonaise",bp:6,prep:5,cui:0,diff:1,qual:5,ig:[["Sauce soja",15,"cl"],["Jus de yuzu ou citron",8,"cl"],["Vinaigre de riz",3,"cs"],["Mirin",2,"cs"],["Dashi",3,"cs"],["Kombu",5,"g"],["Katsuobushi",5,"g"]],et:"1. Mélanger tous les ingrédients dans un bocal.\n2. Ajouter kombu + katsuobushi.\n3. Laisser infuser au froid 24h minimum.\n4. Filtrer finement.\n5. Se conserve 3 mois au réfrigérateur.",vin:"Usage : sashimis, grillades, shabu-shabu, légumes",notes:"Doit infuser 24h minimum. Le yuzu est le parfum authentique mais le citron convient."},
{id:"JP025",co:"Asie",cat:"Plat",sous:"Porc",nom:"Buta no Shogayaki (Porc au Gingembre)",chef:"Tradition japonaise quotidienne",bp:4,prep:10,cui:10,diff:1,qual:4,ig:[["Porc en fines tranches",600,"g"],["Gingembre frais râpé",40,"g"],["Sauce soja",4,"cs"],["Mirin",3,"cs"],["Saké",2,"cs"],["Sucre",1,"cs"],["Huile végétale",2,"cs"],["Chou blanc émincé",300,"g"]],et:"1. Marinade : gingembre râpé + soja + mirin + saké + sucre. Mariner le porc 15 min.\n2. Émincer le chou en chiffonnade très fine. Réserver au froid.\n3. Chauffer l'huile à feu vif. Cuire le porc sans la marinade 2-3 min.\n4. Verser la marinade. Réduire jusqu'à sauce caramélisée (3-4 min).\n5. Servir sur lit de chou cru avec riz blanc.",vin:"Bière japonaise ou saké froid",notes:"Le chou cru absorbe la sauce et complète parfaitement le porc."},
{id:"JP026",co:"Asie",cat:"Dessert",sous:"Gâteau",nom:"Japanese Cheesecake Soufflé",chef:"Tradition japonaise moderne",bp:8,prep:30,cui:70,diff:3,qual:4,ig:[["Cream cheese",250,"g"],["Beurre",50,"g"],["Lait entier",10,"cl"],["Jaunes d'oeufs",6,"pièces"],["Blancs d'oeufs",6,"pièces"],["Sucre",130,"g"],["Farine",60,"g"],["Maïzena",20,"g"],["Jus de citron",1,"cs"]],et:"1. Bain-marie : fondre cream cheese + beurre + lait jusqu'à lisse. Tiédir.\n2. Incorporer jaunes + citron + farine + maïzena tamisées.\n3. Monter blancs en neige avec sucre progressivement. Pics souples.\n4. Incorporer délicatement en 3 fois.\n5. Moule 20cm chemisé. Bain-marie au four 160°C 70 min. Refroidir au four éteint 1h.",vin:"Thé matcha ou café japonais",notes:"Le bain-marie est indispensable — il garantit la texture moelleuse et évite les craquelures."},
{id:"JP027",co:"Asie",cat:"Entrée",sous:"Salade",nom:"Sunomono (Concombre au Vinaigre)",chef:"Tradition japonaise",bp:4,prep:15,cui:0,diff:1,qual:4,ig:[["Concombres japonais",3,"pièces"],["Wakame séché",10,"g"],["Vinaigre de riz",6,"cs"],["Sucre",2,"cs"],["Sauce soja",1,"cs"],["Sel",1,"cc"],["Graines de sésame grillées",1,"cs"]],et:"1. Trancher finement les concombres à la mandoline. Saler 15 min pour dégorger.\n2. Réhydrater wakame 5 min. Égoutter.\n3. Presser les concombres pour éliminer l'eau.\n4. Mélanger vinaigre + sucre + soja jusqu'à sucre dissous.\n5. Mélanger concombres + wakame + sauce. Graines de sésame. Réfrigérer 30 min.",vin:"Saké froid ou thé vert",notes:"Presser soigneusement les concombres — l'eau résiduelle diluerait la sauce."},
{id:"JP028",co:"Asie",cat:"Plat",sous:"Volaille",nom:"Teriyaki de Poulet Glacé",chef:"Tradition japonaise",bp:4,prep:5,cui:15,diff:1,qual:5,ig:[["Cuisses de poulet désossées",800,"g"],["Sauce soja",6,"cs"],["Mirin",4,"cs"],["Saké",3,"cs"],["Sucre",2,"cs"],["Gingembre frais",20,"g"],["Ail",2,"gousses"],["Graines de sésame",1,"cs"]],et:"1. Sauce teriyaki : soja + mirin + saké + sucre + gingembre + ail. Réduire 5 min jusqu'à sirupeux.\n2. Saisir cuisses côté peau dans poêle froide sans huile 6-7 min à feu moyen.\n3. Retourner. Cuire 4 min. Évacuer la graisse.\n4. Verser sauce teriyaki. Laisser glacer 2-3 min en arrosant.\n5. Trancher. Graines de sésame.",vin:"Bière japonaise ou saké froid",notes:"Démarrer côté peau dans poêle froide fait fondre la graisse lentement pour une peau parfaitement croustillante."},
{id:"JP029",co:"Asie",cat:"Assaisonnement",sous:"Fond",nom:"Dashi Maison (Bouillon de Base Japonais)",chef:"Tradition japonaise fondamentale",bp:4,prep:5,cui:15,diff:1,qual:5,ig:[["Kombu séché",20,"g"],["Katsuobushi (copeaux de bonite)",20,"g"],["Eau filtrée",1,"L"]],et:"1. Tremper le kombu dans l'eau froide 30 min — jamais dans de l'eau tiède.\n2. Porter doucement à frémissement. Juste avant ébullition, retirer le kombu.\n3. Porter à ébullition franche 10 secondes.\n4. Hors feu : ajouter katsuobushi. Laisser infuser 5 min exactement.\n5. Filtrer délicatement sans presser.",vin:"Base de toute la cuisine japonaise",notes:"Ne jamais bouillir le kombu — il deviendrait amer. Le katsuobushi doit juste infuser, pas cuire."},
{id:"KR001",co:"Asie",cat:"Plat",sous:"Bibimbap / Corée",nom:"Bibimbap Dolsot (Bol en Pierre Brûlante) Coréen Authentique",chef:"Tradition Jeonju (Corée du Sud — capitale culinaire)",bp:4,prep:45,cui:25,diff:3,qual:5,ig:[["Riz court japonica",350,"g"],["Bœuf bulgogi (entrecôte tranchée fine 5 mm)",250,"g"],["Sauce soja Kikkoman",3,"cs"],["Sucre brun",1,"cs"],["Huile sésame grillé",4,"cc"],["Ail râpé",3,"gousses"],["Épinards frais",200,"g"],["Carottes en julienne",2,"pièces"],["Courgette en julienne",1,"pièce"],["Champignons shiitake frais",6,"pièces"],["Pousses de soja",150,"g"],["Œufs frais (jaunes coulants)",4,"pièces"],["Pâte de piment gochujang",4,"cs"],["Vinaigre de riz",1,"cs"],["Sirop de riz mool yeot",1,"cc"],["Nori grillé",2,"feuilles"],["Graines de sésame grillées",2,"cs"],["Huile végétale",4,"cs"]],et:"RIZ TRADITIONNEL (technique Jeonju) :\n1. Rincer le riz 4-5 fois jusqu'à eau claire. Tremper 30 min.\n2. Cuire dans 42 cl d'eau, couvert, ébullition puis 15 min feu doux + 10 min repos hors feu.\nMARINADE BULGOGI (signature) :\n3. Mélanger soja + sucre + 2 cc huile sésame + ail + 1/4 cc poivre. Mariner le bœuf 30 min.\nLÉGUMES NAMUL (technique coréenne — chaque légume séparément) :\n4. ÉPINARDS : blanchir 30 sec, refroidir glace, presser, assaisonner avec 1 cc huile sésame + sel + ail + sésame.\n5. CAROTTES : sauter à feu vif 2 min dans 1 cs huile, sel.\n6. COURGETTE : sauter 3 min à feu vif, sel.\n7. SHIITAKE : tranchés, sautés 4 min dans 1 cs huile + soja + sucre.\n8. POUSSES DE SOJA : blanchir 90 sec, refroidir, assaisonner sésame + sel + ail.\nVIANDE BULGOGI :\n9. Sauter le bœuf mariné dans wok brûlant 3 min — caramélisation marquée.\nSAUCE GOCHUJANG :\n10. Mélanger gochujang + 1 cc huile sésame + sucre + vinaigre de riz + sirop yeot + 1 cc graines sésame.\nDOLSOT (la magie du bol en pierre brûlante) :\n11. Préchauffer 4 bols en pierre dolsot ou cocottes en fonte au four 250°C 15 min — ils doivent être brûlants.\n12. Huiler généreusement le fond (huile sésame). Tasser le riz au fond.\n13. Disposer en quartiers colorés en éventail : épinards, carottes, courgette, shiitake, pousses de soja, bulgogi.\n14. Casser un œuf cru au centre — il cuit dans la chaleur résiduelle.\n15. Ajouter 1 cs gochujang sur le côté (le convive dose).\n16. Servir IMMÉDIATEMENT — le riz au fond crépite et forme une croûte croustillante (\"nurungji\" — la couche dorée signature dolsot).\n17. À table, mélanger énergiquement TOUS les composants ensemble — c'est le rituel sacré du bibimbap. Manger immédiatement.",vin:"Soju coréen ou bière Hite",notes:"Tradition Jeonju (capitale culinaire de Corée) : le bibimbap dolsot diffère du bibimbap classique par le bol brûlant qui crée la nurungji (croûte dorée). Chaque légume est cuit séparément (technique namul) — c'est ce qui donne la palette de saveurs distinctes. Mélanger énergiquement avant de manger."},
{id:"KR002",co:"Asie",cat:"Plat",sous:"Bulgogi / Corée",nom:"Bulgogi de Bœuf Marbré à la Poire Asiatique (Recette Hooni Kim — Danji NYC)",chef:"Hooni Kim (★ Danji, NYC — premier chef coréen étoilé US)",bp:4,prep:30,cui:8,diff:2,qual:5,ig:[["Bœuf entrecôte ou faux-filet (tranché 3 mm — au congélateur 30 min facilite)",600,"g"],["Poire asiatique (la magie tendreté)",1,"pièce"],["Sauce soja Kikkoman premium",6,"cs"],["Sucre brun Muscovado",2,"cs"],["Huile sésame grillé Sang Chun",2,"cs"],["Ail râpé",6,"gousses"],["Gingembre frais râpé",3,"cm"],["Oignons verts ciselés",4,"tiges"],["Sake (mirin alternative)",2,"cs"],["Poivre noir Sarawak",1,"cc"],["Graines de sésame grillées",2,"cs"],["Feuilles de laitue Boston (pour wraps)",16,"feuilles"],["Sauce ssamjang (gochujang + doenjang)",4,"cs"],["Riz blanc cuit",400,"g"],["Kimchi",200,"g"]],et:"MARINADE SIGNATURE HOONI KIM (la poire = secret) :\n1. Râper finement la poire asiatique avec son jus — l'enzyme tendrise la viande mieux que n'importe quel autre attendrisseur naturel.\n2. Mélanger : poire râpée + sauce soja + sucre brun + huile sésame + ail + gingembre + sake + poivre + 2 oignons verts ciselés.\n3. Verser sur le bœuf tranché fin. Masser 2 min — pénétration profonde. Mariner au frais 4 H minimum, idéalement 12 H.\nCUISSON INSTANTANÉE (technique Danji) :\n4. Préchauffer une plancha en fonte ou un grill très chaud à feu max — la viande doit grésiller dès contact (test : goutte d'eau s'évapore en 1 sec).\n5. Saisir le bœuf mariné PAR PETITES QUANTITÉS (4-5 tranches max) 60-90 secondes par face — caramélisation profonde sans surcuisson.\n6. Réserver dans plat chaud, continuer jusqu'à épuisement.\nSAUCE SSAMJANG (l'accompagnement coréen sacré) :\n7. Mélanger gochujang + doenjang (pâte soja fermenté) + 1 cs huile sésame + 1 cc sucre + 1 cc graines sésame + 1 oignon vert ciselé.\nSERVICE TRADITIONNEL \"SSAMBAP\" (rituel des wraps) :\n8. Disposer sur grand plat communautaire : viande bulgogi chaude au centre, feuilles de laitue Boston empilées, riz blanc, kimchi, ssamjang, oignons verts, graines de sésame.\n9. Chaque convive prend une feuille de laitue, dépose 1 cs riz + 2 tranches bulgogi + 1 cc ssamjang + kimchi + sésame, plie en wrap, mange à la main d'une bouchée (\"ssam\" = wrap coréen).\n10. Boire soju glacé ou bière Hite entre les bouchées — tradition coréenne.",vin:"Soju traditionnel Chamisul ou bière Cass coréenne",notes:"Hooni Kim (★ Danji NYC — premier chef coréen étoilé aux États-Unis) : \"La poire asiatique (Pyrus pyrifolia) est le SECRET du bulgogi authentique — son enzyme protéolytique tendrise la viande sans la rendre molle. Jamais d'ananas (trop agressif) ni d'attendrisseur chimique. La règle d'or : mariner 12 h, cuire à feu MAX, manger en wrap. C'est le BBQ coréen sublimé.\""},
{id:"KR003",co:"Asie",cat:"Entrée",sous:"Kimchi",nom:"Kimchi de Chou Fermenté",chef:"Tradition coréenne",bp:8,prep:60,cui:0,diff:2,qual:4,ig:[["Chou napa (chou chinois)",2000,"g"],["Gros sel",100,"g"],["Piment rouge coréen gochugaru",6,"cs"],["Oignons verts",6,"tiges"],["Ail",8,"gousses"],["Gingembre",3,"cm"],["Radis blanc en julienne",200,"g"],["Sauce de poisson ou soja",3,"cs"],["Sucre",1,"cc"]],et:"1. Couper le chou en quartiers. Saupoudrer généreusement de sel entre les feuilles. Laisser dégorger 2h. Rincer, essorer.\n2. Pâte kimchi : mixer ail + gingembre + gochugaru + sauce de poisson + sucre.\n3. Mélanger chou + radis + oignons verts avec la pâte kimchi (protéger les mains avec des gants).\n4. Tasser dans des bocaux hermétiques. Laisser fermenter 24-48h à T° ambiante.\n5. Réfrigérer. Le kimchi est bon après 48h et continue à se développer pendant des semaines.",vin:"Makgeolli ou bière coréenne froide",notes:"Le kimchi fermenté se conserve des mois au frigo. Jeune (fresh), il est croquant. Vieux, il est acide et parfait pour les ragoûts."},
{id:"KR004",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Doenjang Jjigae (Soupe de Pâte de Soja Coréenne)",chef:"Tradition coréenne",bp:4,prep:10,cui:20,diff:1,qual:4,ig:[["Doenjang (pâte de soja fermenté)",4,"cs"],["Tofu ferme",250,"g"],["Courgettes",1,"pièce"],["Champignons",100,"g"],["Pommes de terre",1,"pièce"],["Oignons verts",3,"tiges"],["Ail",3,"gousses"],["Bouillon anchois-kombu",80,"cl"],["Piment coréen gochugaru",1,"cc"]],et:"1. Préparer le bouillon anchois-kombu : kombu + anchois séchés dans l'eau froide 30 min. Porter à frémissement 10 min. Filtrer.\n2. Porter le bouillon à ébullition. Dissoudre le doenjang dans le bouillon.\n3. Ajouter pommes de terre en cubes. Cuire 8 min.\n4. Ajouter courgettes + champignons + tofu + ail + gochugaru. Frémir 8 min.\n5. Parsemer d'oignons verts. Servir avec riz blanc.",vin:"Thé d'orge coréen (boricha) ou eau",notes:"Le doenjang est à la Corée ce que le miso est au Japon. Chaque famille a sa propre recette."},
{id:"KR005",co:"Asie",cat:"Plat",sous:"Porc",nom:"Bossam (Porc Bouilli aux Feuilles de Chou)",chef:"Tradition coréenne",bp:6,prep:20,cui:90,diff:2,qual:4,ig:[["Poitrine de porc entière",1200,"g"],["Ail",8,"gousses"],["Gingembre",3,"cm"],["Oignons verts",4,"tiges"],["Feuilles de chou napa",1,"pièce"],["Doenjang (pâte de soja)",2,"cs"],["Gochujang",2,"cs"],["Ail haché pour sauce",4,"gousses"],["Huile de sésame",1,"cs"],["Sésame grillé kimchi",1,"qs"]],et:"1. Cuire la poitrine de porc entière dans l'eau avec ail + gingembre + oignons verts + pâte de soja 1h30.\n2. Retirer, laisser tiédir 15 min. Trancher finement.\n3. Sauce bossam : mélanger gochujang + ail haché + huile sésame + sésame.\n4. Servir à table : feuilles de chou napa entières + tranches de porc tiède + sauce.\n5. Chaque convive fait ses petits rouleaux en enveloppant le porc + sauce dans la feuille de chou.",vin:"Makgeolli (bière de riz coréenne) ou soju",notes:"Le bossam est le plat convivial des familles coréennes. La cuisson dans la pâte de soja ôte le goût fort du porc."},
{id:"KR006",co:"Asie",cat:"Dessert",sous:"Crêpe",nom:"Jeon (Crêpes Salées Coréennes aux Légumes)",chef:"Tradition coréenne",bp:4,prep:20,cui:20,diff:1,qual:4,ig:[["Farine de riz",150,"g"],["Farine T55",50,"g"],["Eau froide",25,"cl"],["Oeuf",1,"pièce"],["Oignons verts",6,"tiges"],["Poivrons rouge et vert",1,"pièce"],["Crevettes ou poulpe",100,"g"],["Sauce soja",3,"cs"],["Vinaigre de riz",1,"cs"],["Huile de sésame",1,"cs"]],et:"1. Mélanger les farines + eau froide + oeuf + sel jusqu'à pâte lisse.\n2. Couper légumes en julienne fine. Les incorporer dans la pâte avec les fruits de mer.\n3. Chauffer généreusement de l'huile dans poêle. Verser une louche de pâte garnie.\n4. Cuire à feu moyen-fort 3-4 min jusqu'à bords croustillants et fond bien doré. Retourner.\n5. Sauce trempette : soja + vinaigre + huile sésame + piment. Servir les jeon chauds coupés en carrés.",vin:"Makgeolli ou bière OB coréenne",notes:"Les pajeon (crêpes aux oignons verts) et les haemul pajeon (aux fruits de mer) sont les plus populaires. Très croustillantes grâce à la farine de riz."},
{id:"KR007",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Budae Jjigae (Soupe de l'Armée)",chef:"Tradition coréenne post-guerre",bp:4,prep:15,cui:20,diff:1,qual:4,ig:[["Kimchi",200,"g"],["Spam ou jambon en dés",150,"g"],["Saucisses cocktail",100,"g"],["Tofu ferme",150,"g"],["Ramen instantané",1,"paquets"],["Gochujang",2,"cs"],["Doenjang",1,"cs"],["Oignons verts",3,"tiges"],["Champignons",100,"g"],["Bouillon anchois",80,"cl"]],et:"1. Dans une grande poêle ou casserole : disposer tous les ingrédients en sections distinctes.\n2. Ajouter le bouillon d'anchois chaud.\n3. Ajouter gochujang + doenjang + ail + gingembre.\n4. Porter à frémissement. Cuire 10 min à feu moyen.\n5. Ajouter les ramen et les noodles de l'assaisonnement. Cuire 3 min. Parsemer oignons verts.",vin:"Bière Hite ou soju coréen très froid",notes:"Le budae jjigae (soupe de l'armée américaine) est né après la guerre de Corée avec les surplus américains (Spam, saucisses). Devenu un classique populaire."},
{id:"KR008",co:"Asie",cat:"Plat",sous:"BBQ",nom:"Galbi (Côtes de Boeuf Marinées Coréennes)",chef:"Tradition coréenne",bp:4,prep:20,cui:15,diff:2,qual:5,ig:[["Travers de boeuf fins",1200,"g"],["Sauce soja",10,"cs"],["Sucre roux",3,"cs"],["Miel",2,"cs"],["Huile de sésame",2,"cs"],["Ail haché",8,"gousses"],["Gingembre râpé",30,"g"],["Oignons verts",4,"tiges"],["Poire Nashi",1,"pièce"],["Graines de sésame",2,"cs"]],et:"1. Inciser les côtes. Tremper dans eau froide 1h pour enlever le sang.\n2. Mixer la poire. Mélanger avec soja + sucre + miel + sésame + ail + gingembre.\n3. Mariner les côtes 4h minimum, idéalement 12h.\n4. Griller sur braise vive 4-5 min par face.\n5. Oignons verts + graines de sésame. Servir avec laitue + riz.",vin:"Soju coréen ou bière OB",notes:"La poire coréenne (nashi) est l'attendrisseur naturel — ne jamais la remplacer par du kiwi."},
{id:"KR009",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Dak Bulgogi (Poulet Mariné Coréen)",chef:"Tradition coréenne",bp:4,prep:15,cui:15,diff:1,qual:4,ig:[["Cuisses de poulet désossées",800,"g"],["Gochujang",2,"cs"],["Sauce soja",4,"cs"],["Sucre roux",2,"cs"],["Huile de sésame",2,"cs"],["Ail gingembre",1,"qs"],["Oignons",1,"pièce"],["Oignons verts",3,"tiges"],["Graines de sésame",1,"cs"]],et:"1. Couper poulet en lanières. Mariner 2h avec gochujang + soja + sucre + sésame + ail + gingembre.\n2. Chauffer huile à vif. Ajouter oignons émincés. Dorer 2 min.\n3. Ajouter le poulet avec sa marinade. Sauter à feu vif 8-10 min.\n4. Oignons verts à la fin.\n5. Servir avec riz blanc + laitue + kimchi.",vin:"Soju ou bière Hite",notes:"Le gochujang (pâte de piment fermentée) est l'âme de la cuisine coréenne — irremplaçable."},
{id:"KR010",co:"Asie",cat:"Plat",sous:"Riz",nom:"Bibimbap Dolsot (Riz Mélangé en Pierre Chaude)",chef:"Tradition coréenne",bp:4,prep:30,cui:20,diff:2,qual:5,ig:[["Riz à sushi cuit",600,"g"],["Boeuf haché",200,"g"],["Épinards blanchis",150,"g"],["Carottes",2,"pièces"],["Courgette",1,"pièce"],["Shiitake",100,"g"],["Pousses de soja",150,"g"],["Gochujang",3,"cs"],["Sauce soja",2,"cs"],["Huile de sésame",2,"cs"],["Oeufs",4,"pièces"],["Ail graines de sésame",1,"qs"]],et:"1. Préparer chaque légume séparément sauté à l'ail + huile sésame.\n2. Faire revenir boeuf haché avec soja + sésame + gingembre.\n3. Chauffer bols en pierre (dolsot). Huiler le fond.\n4. Verser riz. Disposer légumes + boeuf en secteurs radiaux.\n5. Casser un oeuf cru au centre. Mélanger à table avec gochujang — le riz en bas devient croustillant (nurungji).",vin:"Makgeolli ou soju",notes:"Le bol dolsot chaud forme une croûte de riz croustillante au fond — le meilleur du plat."},
{id:"KR011",co:"Asie",cat:"Accompagnement",sous:"Kimchi",nom:"Kimchi de Chou Napa Traditionnel",chef:"Tradition coréenne millénaire",bp:10,prep:45,cui:0,diff:2,qual:5,ig:[["Chou chinois napa",2000,"g"],["Gros sel marin",200,"g"],["Eau",1,"L"],["Gochugaru (piment coréen en flocons)",6,"cs"],["Ail",1,"tête"],["Gingembre",50,"g"],["Sauce de poisson",3,"cs"],["Sucre",1,"cs"],["Farine de riz gluant",2,"cs"],["Eau pour colle de riz",20,"cl"],["Radis coréen",200,"g"],["Oignons verts",1,"bouquet"]],et:"1. Couper chou en quartiers. Saumure : eau + sel. Immerger 3h en retournant. Rincer 3 fois.\n2. Colle de riz : cuire farine gluante dans eau en fouettant. Refroidir.\n3. Pâte : colle + gochugaru + ail + gingembre mixés + sauce poisson + sucre.\n4. Radis + oignons verts en julienne mélangés à la pâte.\n5. Enduire chaque feuille de chou. Tasser dans bocal. Fermenter 2 jours à T° ambiante puis au froid.",vin:"Condiment essentiel de tous les repas coréens",notes:"Le gochugaru (piment coréen doux et fumé) est irremplaçable. Se bonifie avec le temps."},
{id:"KR012",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Soondubu Jjigae (Ragoût de Tofu Soyeux)",chef:"Tradition coréenne",bp:4,prep:10,cui:15,diff:2,qual:4,ig:[["Tofu très soyeux",500,"g"],["Palourdes",200,"g"],["Porc haché",100,"g"],["Kimchi",150,"g"],["Gochugaru",2,"cs"],["Doenjang",1,"cs"],["Bouillon d'anchois ou dashi",60,"cl"],["Ail",3,"gousses"],["Oeufs",2,"pièces"],["Oignons verts",2,"tiges"],["Huile de sésame",1,"cs"]],et:"1. Dorer porc haché. Ajouter ail + gochugaru. Cuire 2 min.\n2. Ajouter kimchi haché. Cuire 3 min.\n3. Verser bouillon. Ajouter doenjang. Porter à frémissement.\n4. Ajouter palourdes. Cuire 3 min jusqu'à ouverture.\n5. Incorporer tofu délicatement. Casser oeufs dessus. Couvrir 2 min. Oignons verts + sésame.",vin:"Soju ou bière coréenne",notes:"Servir bouillant dans le pot en terre (ttukbaegi). L'oeuf continue de cuire à table."},
{id:"KR013",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Bulgogi Classique",chef:"Tradition coréenne royale",bp:4,prep:20,cui:10,diff:1,qual:5,ig:[["Boeuf faux-filet en fines tranches",600,"g"],["Sauce soja",6,"cs"],["Sucre roux",3,"cs"],["Huile de sésame",2,"cs"],["Ail",6,"gousses"],["Poire Nashi râpée",1,"pièce"],["Oignon râpé",1,"pièce"],["Oignons verts",3,"tiges"],["Gingembre",20,"g"],["Graines de sésame",2,"cs"]],et:"1. Couper le boeuf en fines tranches (congeler 30 min facilite).\n2. Marinade : soja + sucre + sésame + ail + poire râpée + oignon + gingembre.\n3. Mariner 2h minimum.\n4. Poêle ou plancha à très vif. Saisir boeuf en une couche 2 min de chaque côté.\n5. Servir avec riz + kimchi + feuilles de laitue pour envelopper.",vin:"Soju ou vin coréen",notes:"Bulgogi = viande de feu. La poire Nashi râpée est l'attendrisseur naturel sans modifier le goût."},
{id:"KR014",co:"Asie",cat:"Entrée",sous:"Crêpe",nom:"Pajeon (Crêpe aux Oignons Verts)",chef:"Tradition coréenne",bp:4,prep:15,cui:15,diff:1,qual:4,ig:[["Farine T55",150,"g"],["Farine de riz",50,"g"],["Eau très froide",30,"cl"],["Oeuf",1,"pièce"],["Oignons verts",12,"tiges"],["Fruits de mer mélangés",300,"g"],["Huile végétale",6,"cs"],["Sauce soja vinaigre sésame gochugaru",1,"qs"]],et:"1. Couper oignons verts en tronçons de 7cm.\n2. Pâte : farines + eau très froide + oeuf + sel. Ne pas trop mélanger.\n3. Chauffer huile abondante. Disposer oignons verts en grille. Verser la pâte.\n4. Ajouter fruits de mer. Cuire 4-5 min jusqu'à fond doré et croustillant.\n5. Retourner. Cuire 3 min. Servir avec sauce soja + vinaigre + sésame + gochugaru.",vin:"Makgeolli (bière de riz coréenne)",notes:"La tradition veut qu'on mange le pajeon les jours de pluie. La pâte très froide garantit le croustillant."},
{id:"KR015",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Kimchi Jjigae (Ragoût de Kimchi)",chef:"Tradition coréenne du quotidien",bp:4,prep:10,cui:30,diff:1,qual:4,ig:[["Kimchi mûr",400,"g"],["Poitrine de porc en lamelles",300,"g"],["Tofu ferme",200,"g"],["Oignons",1,"pièce"],["Gochugaru",1,"cs"],["Doenjang",1,"cs"],["Ail",3,"gousses"],["Sucre",1,"cc"],["Bouillon d'anchois",60,"cl"],["Huile de sésame",1,"cs"],["Oignons verts",2,"tiges"]],et:"1. Dorer porc jusqu'à bien coloré. Évacuer l'excès de graisse.\n2. Ajouter kimchi avec son jus + oignons. Cuire 5 min.\n3. Ajouter gochugaru + doenjang + ail + sucre. Cuire 3 min.\n4. Mouiller bouillon. Frémir 15 min.\n5. Ajouter tofu en cubes. Cuire 5 min. Huile sésame + oignons verts.",vin:"Soju coréen glacé",notes:"Utiliser un kimchi bien fermenté (1 mois minimum) — plus il est mûr, meilleur le jjigae."},
{id:"KR016",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Bingsu aux Fruits Rouges",chef:"Tradition coréenne d'été",bp:4,prep:15,cui:0,diff:1,qual:4,ig:[["Glace pilée très fine",1500,"g"],["Lait concentré sucré",30,"cl"],["Fraises",300,"g"],["Framboises",150,"g"],["Lait condensé pour napper",4,"cs"],["Azuki sucrés cuits",200,"g"],["Mochi",6,"pièces"]],et:"1. Piler la glace en neige très fine.\n2. Dans chaque bol glacé : fond de glace pilée. Verser lait concentré sucré.\n3. Ajouter une autre couche de glace pilée.\n4. Disposer fruits rouges + azuki + mochi.\n5. Napper de lait condensé. Servir immédiatement.",vin:"Dessert rafraîchissant de canicule coréenne",notes:"Le bingsu est le dessert national d'été en Corée. Les variantes sont infinies : matcha, mangue, chocolat."},
{id:"KR017",co:"Asie",cat:"Plat",sous:"Nouilles",nom:"Naengmyeon (Nouilles Froides Coréennes)",chef:"Tradition de Pyongyang",bp:4,prep:15,cui:10,diff:2,qual:4,ig:[["Nouilles de sarrasin",400,"g"],["Bouillon de boeuf très froid",80,"cl"],["Vinaigre de riz",4,"cs"],["Sucre",2,"cs"],["Moutarde coréenne",1,"cs"],["Oeufs durs",2,"pièces"],["Concombre",1,"pièce"],["Poire Nashi",1,"pièce"],["Kimchi radis",150,"g"],["Graines de sésame",1,"cs"]],et:"1. Cuire nouilles de sarrasin. Rincer énergiquement à l'eau glacée.\n2. Bouillon : bouillon froid + vinaigre + sucre + moutarde. Ajouter des glaçons.\n3. Émincer finement concombre et poire en julienne.\n4. Disposer nouilles dans bols glacés. Verser bouillon glacé.\n5. Garnir de concombre + poire + demi-oeuf dur + kimchi + graines de sésame.",vin:"Bière coréenne très froide",notes:"Le bouillon doit être presque congelé. La poire Nashi apporte une douceur rafraîchissante."},
{id:"KR018",co:"Asie",cat:"Accompagnement",sous:"Banchan",nom:"Sigeumchi Namul (Épinards au Sésame)",chef:"Tradition coréenne",bp:4,prep:10,cui:3,diff:1,qual:4,ig:[["Épinards frais",500,"g"],["Ail",2,"gousses"],["Huile de sésame",2,"cs"],["Sauce soja",1,"cs"],["Graines de sésame grillées",2,"cs"],["Sel",1,"pincée"]],et:"1. Blanchir les épinards 30 secondes dans eau bouillante salée. Eau glacée immédiatement.\n2. Presser soigneusement pour enlever toute l'eau.\n3. Couper grossièrement.\n4. Mélanger avec ail écrasé + huile sésame + soja + sel.\n5. Parsemer de graines de sésame. Servir à T° ambiante.",vin:"Accompagnement classique des repas coréens",notes:"Les namul sont les légumes assaisonnés (banchan) servis avec tous les repas coréens."},
{id:"KR019",co:"Asie",cat:"Entrée",sous:"Rouleau",nom:"Kimbap (Rouleaux de Riz Coréens)",chef:"Tradition coréenne",bp:4,prep:30,cui:10,diff:2,qual:4,ig:[["Riz à sushi cuit",600,"g"],["Huile de sésame",2,"cs"],["Sel",1,"cc"],["Feuilles de nori",6,"pièces"],["Épinards blanchis",100,"g"],["Carottes julienne sautées",100,"g"],["Omelette en bandes",3,"oeufs"],["Jambon ou crabe kamaboko",150,"g"],["Concombre julienne",1,"pièce"],["Takuan (radis jaune mariné)",100,"g"]],et:"1. Assaisonner riz tiède avec huile de sésame + sel (pas de vinaigre — différence avec les sushis).\n2. Préparer toutes les garnitures en bandes.\n3. Poser nori sur natte. Étaler fine couche de riz aux 3/4.\n4. Disposer les garnitures en ligne au centre.\n5. Rouler serré avec la natte. Trancher en rondelles de 1.5cm.",vin:"Thé vert coréen ou soda au miel",notes:"Contrairement aux sushis japonais, le kimbap utilise huile de sésame au lieu de vinaigre — sa signature."},
{id:"MY001",co:"Asie",cat:"Plat",sous:"Riz",nom:"Nasi Lemak (Riz au Lait de Coco)",chef:"Tradition malaise nationale",bp:4,prep:20,cui:30,diff:2,qual:5,ig:[["Riz long",300,"g"],["Lait de coco",30,"cl"],["Feuilles de pandan",3,"pièces"],["Sel",1,"cc"],["Oeufs durs",4,"pièces"],["Anchois frits (ikan bilis)",80,"g"],["Cacahuètes grillées",60,"g"],["Concombre",1,"pièce"],["Sambal belacan",6,"cs"]],et:"1. Rincer le riz. Verser lait de coco + même volume d'eau + sel + feuilles pandan froissées.\n2. Cuire à feu doux 20 min couvert. Le riz absorbe tout.\n3. Frire les anchois séchés dans l'huile jusqu'à croustillants. Égoutter.\n4. Sambal belacan : pâte de piment + pâte de crevettes (belacan) frite.\n5. Servir le riz emmailloté de feuille de bananier avec oeuf dur + anchois + cacahuètes + concombre + sambal.",vin:"Thé glacé à la pandan ou café kopi malais",notes:"Le nasi lemak est le plat national malaisien, servi au petit-déjeuner. Les feuilles de pandan parfument le riz de manière unique."},
{id:"MY002",co:"Asie",cat:"Plat",sous:"Nouilles",nom:"Char Kway Teow (Nouilles Plates Sautées)",chef:"Tradition sino-malaise de Penang",bp:4,prep:15,cui:10,diff:2,qual:5,ig:[["Nouilles de riz plates (kway teow)",400,"g"],["Crevettes",200,"g"],["Palourdes",150,"g"],["Oeufs",3,"pièces"],["Pousses de soja",150,"g"],["Ciboulette chinoise",50,"g"],["Kecap manis",3,"cs"],["Sauce soja claire",2,"cs"],["Sauce d'huîtres",2,"cs"],["Ail",4,"gousses"],["Piment",2,"pièces"],["Lard (char siu)",80,"g"],["Huile",4,"cs"]],et:"1. Séparer les nouilles. Tout préparer avant de commencer — cuisson ultra-rapide.\n2. Huile fumante dans wok. Ail + piment 30 sec. Ajouter lard.\n3. Crevettes + palourdes 1 min. Pousser sur les bords.\n4. Oeufs au centre. Brouiller à moitié. Ajouter nouilles + sauces.\n5. Sauter à feu maximum 2 min. Pousses de soja + ciboulette. Sauter 30 sec.",vin:"Bière Tiger ou thé glacé",notes:"Le wok hei (souffle du wok) est l'essence du char kway teow — feu maximum obligatoire. Travailler en petites portions."},
{id:"MY003",co:"Asie",cat:"Plat",sous:"Curry",nom:"Curry Laksa (Soupe Curry aux Nouilles)",chef:"Tradition Peranakan de Malaisie",bp:4,prep:20,cui:25,diff:2,qual:5,ig:[["Nouilles de riz ou d'oeufs",400,"g"],["Lait de coco",60,"cl"],["Bouillon de crevettes",60,"cl"],["Pâte laksa",5,"cs"],["Crevettes",200,"g"],["Tofu frit",150,"g"],["Pousses de soja",150,"g"],["Palourdes",200,"g"],["Oeufs durs",4,"pièces"],["Feuilles de coriandre",1,"bouquet"],["Sambal",1,"qs"]],et:"1. Frire la pâte laksa dans l'huile 3 min.\n2. Ajouter lait de coco + bouillon. Porter à frémissement. Cuire 10 min.\n3. Ajouter palourdes. Cuire 3 min. Ajouter crevettes. Cuire 2 min.\n4. Cuire les nouilles. Égoutter.\n5. Bols : nouilles + pousses de soja + tofu + crevettes + palourdes + oeuf. Verser bouillon chaud. Coriandre + sambal.",vin:"Thé glacé ou bière Carlsberg Malaisie",notes:"La pâte laksa maison est complexe — les préparations en pot comme Prima Taste sont respectables pour la version rapide."},
{id:"MY004",co:"Asie",cat:"Plat",sous:"Boeuf",nom:"Beef Rendang Malaisien",chef:"Tradition malaise-Minangkabau",bp:6,prep:30,cui:150,diff:2,qual:5,ig:[["Boeuf à braiser",1000,"g"],["Lait de coco",80,"cl"],["Noix de coco râpée toastée (kerisik)",80,"g"],["Citronnelle",4,"tiges"],["Galanga",40,"g"],["Feuilles de turmeric",3,"pièces"],["Piment rouge",6,"pièces"],["Échalotes",8,"pièces"],["Ail",6,"gousses"],["Curcuma gingembre",1,"qs"],["Tamarinde",2,"cs"]],et:"1. Mixer piments + échalotes + ail + galanga + curcuma + gingembre en pâte.\n2. Torréfier noix de coco râpée à sec jusqu'à brun doré (kerisik). Moudre en pâte.\n3. Faire revenir pâte d'épices 8 min. Ajouter boeuf. Dorer.\n4. Ajouter lait de coco + citronnelle + feuilles. Mijoter 2h.\n5. Ajouter kerisik + tamarin. Cuire encore 30 min jusqu'à sauce presque sèche.",vin:"Thé tarik malaisien",notes:"Le kerisik (noix de coco râpée frite et broyée) est la différence entre le rendang malaisien et indonésien — plus sec et noix."},
{id:"MY005",co:"Asie",cat:"Entrée",sous:"Salade",nom:"Rojak (Salade de Fruits et Légumes à la Sauce Noire)",chef:"Tradition Penang et Singapour",bp:4,prep:20,cui:5,diff:1,qual:4,ig:[["Ananas frais",200,"g"],["Mangue verte",1,"pièce"],["Concombre",1,"pièce"],["Pousses de soja blanchies",150,"g"],["Tofu frit croustillant",150,"g"],["Craquettes de crevettes",60,"g"],["Sauce de crevettes noire (hae kor)",3,"cs"],["Sucre de palme",2,"cs"],["Piment haché",1,"pièce"],["Jus de citron vert",2,"cs"],["Cacahuètes grillées",60,"g"]],et:"1. Couper ananas + mangue + concombre en morceaux de 2cm.\n2. Sauce : hae kor + sucre palme + piment + lime. Chauffer légèrement jusqu'à sucre dissous.\n3. Cuire légèrement en remuant jusqu'à sauce caramel épaisse. Refroidir.\n4. Mélanger fruits + légumes + tofu + pousses de soja avec la sauce.\n5. Parsemer cacahuètes + craquettes de crevettes.",vin:"Thé glacé ou eau de coco",notes:"La sauce hae kor (pâte de crevettes noire sucrée) est ce qui distingue le rojak de toutes les autres salades."},
{id:"MY006",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Ayam Percik (Poulet Laqué à la Coco)",chef:"Tradition du Kelantan - Malaisie",bp:4,prep:20,cui:45,diff:2,qual:4,ig:[["Poulet découpé",1500,"g"],["Lait de coco",50,"cl"],["Citronnelle",3,"tiges"],["Galanga",30,"g"],["Piment rouge",4,"pièces"],["Échalotes",6,"pièces"],["Curcuma",1,"cc"],["Coriandre cumin",1,"qs"],["Sel sucre",1,"qs"]],et:"1. Mixer piments + échalotes + galanga + curcuma + épices en pâte.\n2. Faire revenir la pâte 5 min. Ajouter lait de coco + sel + sucre + citronnelle.\n3. Badigeonner généreusement le poulet de cette sauce. Mariner 2h.\n4. Griller sur braise ou plancha 15 min en badigeonnant régulièrement avec la sauce.\n5. Finir au four 180°C 15 min pour cuire à coeur.",vin:"Thé tarik ou eau de coco fraîche",notes:"Le badigeonnage répété crée une laque épaisse sur le poulet. La sauce au lait de coco caramélise magnifiquement."},
{id:"MY007",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Cendol (Dessert Glacé Malaisien)",chef:"Tradition malaisienne",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Farine de riz gluant",100,"g"],["Farine de haricots verts",20,"g"],["Extrait de pandan",2,"cs"],["Sucre de palme (gula melaka)",150,"g"],["Eau",10,"cl"],["Lait de coco",40,"cl"],["Sel",1,"pincée"],["Glace pilée",1,"qs"],["Haricots rouges sucrés",200,"g"]],et:"1. Cendol : mélanger farines + pandan + 20cl eau. Cuire en remuant jusqu'à pâte épaisse. Passer à travers presse à cendol (ou passoire à gros trous) directement dans eau glacée.\n2. Sirop de palme : cuire gula melaka + 5cl eau jusqu'à fondu. Filtrer. Refroidir.\n3. Lait de coco : chauffer avec sel. Refroidir.\n4. Grands bols : glace pilée en montagne.\n5. Déposer cendol (vermicelles verts) + haricots + sirop de palme + lait de coco.",vin:"Dessert-boisson malaisien incomparable",notes:"Le gula melaka (sucre de palme de Malaisie) est plus foncé et plus parfumé que le sucre de coco — ne pas substituer."},
{id:"MY008",co:"Asie",cat:"Plat",sous:"Porc",nom:"Bak Kut Teh (Soupe d'Os de Porc aux Herbes)",chef:"Tradition sino-malaisienne",bp:4,prep:10,cui:90,diff:1,qual:4,ig:[["Côtes de porc",1000,"g"],["Ail",2,"têtes"],["Sauce soja claire",4,"cs"],["Sauce soja noire",2,"cs"],["Poivre blanc",1,"cs"],["Cinq-épices",1,"cc"],["Cannelle bâton",1,"pièce"],["Clous de girofle étoile de badiane",1,"qs"],["Sel sucre",1,"qs"],["Riz blanc ail frit herbes",1,"qs"]],et:"1. Blanchir les côtes 5 min. Rincer.\n2. Dans grande casserole : côtes + têtes d'ail entières + épices entières + soja + 2L eau.\n3. Porter à ébullition. Réduire. Frémir 1h30 à couvert.\n4. Rectifier sel + sucre + poivre blanc.\n5. Servir dans pots de terre avec riz blanc + ail frit + sauce soja + piment.",vin:"Thé de Chine ou café kopi malais",notes:"Le bak kut teh (os de porc au thé) est le petit-déjeuner des travailleurs sino-malaisiens. Le poivre blanc abondant est sa signature."},
{id:"MY009",co:"Asie",cat:"Accompagnement",sous:"Légumes",nom:"Kangkung Belacan (Cresson d'Eau Sauté)",chef:"Tradition malaisienne",bp:4,prep:5,cui:5,diff:1,qual:4,ig:[["Kangkung (cresson d'eau)",600,"g"],["Ail",4,"gousses"],["Piment rouge",2,"pièces"],["Pâte de crevettes (belacan)",1,"cc"],["Sauce d'huîtres",2,"cs"],["Sauce soja",1,"cs"],["Huile",3,"cs"]],et:"1. Laver et couper le kangkung.\n2. Chauffer huile à très vif.\n3. Faire revenir belacan + ail + piment 30 sec jusqu'à très parfumé.\n4. Ajouter kangkung. Sauter à feu maximum 1-2 min.\n5. Sauce d'huîtres + soja. Sauter 30 sec.",vin:"Accompagnement de tous les repas malaisiens",notes:"Le kangkung (cresson d'eau) est le légume de base malaisien. La cuisson ultra-rapide préserve la couleur verte et le croquant."},
{id:"MY010",co:"Asie",cat:"Sauce / Base",sous:"Pâte",nom:"Rempah (Pâte d'Épices de Base Malaisienne)",chef:"Tradition malaisienne",bp:6,prep:20,cui:10,diff:1,qual:4,ig:[["Échalotes",10,"pièces"],["Ail",6,"gousses"],["Citronnelle",3,"tiges"],["Galanga",30,"g"],["Curcuma frais",20,"g"],["Piments rouges",4,"pièces"],["Gingembre",20,"g"],["Pâte de crevettes (belacan)",1,"cc"],["Huile",4,"cs"]],et:"1. Mixer tous les ingrédients sauf l'huile jusqu'à pâte grossière.\n2. Chauffer l'huile dans wok. Faire revenir la pâte à feu moyen.\n3. Remuer constamment 8-10 min jusqu'à la pâte sèche, parfumée, et l'huile remonte à la surface.\n4. Ce stade s'appelle pecah minyak (l'huile se sépare) — la pâte est prête.\n5. Utiliser immédiatement ou conserver 2 semaines au froid.",vin:"Base de curries, rendang, laksa, gulai malaisiens",notes:"Pecah minyak (l'huile se sépare) est le signe que la pâte est cuite. Avant ce stade, les arômes crus sont encore présents."},
{id:"PH001",co:"Asie",cat:"Plat",sous:"Porc",nom:"Adobo de Porc et Poulet Philippin",chef:"Tradition philippine nationale",bp:4,prep:10,cui:45,diff:1,qual:5,ig:[["Porc en cubes",400,"g"],["Poulet découpé",600,"g"],["Vinaigre blanc",15,"cl"],["Sauce soja",8,"cs"],["Ail",8,"gousses"],["Feuilles de laurier",4,"pièces"],["Poivre noir en grains",1,"cc"],["Huile",2,"cs"],["Sel",1,"qs"]],et:"1. Mariner viandes dans vinaigre + soja + ail + laurier + poivre 1h.\n2. Mettre le tout (marinade incluse) dans casserole. Porter à ébullition.\n3. Réduire et mijoter 30 min couvert jusqu'à viandes cuites.\n4. Retirer les viandes. Réduire la sauce jusqu'à presque sirupeuse.\n5. Dorer les viandes dans l'huile jusqu'à caramélisées. Verser la sauce réduite.",vin:"Bière San Miguel très froide",notes:"L'adobo philippin n'est pas une poudre de curry — c'est un mode de cuisson au vinaigre et soja. L'acidité du vinaigre préservait la viande avant réfrigération."},
{id:"PH002",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Sinigang na Baboy (Soupe Aigre au Porc)",chef:"Tradition philippine",bp:4,prep:15,cui:45,diff:1,qual:4,ig:[["Travers de porc",800,"g"],["Tamarin frais ou en pâte",150,"g"],["Eau",200,"cl"],["Tomates",3,"pièces"],["Oignons",1,"pièce"],["Radis daikon",1,"pièce"],["Haricots verts",150,"g"],["Épinards kangkung",200,"g"],["Aubergines longues",2,"pièces"],["Nuoc-mâm",3,"cs"]],et:"1. Blanchir le porc 5 min. Rincer. Dans grande casserole avec eau fraîche.\n2. Ajouter tomates + oignons + pâte de tamarin. Porter à frémissement. Cuire 30 min.\n3. Ajouter daikon + aubergines. Cuire 8 min.\n4. Ajouter haricots verts + épinards. Cuire 3 min.\n5. Assaisonner nuoc-mâm + sel. L'acidité doit être prononcée.",vin:"Bière San Miguel ou eau fraîche",notes:"L'acidité du sinigang est sa signature — l'agent acidifiant varie (tamarin, goyave verte, citron). Le tamarin est le plus classique."},
{id:"PH003",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Chicken Inasal (Poulet Grillé de Bacolod)",chef:"Tradition de Bacolod - Visayas",bp:4,prep:20,cui:25,diff:1,qual:4,ig:[["Cuisses de poulet",1200,"g"],["Vinaigre de coco",8,"cs"],["Jus de citron vert",4,"cs"],["Ail",6,"gousses"],["Gingembre",30,"g"],["Citronnelle",3,"tiges"],["Annato (atsuete) en poudre",1,"cs"],["Sel sucre",1,"qs"],["Huile d'annato",4,"cs"]],et:"1. Marinade : vinaigre + lime + ail + gingembre + citronnelle + annato + sel + sucre. Mariner poulet 4h.\n2. Huile d'annato : chauffer huile + graines d'annato jusqu'à rouge vif. Filtrer.\n3. Griller sur braise à feu moyen 20-25 min en retournant souvent.\n4. Badigeonner régulièrement d'huile d'annato pendant la cuisson.\n5. La peau doit être rouge-orange brillante et légèrement caramélisée.",vin:"Bière San Miguel ou coconut water",notes:"L'annato (achuète) donne la couleur rouge-orange caractéristique sans piquant. Le vinaigre de coco est l'acidité philippine traditionnelle."},
{id:"PH004",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Halo Halo (Dessert Glacé Philippin)",chef:"Tradition philippine",bp:4,prep:20,cui:0,diff:1,qual:4,ig:[["Glace pilée",1500,"g"],["Lait concentré sucré",8,"cs"],["Haricots rouges sucrés",100,"g"],["Haricots blancs sucrés",100,"g"],["Ube (taro violet) en crème",4,"cs"],["Jackfruit en boîte",100,"g"],["Perles de sagou",100,"g"],["Gelée de coco (nata de coco)",100,"g"],["Crème glacée ube ou vanille",4,"boules"]],et:"1. Cuire et sucrer séparément les haricots. Refroidir.\n2. Cuire le sagou jusqu'à translucide. Rincer. Refroidir.\n3. Dans grands verres hauts : disposer haricots + jackfruit + sagou + nata de coco.\n4. Couvrir entièrement de glace pilée.\n5. Verser lait concentré sucré. Déposer une belle couche de crème ube + boule de glace sur le dessus.",vin:"Dessert et rafraîchissement tropical philippin",notes:"Halo halo signifie mélange-mélange. Il faut mélanger vigoureusement avant de manger — toutes les textures se combinent."},
{id:"PH005",co:"Asie",cat:"Plat",sous:"Légumes",nom:"Pinakbet (Ragoût de Légumes à la Pâte de Crevettes)",chef:"Tradition Ilocano - Luzon",bp:4,prep:20,cui:25,diff:1,qual:4,ig:[["Aubergines longues",3,"pièces"],["Gombos (okra)",150,"g"],["Haricots longs",200,"g"],["Citrouille kabocha",300,"g"],["Piments longs",3,"pièces"],["Porc rôti ou chicharron",200,"g"],["Bagoo ou pâte de crevettes",3,"cs"],["Ail oignons gingembre",1,"qs"],["Tomates",2,"pièces"]],et:"1. Faire revenir ail + oignons + gingembre dans l'huile.\n2. Ajouter tomates + bagoo (pâte de crevettes fermentée). Cuire 5 min.\n3. Ajouter citrouille + haricots. Cuire 8 min couverts.\n4. Ajouter aubergines + gombos + piments.\n5. Couvrir et cuire 10 min. Ajouter chicharron à la fin. NE PAS MÉLANGER — la tradition veut qu'on ne remue pas.",vin:"Bière San Miguel",notes:"La règle d'or du pinakbet : ne pas mélanger une fois les légumes ajoutés — ils cuisent dans la vapeur sans se briser."},
{id:"PH006",co:"Asie",cat:"Plat",sous:"Poisson",nom:"Kinilaw na Isda (Ceviche Philippin au Vinaigre de Coco)",chef:"Tradition philippine",bp:4,prep:20,cui:0,diff:1,qual:5,ig:[["Poisson très frais (thon, mahi-mahi)",500,"g"],["Vinaigre de coco",20,"cl"],["Jus de citron vert",4,"cs"],["Gingembre frais râpé",30,"g"],["Oignons rouges",1,"pièce"],["Piment rouge oiseau",2,"pièces"],["Lait de coco",5,"cs"],["Coriandre",1,"bouquet"],["Sel",1,"cc"]],et:"1. Couper le poisson en cubes de 1.5cm. Le poisson doit être impeccablement frais.\n2. Mariner dans vinaigre de coco + jus lime + sel 15 min — le vinaigre cuit le poisson chimiquement.\n3. Égoutter l'excès de vinaigre.\n4. Ajouter gingembre + oignons + piments + lait de coco. Mélanger.\n5. Servir immédiatement. Coriandre.",vin:"Bière San Miguel ou tubo (jus de canne à sucre)",notes:"Le kinilaw est l'ancêtre du ceviche péruvien. Le vinaigre de coco est moins acide que le vinaigre ordinaire — goût plus doux et fruité."},
{id:"PH007",co:"Asie",cat:"Entrée",sous:"Bouillon",nom:"Bulalo (Soupe d'Os de Boeuf Philippine)",chef:"Tradition de la province de Batangas",bp:4,prep:10,cui:180,diff:1,qual:4,ig:[["Jarret de boeuf avec os à moelle",1500,"g"],["Maïs en épis",2,"pièces"],["Chou",400,"g"],["Bok choy",200,"g"],["Oignons",2,"pièces"],["Poivre en grains",1,"cs"],["Nuoc-mâm",3,"cs"],["Sel",1,"qs"]],et:"1. Blanchir les jarrets 5 min. Rincer soigneusement.\n2. Dans grande casserole : jarrets + oignons + poivre + 3L eau. Cuire 2h30 à frémissement jusqu'à viande fondante.\n3. Ajouter maïs en tronçons. Cuire 20 min.\n4. Ajouter chou + bok choy. Cuire 5 min.\n5. Assaisonner nuoc-mâm + sel. Servir dans un grand bol avec la moelle dans l'os.",vin:"Bière San Miguel ou thé de jasmin",notes:"La moelle dans l'os se mange à la cuillère — le sel enhances son onctuosité. C'est le plat des dimanches philippins."},
{id:"PK001",co:"Asie",cat:"Plat",sous:"Viande",nom:"Nihari (Ragoût de Boeuf du Matin)",chef:"Tradition de Lahore et Delhi",bp:6,prep:20,cui:300,diff:2,qual:5,ig:[["Jarret de boeuf",1500,"g"],["Oignons frits",150,"g"],["Ail gingembre pâte",3,"cs"],["Garam nihari (épices spéciales)",3,"cs"],["Coriandre moulue",2,"cc"],["Curcuma",1,"cc"],["Ghee",5,"cs"],["Farine de blé",3,"cs"],["Jus de citron",2,"cs"],["Gingembre julienne coriandre oignons verts",1,"qs"]],et:"1. Faire revenir oignons frits + ail-gingembre dans ghee.\n2. Ajouter toutes les épices. Cuire 3 min.\n3. Ajouter le jarret + eau à hauteur. Porter à ébullition. Cuire 4-5h à feu très doux.\n4. Délayer farine dans un peu d'eau. Incorporer pour épaissir.\n5. Cuire encore 30 min. Servir avec julienne de gingembre + coriandre + oignons verts + citron.",vin:"Thé au lait (doodh patti) ou lassi",notes:"Le nihari est traditionnellement le petit-déjeuner des navabs de Delhi après la prière du matin. La cuisson de 5h est non négociable."},
{id:"PK002",co:"Asie",cat:"Plat",sous:"Viande",nom:"Chapli Kebab (Galettes de Viande du Pendjab)",chef:"Tradition de Peshawar",bp:4,prep:20,cui:15,diff:1,qual:4,ig:[["Boeuf haché grossier",700,"g"],["Oignons",2,"pièces"],["Tomates",2,"pièces"],["Oeuf",1,"pièce"],["Coriandre fraîche",3,"cs"],["Coriandre moulue",1,"cc"],["Cumin moulu",1,"cc"],["Piment rouge",1,"cc"],["Grenade sèche (anardana)",2,"cs"],["Farine de maïs",2,"cs"],["Huile pour friture",1,"L"]],et:"1. Mélanger boeuf + oignons râpés exprimés + tomates épépinées + oeuf + épices + anardana + farine + coriandre.\n2. Former des galettes plates de 10cm.\n3. Chauffer huile abondante dans poêle. Frire les galettes 3-4 min par face.\n4. Égoutter sur papier absorbant.\n5. Servir avec rondelles de tomate + oignons + chutney vert.",vin:"Thé karak ou lassi salé",notes:"L'anardana (grenade sèche) est l'ingrédient secret du chapli kebab de Peshawar. Ne pas substituer."},
{id:"PK003",co:"Asie",cat:"Entrée",sous:"Riz",nom:"Mutton Karahi (Agneau au Wok)",chef:"Tradition pakisanaise",bp:4,prep:10,cui:60,diff:2,qual:5,ig:[["Agneau en cubes",800,"g"],["Tomates fraîches",6,"pièces"],["Ail",8,"gousses"],["Gingembre",50,"g"],["Piment rouge",1,"cs"],["Coriandre moulue",1,"cc"],["Cumin",1,"cc"],["Poivre noir concassé",1,"cc"],["Ghee",6,"cs"],["Coriandre fraîche",1,"bouquet"],["Piments verts",3,"pièces"]],et:"1. Chauffer ghee dans karahi (wok profond). Dorer l'agneau sans eau 10-15 min en remuant.\n2. Ajouter tomates écrasées + ail + gingembre. Cuire jusqu'à tomates fondues (20 min).\n3. Ajouter épices. Cuire jusqu'à huile remontée en surface.\n4. L'agneau cuit dans ses propres jus et tomates sans eau ajoutée.\n5. Garnir coriandre + piments verts + gingembre julienne.",vin:"Thé vert ou lassi",notes:"La clé du karahi : cuire sans eau. Les tomates et la graisse de l'agneau créent le bouillon naturel."},
{id:"PK004",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Kheer Caramel (Riz au Lait Épicé Pakistanais)",chef:"Tradition pakistanaise",bp:6,prep:5,cui:45,diff:1,qual:4,ig:[["Riz basmati",100,"g"],["Lait entier",150,"cl"],["Sucre",100,"g"],["Cardamome verte",4,"pièces"],["Eau de rose",2,"cs"],["Pistaches effilées",40,"g"],["Amandes effilées",40,"g"],["Safran",0.2,"g"]],et:"1. Rincer le riz. Cuire dans le lait entier à feu doux 40 min en remuant constamment.\n2. Ajouter sucre + cardamome + safran. Cuire encore 5 min.\n3. Eau de rose hors feu.\n4. Verser dans des coupes. Réfrigérer 4h.\n5. Garnir de pistaches + amandes effilées + pétales de rose séchés.",vin:"Thé chai ou eau de rose fraîche",notes:"Le kheer pakistanais est plus épicé à la cardamome que le kheer indien. L'eau de rose est sa signature."},
{id:"PK005",co:"Asie",cat:"Plat",sous:"Pain",nom:"Haleem (Ragoût de Blé et Lentilles à la Viande)",chef:"Tradition pakistanaise et hyderabadi",bp:6,prep:20,cui:240,diff:2,qual:4,ig:[["Blé concassé",200,"g"],["Lentilles mélangées",150,"g"],["Boeuf ou agneau haché",600,"g"],["Oignons frits",150,"g"],["Ail gingembre pâte",3,"cs"],["Garam masala",2,"cc"],["Curcuma",1,"cc"],["Ghee",4,"cs"],["Jus de citron gingembre coriandre",1,"qs"]],et:"1. Faire tremper blé et lentilles la nuit. Égoutter.\n2. Cuire viande avec épices + oignons frits. Ajouter blé + lentilles + eau.\n3. Cuire 3-4h à feu doux jusqu'à blé et lentilles complètement fondus.\n4. Battre énergiquement (ou mixer) jusqu'à texture homogène et filante.\n5. Ghee grillé sur le dessus. Oignons frits + gingembre + coriandre + citron.",vin:"Thé pakistanais fort",notes:"Le haleem est un plat de réconciliation des textures — la viande disparaît dans le blé. Battre longuement est essentiel."},
{id:"SG001",co:"Asie",cat:"Plat",sous:"Poulet",nom:"Hainanese Chicken Rice (Poulet Hainanais)",chef:"Tradition de Singapour",bp:4,prep:20,cui:60,diff:2,qual:5,ig:[["Poulet entier",1600,"g"],["Riz long",400,"g"],["Ail",10,"gousses"],["Gingembre",60,"g"],["Oignons verts",6,"tiges"],["Huile de poulet (graisse récupérée)",3,"cs"],["Bouillon de poulet",80,"cl"],["Sauce chili rouge",6,"cs"],["Sauce soja sucrée",4,"cs"],["Huile de sésame",2,"cs"]],et:"1. Pocher le poulet entier dans eau avec ail + gingembre + oignons verts. Frémissement 45 min. Sortir. Plonger dans eau glacée 15 min (peau croustillante).\n2. Faire revenir ail + gingembre dans graisse de poulet. Ajouter riz. Nacrer.\n3. Cuire le riz avec bouillon de poulet au lieu d'eau.\n4. Découper le poulet. Arroser d'huile de sésame + soja.\n5. Servir avec bols de bouillon + sauce chili + sauce de gingembre.",vin:"Thé à la chrysanthème ou thé chinois",notes:"Le plongeon dans l'eau glacée est le secret de la peau lisse et légèrement gélatineuse caractéristique. Le riz cuit dans le bouillon de poulet est aussi important que le poulet lui-même."},
{id:"SG002",co:"Asie",cat:"Plat",sous:"Crabe",nom:"Chili Crab de Singapour",chef:"Tradition singapourienne nationale",bp:4,prep:20,cui:20,diff:2,qual:5,ig:[["Crabe de vase",1500,"g"],["Sauce tomate",4,"cs"],["Pâte de piment (sambal)",3,"cs"],["Ail",6,"gousses"],["Gingembre",30,"g"],["Sauce de soja",2,"cs"],["Sucre",2,"cs"],["Oeufs",2,"pièces"],["Oignons verts",3,"tiges"],["Huile",4,"cs"],["Fécule délayée",2,"cs"],["Pains mantou frits",8,"pièces"]],et:"1. Couper le crabe vivant proprement. Nettoyer.\n2. Frire ail + gingembre + sambal dans huile 2 min.\n3. Ajouter les morceaux de crabe. Sauter 5 min.\n4. Ajouter sauce tomate + soja + sucre + 10cl eau. Couvrir 5 min.\n5. Lier avec fécule. Battre oeufs. Verser en filet pour créer des filaments. Oignons verts. Servir avec mantou.",vin:"Bière Tiger très froide ou vin blanc Singapore Sling",notes:"Le chili crab est l'emblème de Singapour. Les mantou frits pour tremper dans la sauce sont obligatoires."},
{id:"SG003",co:"Asie",cat:"Plat",sous:"Nouilles",nom:"Laksa de Singapour",chef:"Tradition Peranakan singapourienne",bp:4,prep:20,cui:20,diff:2,qual:5,ig:[["Pâte laksa",6,"cs"],["Lait de coco",60,"cl"],["Bouillon de crevettes",60,"cl"],["Crevettes",250,"g"],["Filet de poisson frit",200,"g"],["Tofu frit",150,"g"],["Vermicelles de riz ou mee tai mak",400,"g"],["Pousses de soja",150,"g"],["Oeufs de caille durs",8,"pièces"],["Sambal otah",1,"qs"],["Feuilles de laksa (daun kesum)",1,"bouquet"]],et:"1. Frire la pâte laksa dans l'huile 3 min jusqu'à très parfumée.\n2. Ajouter lait de coco + bouillon. Frémir 10 min.\n3. Cuire crevettes dans le bouillon 3 min. Réserver.\n4. Bols : vermicelles + pousses de soja + tofu + poisson + crevettes + oeufs.\n5. Verser bouillon brûlant. Feuilles de laksa fraîches. Sambal.",vin:"Thé teh tarik ou bière Tiger",notes:"La pâte laksa singapourienne (katong style) est plus crémeuse et moins acide que la malaisienne de Penang."},
{id:"SG004",co:"Asie",cat:"Entrée",sous:"Soupe",nom:"Bak Chor Mee (Nouilles au Porc Haché)",chef:"Tradition sino-singapourienne",bp:4,prep:15,cui:15,diff:1,qual:4,ig:[["Nouilles chinoises fines (mee pok)",400,"g"],["Porc haché",300,"g"],["Foie de porc",100,"g"],["Boulettes de porc",12,"pièces"],["Champignons shiitake",60,"g"],["Vinaigre noir",4,"cs"],["Sauce de soja",3,"cs"],["Huile pimentée",2,"cs"],["Oignons frits",3,"cs"],["Bouillon de porc",120,"cl"]],et:"1. Assaisonner chaque bol : vinaigre noir + soja + huile pimentée + oignons frits.\n2. Cuire les nouilles al dente. Égoutter.\n3. Mélanger nouilles dans les bols assaisonnés.\n4. Dans le bouillon chaud : pocher porc haché + foie + boulettes 3-4 min.\n5. Disposer sur les nouilles. Verser un peu de bouillon. Champignons.",vin:"Thé chinois chaud",notes:"Le vinaigre noir dans la sauce est la signature du bak chor mee — son acidité équilibre la richesse du porc."},
{id:"SG005",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Chendol de Singapour",chef:"Tradition sino-malaise de Singapour",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Farine de riz gluant",100,"g"],["Extrait de pandan",2,"cs"],["Gula melaka (sucre de palme)",150,"g"],["Eau",10,"cl"],["Lait de coco",40,"cl"],["Sel marin",1,"pincée"],["Glace pilée",1,"qs"],["Haricots rouges sucrés",200,"g"]],et:"1. Cendol : mélanger farine + pandan + 20cl eau. Cuire en remuant jusqu'à pâte. Passer dans passoire à trous pour former des vermicelles verts dans l'eau glacée.\n2. Sirop gula melaka : cuire sucre de palme + eau + pandan jusqu'à caramel foncé. Filtrer.\n3. Lait de coco : chauffer avec pincée de sel. Refroidir.\n4. Montagnes de glace pilée dans bols.\n5. Cendol vert + haricots rouges + sirop foncé + lait de coco.",vin:"Rafraîchissement équatorial incontournable",notes:"Différence avec le cendol malaisien : la version singapourienne est souvent plus abondante en gula melaka — sirop très noir et intense."},
{id:"TH001",co:"Asie",cat:"Plat",sous:"Pad Thai / Bangkok",nom:"Pad Thai Authentique aux Crevettes Tigrées (Recette David Thompson)",chef:"David Thompson (★ Nahm Bangkok)",bp:4,prep:25,cui:12,diff:3,qual:5,ig:[["Nouilles de riz plates 5 mm sèches",350,"g"],["Crevettes tigrées fraîches décortiquées (queue ouverte)",16,"pièces"],["Tofu ferme en cubes 1 cm",150,"g"],["Œufs frais",3,"pièces"],["Tamarin pulpe (signature obligatoire)",4,"cs"],["Sucre de palme Thaï",4,"cs"],["Nuoc mâm Phú Quốc Premium",4,"cs"],["Ail râpé",4,"gousses"],["Échalote thaïe (krachai)",2,"pièces"],["Pousses de soja fraîches",200,"g"],["Cacahuètes grillées concassées",100,"g"],["Lime de Thaïlande (kaffir lime + lime acide)",2,"pièces"],["Coriandre fraîche",1,"bouquet"],["Ciboule chinoise",4,"tiges"],["Piment rouge thaï frais (prik chee fa)",2,"pièces"],["Daikon mariné (signature Bangkok)",60,"g"],["Huile végétale neutre",4,"cs"]],et:"SAUCE PAD THAI (le secret professionnel David Thompson) :\n1. Faire infuser la pulpe de tamarin dans 6 cs eau chaude 10 min. Filtrer en pressant — récupérer le jus tamarin pur.\n2. Mélanger : 4 cs jus tamarin + sucre de palme + nuoc mâm. Chauffer doucement jusqu'à dissolution complète — la sauce est aigre-douce-salée en équilibre, profonde.\nPRÉPARATION DES NOUILLES :\n3. Plonger nouilles sèches dans eau TIÈDE 25 min jusqu'à souples mais encore al dente. Égoutter, garder humides.\nWOK À FEU MAX (technique 'wok hei' thaï) :\n4. Préchauffer wok à feu MAX. Verser 2 cs huile.\n5. Saisir tofu en cubes 90 sec, doré aux bords. Pousser sur le côté.\n6. Ajouter crevettes 60 sec côté plat — encore translucides à cœur. Pousser sur le côté.\n7. Ail + échalote 15 sec.\n8. Casser les œufs au centre. Brouiller 30 sec — encore baveux.\nNOUILLES (étape capitale) :\n9. Verser les nouilles dans le wok. Verser la sauce tamarin-palme-nuoc mâm dessus. Sauter énergiquement 90 sec — la sauce caramélise sur les nouilles, créant la couleur ambrée signature pad thai.\n10. Ajouter cacahuètes (moitié) + pousses de soja (moitié) + ciboule. Sauter 30 sec — les pousses doivent rester croquantes.\nDRESSAGE BANGKOK STYLE :\n11. Dresser sur grand plat plat. Garnir : reste de cacahuètes + reste pousses de soja crues + coriandre + lime en quartiers + piment thaï frais en tranches + daikon mariné.\n12. Convive : presse lime sur son pad thai + ajoute piment selon goût.",vin:"Bière thaïe Singha ou Riesling Mosel demi-sec",notes:"David Thompson (★ Nahm Bangkok — Australien autorité de la cuisine thaïlandaise) : \"Le pad thai authentique est un trio sacré : tamarin (aigre), sucre de palme (doux), nuoc mâm (salé). Sans tamarin, ce n'est PAS du pad thai. Wok ultra-chaud, nouilles caramélisées, garnitures crues.\""},
{id:"TH002",co:"Asie",cat:"Plat",sous:"Curry vert / Bangkok",nom:"Gaeng Khiao Wan Gai (Curry Vert Thaï au Poulet, Recette Chumpol Jangprai)",chef:"Chumpol Jangprai (★, R-Haan Bangkok)",bp:4,prep:25,cui:25,diff:3,qual:5,ig:[["Cuisses de poulet désossées en cubes",600,"g"],["Pâte de curry vert maison ou Mae Ploy",4,"cs"],["Lait de coco Premium Aroy-D",60,"cl"],["Aubergines thaïes rondes (makua pao)",250,"g"],["Aubergines thaïes pois (makua puang)",80,"g"],["Bouillon de poulet",15,"cl"],["Citronnelle (lemongrass)",2,"tiges"],["Galanga frais",3,"cm"],["Feuilles kaffir lime fraîches",6,"feuilles"],["Basilic thaï frais (bai horapa)",1,"bouquet"],["Piment vert thaï (prik kee nu)",4,"pièces"],["Nuoc mâm",3,"cs"],["Sucre de palme",2,"cs"],["Pâte de crevettes Kapi (signature)",1,"cc"]],et:"BASE AROMATIQUE (technique Jangprai) :\n1. Diviser le lait de coco : prélever 25 cl du dessus (la crème) + garder 35 cl (le lait fluide).\n2. Écraser la citronnelle au pilon (libère arômes). Couper en tronçons. Trancher galanga.\nFRITURE DU CURRY (étape capitale 'cracking') :\n3. Dans un wok ou poêle large, chauffer la CRÈME du lait de coco à feu moyen-vif 5 min — elle se sépare en petits grains huileux et liquide. Cette \"break\" est ce qui donne la profondeur.\n4. Ajouter la pâte de curry vert + pâte de crevettes Kapi. Frire 4-5 min jusqu'à parfum très intense et que l'huile rouge-verte remonte (signature professionnelle).\nCUISSON DU POULET :\n5. Ajouter le poulet en cubes. Enrober 2 min.\n6. Verser le LAIT DE COCO FLUIDE + bouillon + citronnelle + galanga + feuilles kaffir lime. Frémir 12 min.\nLÉGUMES (texture importante) :\n7. Ajouter aubergines makua pao (rondes) — couper en quartiers. 6 min.\n8. Ajouter aubergines makua puang (pois) — entières. 4 min.\nASSAISONNEMENT THAÏ (équilibre sacré) :\n9. Assaisonner : nuoc mâm + sucre de palme. Goûter — le curry doit être : salé (nuoc mâm) + doux (sucre) + crémeux (coco) + parfumé (citronnelle/kaffir) + piquant (curry vert) en équilibre.\n10. Ajouter piments verts thaï tranchés (selon tolérance).\nFINITION (la touche fraîche) :\n11. Hors feu, ajouter feuilles de basilic thaï entières + 6 feuilles kaffir lime déchirées (libèrent leurs arômes).\nSERVICE :\n12. Servir bouillant dans bol traditionnel thaï avec riz jasmine.\n13. Accompagner : nam pla prik (sauce piment-poisson), sucre, vinaigre — chaque convive ajuste.",vin:"Bière thaïe Chang Premium ou Riesling Mosel demi-sec",notes:"Chumpol Jangprai (★ R-Haan Bangkok) : \"Le curry vert authentique est défini par 4 saveurs équilibrées : crémeux (coco), salé (nuoc mâm + Kapi), doux (sucre palme), fraîcheur (kaffir lime + basilic thaï). La 'crème' du coco doit toujours 'craquer' avant d'ajouter la pâte — c'est la base.\""},
{id:"TH003",co:"Asie",cat:"Soupe",sous:"Soupe",nom:"Tom Kha Gai (Soupe Coco Galanga Poulet)",chef:"Tradition thaïlandaise",bp:4,prep:15,cui:20,diff:1,qual:4,ig:[["Lait de coco",80,"cl"],["Blancs de poulet en fines lanières",400,"g"],["Galanga frais",4,"cm"],["Citronnelle",2,"tiges"],["Kaffir lime feuilles",6,"pièces"],["Champignons de Paris",200,"g"],["Nuoc-mâm",3,"cs"],["Jus de lime",4,"cs"],["Piment oiseau",2,"pièces"],["Coriandre fraîche",0.5,"bouquet"]],et:"1. Porter le lait de coco à frémissement avec galanga + citronnelle écrasée + kaffir lime.\n2. Ne jamais faire bouillir le lait de coco - il se séparerait.\n3. Ajouter le poulet + champignons. Cuire 8-10 min à frémissement doux.\n4. Assaisonner avec nuoc-mâm + jus de lime.\n5. Parsemer de piment oiseau émincé + coriandre fraîche. Servir dans des bols.",vin:"Riesling Alsace ou eau de coco froide",notes:"Le galanga est indispensable - il ne peut pas être remplacé par du gingembre ordinaire."},
{id:"TH004",co:"Asie",cat:"Plat",sous:"Curry",nom:"Gaeng Daeng (Curry Rouge au Poulet)",chef:"Tradition thaïlandaise",bp:4,prep:15,cui:20,diff:2,qual:5,ig:[["Poulet en cubes",600,"g"],["Pâte de curry rouge thai",4,"cs"],["Lait de coco",50,"cl"],["Aubergines thai",200,"g"],["Haricots plats thai",150,"g"],["Feuilles de combava",6,"pièces"],["Basilic thai",1,"bouquet"],["Piment rouge",2,"pièces"],["Nuoc-mâm",3,"cs"],["Sucre de palme",2,"cs"]],et:"1. Chauffer la crème de coco (dessus du lait) dans wok. Ajouter pâte de curry. Frire 3 min jusqu'à huile séparée.\n2. Ajouter le poulet. Sauter 5 min.\n3. Ajouter reste du lait de coco + feuilles combava déchirées.\n4. Ajouter aubergines + haricots. Cuire 10 min.\n5. Assaisonner nuoc-mâm + sucre palme. Basilic thai + piments. Servir avec riz jasmin.",vin:"Bière Singha ou thé glacé thai",notes:"Frire la pâte de curry dans la crème de coco séparée est la technique thai traditionnelle pour développer les arômes."},
{id:"TH005",co:"Asie",cat:"Plat",sous:"Curry",nom:"Gaeng Massaman (Curry Massaman au Boeuf)",chef:"Tradition thai-musulmane du Sud",bp:4,prep:20,cui:90,diff:2,qual:5,ig:[["Boeuf à braiser en cubes",800,"g"],["Pâte de curry Massaman",5,"cs"],["Lait de coco",60,"cl"],["Pommes de terre",400,"g"],["Cacahuètes",80,"g"],["Oignons",2,"pièces"],["Tamarin",3,"cs"],["Sucre de palme",3,"cs"],["Nuoc-mâm",3,"cs"],["Cannelle cardamome anis étoilé",1,"qs"],["Feuilles de laurier",3,"pièces"]],et:"1. Torréfier les épices entières 1 min à sec. Réserver.\n2. Frire pâte Massaman dans la crème de coco. Ajouter le boeuf.\n3. Mouiller avec lait de coco + 30cl eau + épices. Mijoter 1h.\n4. Ajouter pommes de terre + oignons + cacahuètes + laurier. Cuire 30 min.\n5. Assaisonner tamarin + sucre palme + nuoc-mâm. Équilibre sucré-acide-salé.",vin:"Bière Chang ou thé à la menthe glacé",notes:"Le Massaman est d'influence persane et malaise. Les épices chaudes le distinguent des autres curries thai."},
{id:"TH006",co:"Asie",cat:"Plat",sous:"Sauté",nom:"Pad See Ew (Nouilles Sautées à la Sauce Soja Sucrée)",chef:"Tradition thaïlandaise",bp:4,prep:15,cui:10,diff:2,qual:4,ig:[["Nouilles plates larges",400,"g"],["Poulet ou porc en lamelles",300,"g"],["Oeufs",3,"pièces"],["Brocoli chinois kai lan",300,"g"],["Ail",4,"gousses"],["Sauce soja claire",3,"cs"],["Kecap manis (soja sucré noir)",3,"cs"],["Sauce d'huîtres",2,"cs"],["Sucre",1,"cs"],["Huile",3,"cs"]],et:"1. Séparer les nouilles fraîches ou cuire les sèches, rincer.\n2. Sauter ail dans huile très chaude. Ajouter viande. Dorer rapidement.\n3. Pousser viande sur les bords. Casser oeufs au centre. Brouiller grossièrement.\n4. Ajouter brocoli chinois. Sauter 1 min.\n5. Ajouter nouilles + sauces + sucre. Sauter à très vif 2-3 min pour caraméliser.",vin:"Bière Leo thaï ou thé glacé",notes:"Le feu très vif est essentiel. Certaines nouilles doivent légèrement brûler pour le goût caractéristique."},
{id:"TH007",co:"Asie",cat:"Entrée",sous:"Salade",nom:"Yam Talay (Salade de Fruits de Mer)",chef:"Tradition thaïlandaise",bp:4,prep:20,cui:10,diff:2,qual:4,ig:[["Crevettes",200,"g"],["Calmars",200,"g"],["Moules cuites",150,"g"],["Jus de citron vert",6,"cs"],["Nuoc-mâm",4,"cs"],["Sucre de palme",2,"cs"],["Piments oiseaux",3,"pièces"],["Ail",3,"gousses"],["Citronnelle émincée",2,"tiges"],["Oignons verts",2,"tiges"],["Menthe coriandre",1,"bouquet"],["Tomates cerises",200,"g"]],et:"1. Blanchir séparément crevettes et calmars 1 min. Rafraîchir.\n2. Sauce : jus lime + nuoc-mâm + sucre palme + piments hachés + ail haché + citronnelle.\n3. Mélanger fruits de mer + tomates coupées en deux + oignons verts.\n4. Verser la sauce.\n5. Ajouter herbes fraîches. Servir immédiatement.",vin:"Bière Singha ou cocktail citronnelle",notes:"La balance thaïlandaise : acide, salé, sucré, piquant. Tous perceptibles individuellement."},
{id:"TH008",co:"Asie",cat:"Plat",sous:"Volaille",nom:"Gai Yang (Poulet Grillé d'Isan)",chef:"Tradition d'Isan - Thaïlande",bp:4,prep:15,cui:25,diff:1,qual:4,ig:[["Poulet entier en crapaudine",1500,"g"],["Racines de coriandre",1,"bouquet"],["Ail",8,"gousses"],["Poivre blanc",1,"cc"],["Nuoc-mâm",4,"cs"],["Sauce soja",2,"cs"],["Sucre de palme",2,"cs"],["Lait de coco",10,"cl"],["Jus de citron vert",2,"cs"]],et:"1. Mixer racines de coriandre + ail + poivre + nuoc-mâm + soja + sucre + lait coco en pâte.\n2. Badigeonner le poulet entier ouvert en crapaudine. Mariner 4h.\n3. Griller sur braise moyenne 20-25 min en retournant et arrosant.\n4. La peau doit être dorée-caramélisée.\n5. Servir avec sauce Jaew (nuoc-mâm + lime + piment + ail + coriandre + riz grillé pilé).",vin:"Bière Singha ou eau de coco fraîche",notes:"Le gai yang est le poulet grillé de rue thaïlandais. Les racines de coriandre (pas les feuilles) sont l'ingrédient clé."},
{id:"TH009",co:"Asie",cat:"Plat",sous:"Mer",nom:"Pla Nueng Manao (Poisson Vapeur au Citron Vert)",chef:"Tradition thaïlandaise",bp:4,prep:15,cui:15,diff:2,qual:5,ig:[["Poisson entier",1000,"g"],["Jus de citron vert",6,"cs"],["Nuoc-mâm",4,"cs"],["Sucre",2,"cs"],["Ail",6,"gousses"],["Piments oiseaux",4,"pièces"],["Citronnelle",2,"tiges"],["Gingembre galanga",20,"g"],["Coriandre",1,"bouquet"]],et:"1. Inciser le poisson des deux côtés. Farcir de citronnelle + galanga + coriandre.\n2. Cuire à la vapeur vive 12-15 min.\n3. Sauce : jus lime + nuoc-mâm + sucre + ail + piments hachés. Chauffer légèrement.\n4. Verser la sauce chaude sur le poisson cuit.\n5. Coriandre fraîche. Servir immédiatement.",vin:"Riesling sec ou bière Singha",notes:"La sauce acide-piquante chaude versée sur le poisson vapeur est l'une des grandes préparations de la cuisine thai."},
{id:"TH010",co:"Asie",cat:"Entrée",sous:"Salade",nom:"Som Tum (Salade de Papaye Verte)",chef:"Tradition d'Isan - Thaïlande",bp:4,prep:20,cui:0,diff:2,qual:5,ig:[["Papaye verte",500,"g"],["Tomates cerises",150,"g"],["Haricots longs",100,"g"],["Cacahuètes grillées",50,"g"],["Piments oiseaux",3,"pièces"],["Ail",3,"gousses"],["Nuoc-mâm",3,"cs"],["Jus de citron vert",3,"cs"],["Sucre de palme",2,"cs"],["Crevettes séchées",2,"cs"]],et:"1. Éplucher et râper la papaye en julienne grossière (ou mandoline).\n2. Dans mortier : piler ail + piments en pâte grossière. Ajouter crevettes séchées + sucre.\n3. Ajouter haricots coupés + tomates. Écraser légèrement.\n4. Ajouter papaye + nuoc-mâm + jus lime. Mélanger au pilon en soulevant.\n5. Goûter et ajuster. Parsemer cacahuètes grillées.",vin:"Bière Singha très froide ou eau de coco",notes:"Le mortier est indispensable — il écrase légèrement les ingrédients pour libérer les arômes sans les broyer."},
{id:"TH011",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Tom Kha Gai (Soupe Coco au Poulet et Galanga)",chef:"Tradition thaïlandaise",bp:4,prep:15,cui:20,diff:2,qual:5,ig:[["Lait de coco",80,"cl"],["Blanc de poulet en lamelles",400,"g"],["Galanga frais",40,"g"],["Citronnelle",3,"tiges"],["Feuilles de combava",8,"pièces"],["Champignons de paille",200,"g"],["Nuoc-mâm",4,"cs"],["Jus de citron vert",3,"cs"],["Sucre de palme",1,"cs"],["Piments oiseaux",3,"pièces"],["Coriandre",1,"bouquet"]],et:"1. Porter lait de coco à frémissement avec galanga + citronnelle écrasée + feuilles combava.\n2. Infuser 10 min à feu très doux.\n3. Ajouter poulet. Cuire 8 min.\n4. Ajouter champignons. Cuire 3 min.\n5. Assaisonner nuoc-mâm + lime + sucre. Piments. Coriandre fraîche. Servir.",vin:"Thé thai glacé ou bière Chang",notes:"Ne jamais bouillir fort — le lait de coco se dissocie. Le galanga (kha) est différent du gingembre, plus floral et poivré."},
{id:"TH012",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Khao Niao Mamuang (Riz Gluant à la Mangue)",chef:"Tradition thaïlandaise",bp:4,prep:15,cui:25,diff:2,qual:5,ig:[["Riz gluant",300,"g"],["Lait de coco",40,"cl"],["Sucre",80,"g"],["Sel",1,"cc"],["Mangues mûres",2,"pièces"],["Graines de sésame grillées",1,"cs"]],et:"1. Tremper le riz gluant dans l'eau froide 4h minimum. Égoutter.\n2. Cuire à la vapeur 20-25 min jusqu'à translucide et collant.\n3. Chauffe lait de coco + sucre + sel jusqu'à sucre dissous. Ne pas bouillir.\n4. Verser la sauce coco sur le riz chaud. Mélanger. Laisser absorber 20 min.\n5. Servir avec lamelles de mangue mûre. Filet de lait de coco sucré. Graines de sésame.",vin:"Thé jasmin frais ou eau de coco",notes:"Le riz gluant doit être trempé au moins 4h — sans trempage il ne cuit pas uniformément."},
{id:"TH013",co:"Asie",cat:"Plat",sous:"Sauté",nom:"Pad Krapao Moo (Porc Sauté au Basilic Sacré)",chef:"Tradition thaïlandaise de rue",bp:4,prep:10,cui:10,diff:1,qual:5,ig:[["Porc haché",500,"g"],["Basilic sacré thai (krapao)",1,"bouquet"],["Ail",6,"gousses"],["Piments oiseaux",5,"pièces"],["Sauce d'huîtres",3,"cs"],["Nuoc-mâm",2,"cs"],["Sauce soja noire",1,"cs"],["Sucre",1,"cc"],["Huile",3,"cs"],["Oeufs au plat",4,"pièces"],["Riz jasmin cuit",600,"g"]],et:"1. Chauffer huile à très vif. Faire revenir ail + piments écrasés 30 sec.\n2. Ajouter porc haché. Saisir à feu vif sans mélanger 2 min — laisser colorer.\n3. Casser et mélanger. Ajouter sauce d'huîtres + nuoc-mâm + soja noir + sucre.\n4. Sauter encore 2 min. Hors feu : basilic sacré. Mélanger — il se flétrit instantanément.\n5. Servir sur riz avec oeuf au plat aux bords croustillants.",vin:"Bière Singha ou thé glacé thai",notes:"Le basilic sacré (krapao) n'est pas le basilic européen — poivré et anisé. Le pad krapao est LE plat de rue n°1 en Thaïlande."},
{id:"TH014",co:"Asie",cat:"Sauce / Base",sous:"Pâte",nom:"Pâte de Curry Vert Maison (Gaeng Kiaw Wan)",chef:"Tradition thaïlandaise",bp:4,prep:20,cui:0,diff:2,qual:5,ig:[["Piments verts frais",10,"pièces"],["Citronnelle",3,"tiges"],["Galanga frais",30,"g"],["Feuilles de combava",5,"pièces"],["Ail",8,"gousses"],["Échalotes",5,"pièces"],["Coriandre racines et tiges",1,"bouquet"],["Crevettes séchées",1,"cs"],["Pâte de crevettes (kapi)",1,"cc"],["Cumin coriandre en poudre",1,"qs"]],et:"1. Torréfier cumin + coriandre à sec 1 min.\n2. Couper finement tous les ingrédients.\n3. Piler au mortier dans cet ordre : piments + sel + galanga + citronnelle + combava + ail + échalotes.\n4. Ajouter racines de coriandre + crevettes + kapi + épices.\n5. Piler jusqu'à pâte lisse et homogène. Se conserve 2 semaines au froid ou 3 mois congelé.",vin:"Usage : curry vert, soupes thai, marinades",notes:"La pâte maison est incomparable. Le mortier est obligatoire — un mixer donne une pâte mais sans la même texture et intensité."},
{id:"TW001",co:"Asie",cat:"Plat",sous:"Porc",nom:"Lu Rou Fan (Riz au Porc Braisé Taïwanais)",chef:"Tradition taïwanaise",bp:4,prep:15,cui:90,diff:1,qual:5,ig:[["Poitrine de porc",600,"g"],["Échalotes",6,"pièces"],["Sauce soja",6,"cs"],["Sauce soja noire",2,"cs"],["Saké ou vin de riz",4,"cs"],["Sucre roux",2,"cs"],["Cinq-épices",0.5,"cc"],["Oeufs durs",4,"pièces"],["Riz blanc cuit",600,"g"],["Oignons verts",2,"tiges"]],et:"1. Couper poitrine en petits cubes de 1cm (avec la peau).\n2. Dorer les cubes dans une poêle anti-adhésive jusqu'à la graisse fondue et cubes caramélisés.\n3. Frire les échalotes émincées dans la graisse rendue jusqu'à dorées croustillantes.\n4. Ajouter porc + soja + vin + sucre + cinq-épices + eau à hauteur. Ajouter oeufs entiers épluchés.\n5. Mijoter 1h30 à feu doux. Oeufs absorbent la couleur. Servir sur riz.",vin:"Thé oolong taïwanais ou bière Taiwan Beer",notes:"Le lu rou fan est le comfort food de Taïwan. La peau de porc gélatineuse se fond dans la sauce et lui donne un corps incomparable."},
{id:"TW002",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Beef Noodle Soup Taïwanaise (Niou Rou Mian)",chef:"Tradition taïwanaise",bp:4,prep:20,cui:150,diff:2,qual:5,ig:[["Boeuf à braiser (jarret ou plat de côtes)",800,"g"],["Bouillon de boeuf",200,"cl"],["Sauce soja",6,"cs"],["Pâte de haricots au piment (doubanjiang)",3,"cs"],["Tomates concassées",400,"g"],["Ail",6,"gousses"],["Gingembre",40,"g"],["Anis étoilé cannelle",1,"qs"],["Nouilles fraîches de blé",400,"g"],["Bok choy",4,"pièces"],["Oignons verts",3,"tiges"]],et:"1. Blanchir le boeuf. Rincer.\n2. Dorer ail + gingembre. Ajouter doubanjiang. Cuire 3 min.\n3. Ajouter tomates + boeuf + bouillon + épices entières + soja. Frémir 2h30.\n4. Cuire les nouilles. Blanchir bok choy.\n5. Bols : nouilles + bok choy + boeuf en tranches. Bouillon très chaud. Oignons verts + huile de sésame.",vin:"Bière Taiwan Beer ou thé oolong",notes:"Les beef noodles taïwanaises sont parmi les meilleures nouilles au monde. Le doubanjiang est le secret de leur profondeur."},
{id:"TW003",co:"Asie",cat:"Entrée",sous:"Street food",nom:"Popcorn Chicken Taïwanais (Yan Su Ji)",chef:"Tradition taïwanaise de street food",bp:4,prep:20,cui:10,diff:2,qual:5,ig:[["Blanc de poulet",700,"g"],["Farine de patate douce",150,"g"],["Ail en poudre",1,"cc"],["Cinq-épices",0.5,"cc"],["Poivre blanc",1,"cc"],["Sauce soja",3,"cs"],["Basil thaï",1,"bouquet"],["Huile pour friture",1,"L"],["Poivre et sel mélangés",1,"cs"]],et:"1. Couper poulet en petits cubes de 2cm. Mariner avec soja + ail + cinq-épices + poivre blanc 30 min.\n2. Enrober généreusement de farine de patate douce en tapotant.\n3. Frire à 170°C 4-5 min jusqu'à croustillants.\n4. Monter la T° à 190°C. Frire les feuilles de basilic thai 5 secondes.\n5. Servir poulet mélangé au basilic frit. Sel-poivre mélangés taïwanais.",vin:"Bière froide ou thé perlé",notes:"La farine de patate douce (non la maïzena) donne la texture légèrement crousti-moelleuse unique du popcorn chicken taïwanais."},
{id:"TW004",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Bubble Tea Original (Boba au Lait)",chef:"Tradition taïwanaise des années 1980",bp:4,prep:10,cui:30,diff:1,qual:4,ig:[["Perles de tapioca noires",200,"g"],["Thé noir Assam fort",60,"cl"],["Lait entier",20,"cl"],["Sirop de sucre brun",6,"cs"],["Sirop de cassonade pour perles",3,"cs"],["Glaçons",1,"qs"]],et:"1. Cuire les perles de tapioca dans eau bouillante 30 min en remuant. Égoutter.\n2. Tremper dans sirop de cassonade 20 min. Les perles absorbent le sirop et brillent.\n3. Préparer un thé noir fort. Refroidir.\n4. Dans un shaker : thé + lait + sirop + glaçons. Shaker vigoureusement 30 sec.\n5. Verser dans grands verres avec les perles. Pailles larges.",vin:"Boisson rafraîchissante taïwanaise devenue mondiale",notes:"La texture des perles doit être légèrement mâcheuse (chewy) — ni trop dure ni trop molle. L'erreur commune est de ne pas les laisser reposer dans le sirop assez longtemps."},
{id:"TW005",co:"Asie",cat:"Plat",sous:"Fruits de mer",nom:"Oyster Omelette Taïwanaise (O A Jian)",chef:"Tradition de street food taïwanaise",bp:4,prep:10,cui:10,diff:2,qual:4,ig:[["Huîtres fraîches",300,"g"],["Oeufs",4,"pièces"],["Fécule de patate douce",4,"cs"],["Eau",10,"cl"],["Jeunes pousses de roquette ou épinards",100,"g"],["Sauce soja",2,"cs"],["Ketchup",2,"cs"],["Pâte de piment (chili sauce)",2,"cs"],["Huile",3,"cs"]],et:"1. Mélanger fécule + eau jusqu'à liquide blanc. Battre oeufs séparément.\n2. Chauffer huile à vif. Verser la fécule liquide. Elle fige rapidement en crêpe translucide.\n3. Déposer les huîtres + pousses de légumes sur la crêpe.\n4. Verser les oeufs battus par-dessus.\n5. Retourner et cuire encore 2 min. Sauce : ketchup + soja + chili. Verser sur l'omelette.",vin:"Bière Taiwan Beer ou thé froid",notes:"La texture caractéristique de l'omelette taïwanaise vient de la fécule de patate douce — à la fois croustillante et légèrement gélatineuse."},
{id:"VN001",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Phở Bò Tái Hà Nội Authentique (Bouillon 12 h, Recette Phở Gia Truyền)",chef:"Phở Gia Truyền (Hanoï, référence mondiale depuis 1947)",bp:6,prep:30,cui:720,diff:4,qual:5,ig:[["Os à moelle de bœuf",1500,"g"],["Jarret de bœuf en gros morceaux",800,"g"],["Queue de bœuf",500,"g"],["Aiguillette baronne crue (à trancher fine pour bowl)",400,"g"],["Oignon brûlé (technique signature Hanoï)",2,"pièces"],["Gingembre brûlé",6,"cm"],["Anis étoilé (badiane)",6,"pièces"],["Bâton de cannelle",1,"pièce"],["Cardamome noire",2,"pièces"],["Clou de girofle",4,"pièces"],["Graines de coriandre",1,"cs"],["Graines de fenouil",1,"cc"],["Sucre de canne brut (yellow rock sugar)",30,"g"],["Sauce poisson Phú Quốc premium (3 Crabes ou Red Boat)",6,"cs"],["Sel marin",2,"cc"],["Nouilles de riz fraîches phở (bánh phở)",400,"g"],["Pousses de soja vivantes",200,"g"],["Basilic thaï (rau húng quế)",1,"bouquet"],["Coriandre vietnamienne (rau ngổ)",0.5,"bouquet"],["Citron vert (calamansi mexicain idéal)",4,"pièces"],["Piment chili rouge",3,"pièces"],["Sauce hoisin et sriracha (à part)",1,"qs"]],et:"BLANCHIMENT DES OS (J-2 si possible — technique purification) :\n1. Plonger les os + jarret + queue dans 4 L d'eau bouillante 10 min. Les impuretés et le sang remontent en mousse. Égoutter et rincer SOIGNEUSEMENT à l'eau froide.\nBOUILLON DE 12 HEURES (la signature Hanoï) :\n2. BRÛLAGE DES AROMATIQUES — étape capitale : poser oignons coupés en deux + gingembre tranché DIRECTEMENT sur la flamme du gaz (ou dans poêle à sec à feu fort). Tourner jusqu'à charbonner sur toutes les faces (couleur noire profonde). C'est ce qui donne la couleur ambrée caractéristique du pho.\n3. Toaster à sec dans une poêle 2 min : badiane + cannelle + cardamome + clou de girofle + coriandre + fenouil. Mettre dans un sachet en mousseline (ou nouer dans étamine).\n4. Dans une grande marmite (8 L), mettre os + jarret + queue + aromatiques brûlés + sachet d'épices + 6 L d'eau froide. Porter à frémissement, écumer méticuleusement.\n5. Ajouter sucre de canne + sel + sauce poisson. Frémir À COUVERT TRÈS DOUX pendant 8-12 h (Phở Gia Truyền cuit ses bouillons 14 h). NE JAMAIS BOUILLIR — un bouillon trouble est un bouillon raté.\n6. Filtrer 2 fois au chinois étamine. Récupérer le bouillon pur ambré. Désérouiller (graisses qui flottent). Goûter, ajuster sauce poisson + sel.\nPRÉPARATION DE LA VIANDE (le 'tái' = bœuf cru tranché) :\n7. Trancher l'aiguillette baronne CRUE en fines tranches de 2 mm CONTRE LE GRAIN — le froid facilite (placer 30 min au congélateur). C'est la signature 'tái'.\nSERVICE BOL PAR BOL (technique 'pha lay' Hanoï) :\n8. Cuire les nouilles phở 30 sec dans l'eau bouillante. Égoutter.\n9. Dans chaque bol PROFOND : nouilles chaudes + oignon vert ciselé + tranches de bœuf cru.\n10. VERSER le bouillon BOUILLANT (95°C minimum) sur le bœuf cru — la chaleur du bouillon le saisit instantanément, le rendant rosé. C'est la magie du phở tái.\n11. À table : pousses de soja + basilic thaï + coriandre + lime + piment + sauce hoisin + sriracha en accompagnements séparés. Chaque convive personnalise son bol.\n12. Manger : pincer un peu de chaque garniture, tremper dans le bouillon, déguster. Boire le bouillon directement à la cuillère en chinois.",vin:"Bière vietnamienne Bia Hà Nội ou thé vert chinois Lung Ching",notes:"Phở Gia Truyền (Hanoï, depuis 1947 — La Mecque mondiale du pho) : \"Le pho de Hanoï est plus subtil que celui de Saïgon. Bouillon clair (jamais trouble), épices équilibrées (jamais dominantes), nouilles fraîches du jour. La règle d'or : bouillon 12 h minimum, viande crue qui se cuit dans le bouillon, garnitures à part pour personnalisation. Et toujours : d'abord les nouilles, puis le bouillon, puis les garnitures.\""},
{id:"VN002",co:"Asie",cat:"Entrée",sous:"Rouleaux",nom:"Gỏi Cuốn aux Crevettes Tigrées et Sauce Cacahuète (Recette Charles Phan)",chef:"Charles Phan (★ The Slanted Door, San Francisco)",bp:4,prep:35,cui:8,diff:2,qual:5,ig:[["Galettes de riz vietnamiennes 22 cm",16,"pièces"],["Crevettes tigrées fraîches décortiquées (queue ouverte)",16,"pièces"],["Vermicelles de riz fins (bún)",100,"g"],["Cœur de laitue romaine (feuilles tendres)",8,"feuilles"],["Concombre",1,"pièce"],["Carottes (julienne fine)",2,"pièces"],["Menthe vietnamienne (rau húng)",30,"g"],["Coriandre fraîche",30,"g"],["Basilic thaï",30,"g"],["Ciboule chinoise (signature Charles Phan)",6,"tiges"],["Beurre de cacahuètes naturel (signature)",6,"cs"],["Sauce hoisin premium (Lee Kum Kee)",4,"cs"],["Sauce sriracha",1,"cs"],["Lait de coco",4,"cs"],["Sucre de palme (signature thaï)",1,"cs"],["Lime (jus)",1,"cs"],["Cacahuètes grillées concassées",4,"cs"]],et:"CUISSON DES CREVETTES (étape signature Charles Phan) :\n1. Plonger les crevettes dans une eau bouillante salée 90 secondes — elles doivent rosir mais rester translucides à cœur.\n2. Refroidir aussitôt à l'eau glacée (\"choc thermique\" — fixe la couleur, garde la jutosité).\n3. Couper chaque crevette en deux dans la longueur (technique Phan — les rouleaux sont plus beaux à la coupe).\nPRÉPARATION DES VERMICELLES :\n4. Cuire les vermicelles 3 min dans eau bouillante. Égoutter, rincer à l'eau glacée. Égoutter encore (sans eau résiduelle).\nDÉCOUPE FINE :\n5. Couper concombre en bâtonnets fins (julienne) avec leur peau. Carottes en julienne très fine à la mandoline.\n6. Effeuiller la laitue. Garder les feuilles tendres entières.\n7. Effeuiller herbes (menthe + coriandre + basilic thaï). Couper la ciboule en tronçons de 6 cm.\nSAUCE CACAHUÈTE PHAN (la signature ★) :\n8. Dans un bol, fouetter : beurre de cacahuètes + hoisin + sriracha + lait de coco + sucre de palme + jus de lime + 2 cs eau chaude. La sauce doit être nappante et brillante.\n9. Goûter, équilibrer : sucré + salé + acide + piquant. Saupoudrer cacahuètes concassées.\nROULAGE (technique Slanted Door) :\n10. Préparer un grand bol d'eau tiède (40°C). Tremper UNE galette de riz 5-8 secondes seulement — elle doit être souple mais pas molle (sinon trop fragile). Étaler à plat sur torchon humide.\n11. Sur le tiers inférieur : poser 1 feuille de laitue + 1 cs vermicelles + julienne carottes + concombre + brins de menthe + coriandre + basilic + 1 tronçon ciboule.\n12. Au-dessus de cette base : poser 4 demi-crevettes EN LIGNE côté rosé visible (signature Phan — le rouleau montre les crevettes par transparence).\n13. Rouler en demi-tour, replier les côtés, continuer à rouler en serrant fermement. Le rouleau doit être bien tendu (jamais lâche — perdrait sa forme).\nSERVICE :\n14. Couper chaque rouleau en deux en biais à la lame humide. Disposer sur planche en bois.\n15. Servir avec sauce cacahuète en saucière individuelle + cacahuètes concassées en parsemage.\n16. Quartiers de lime supplémentaires + petites tranches de chili rouge pour les amateurs.",vin:"Bière vietnamienne 333 ou Riesling Mosel sec",notes:"Charles Phan (★ The Slanted Door, San Francisco — autorité de la cuisine vietnamienne moderne) : \"Le secret du gỏi cuốn parfait n'est pas dans la garniture, mais dans le geste : galette trempée 5 secondes (pas plus), roulage très serré, sauce cacahuète onctueuse. La ciboule en signature donne la touche vietnamienne authentique. Et toujours, manger immédiatement — les rouleaux sèchent en 30 minutes.\""},
{id:"VN003",co:"Asie",cat:"Plat",sous:"Viande",nom:"Bò Lúc Lắc (Boeuf Shake)",chef:"Tradition vietnamienne",bp:4,prep:20,cui:10,diff:2,qual:4,ig:[["Filet de boeuf en cubes",600,"g"],["Sauce soja",3,"cs"],["Sauce hoisin",2,"cs"],["Ail",4,"gousses"],["Sucre",1,"cs"],["Poivre noir concassé",1,"cs"],["Laitue",1,"pièce"],["Tomates cerises",200,"g"],["Oignon rouge",1,"pièce"],["Vinaigre de riz",2,"cs"],["Huile d'arachide",4,"cs"]],et:"1. Marinade : soja + hoisin + ail + sucre + poivre 15 min.\n2. Préparer une salade composée de laitue + tomates cerises + oignon rouge tranché + vinaigrette légère.\n3. Chauffer wok très fort. Saisir le boeuf par très petites quantités (30-60 sec/face). Le 'shake' consiste à secouer le wok.\n4. Poivre noir concassé en abondance sur la viande.\n5. Servir immédiatement sur la salade froide - le contraste chaud/froid est la clé.",vin:"Bière 333 froide ou Hanoi Beer",notes:"Bò lúc lắc signifie boeuf 'shake' - le mouvement de secousse du wok est sa signature."},
{id:"VN004",co:"Asie",cat:"Plat",sous:"Riz",nom:"Cơm Tấm (Riz Brisé de Saigon)",chef:"Tradition de Ho Chi Minh-Ville",bp:4,prep:30,cui:20,diff:2,qual:4,ig:[["Riz brisé",400,"g"],["Côtes de porc marinées (sườn)",4,"pièces"],["Oeufs au plat",4,"pièces"],["Chả (pâté de porc cuit vapeur)",200,"g"],["Sauce de poisson",4,"cs"],["Sucre",2,"cs"],["Citron vert",2,"pièces"],["Concombre",1,"pièce"],["Oignons frits",2,"cs"]],et:"1. Marinade sườn : sauce de poisson + sucre + ail + citronnelle. Mariner les côtes 2h.\n2. Griller les côtes de porc marinées sur braise ou gril très chaud jusqu'à caramélisées.\n3. Cuire le riz brisé à l'eau comme du riz normal.\n4. Préparer la sauce nước chấm : nuoc-mâm + sucre + eau + citron + ail + piment.\n5. Assiette : riz brisé + côte de porc + chả tranché + oeuf au plat + concombre + oignons frits. Sauce à part.",vin:"Bière Saigon froide ou thé glacé",notes:"Le riz brisé (tấm) était historiquement le riz des pauvres. Devenu le déjeuner emblématique de Saigon servi à tous les carrefours."},
{id:"VN005",co:"Asie",cat:"Plat",sous:"Crêpe",nom:"Bánh Xèo (Crêpe Sizzling Vietnamienne)",chef:"Tradition du Centre et Sud Vietnam",bp:4,prep:20,cui:15,diff:2,qual:4,ig:[["Farine de riz",200,"g"],["Lait de coco",20,"cl"],["Eau froide",20,"cl"],["Curcuma",1,"cc"],["Crevettes décortiquées",200,"g"],["Porc en fines tranches",200,"g"],["Pousses de soja",150,"g"],["Oignons verts",3,"tiges"],["Salade laitue feuilles",1,"pièce"],["Herbes fraîches menthe basilic",1,"bouquet"]],et:"1. Pâte : farine de riz + lait de coco + eau + curcuma + sel. Laisser reposer 30 min.\n2. Dans poêle très chaude avec huile : saisir les crevettes + porc 1 min.\n3. Verser une fine louche de pâte. Incliner la poêle pour étaler.\n4. Couvrir 2 min. Découvrir, ajouter pousses de soja + oignons verts. Plier en demi-lune.\n5. Servir dans des feuilles de laitue avec herbes fraîches. Sauce nuoc-cham pour tremper.",vin:"Bière Tiger froide",notes:"Bánh xèo signifie 'crêpe qui fait sizzle' à cause du bruit de la pâte dans la poêle très chaude. Se mange enveloppé dans la salade."},
{id:"VN006",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Bún Riêu Cua (Soupe aux Crabes)",chef:"Tradition du Vietnam du Nord",bp:4,prep:30,cui:45,diff:3,qual:4,ig:[["Crabe d'eau douce en conserve ou chair",200,"g"],["Os de porc",600,"g"],["Tomates",4,"pièces"],["Concentré de tomate de tamarin",2,"cs"],["Pâte de crevettes mắm tôm",1,"cs"],["Oeufs",2,"pièces"],["Vermicelles de riz",300,"g"],["Pousses de soja coriandre oignon vert",1,"bouquet"],["Tige de citronnelle",2,"pièces"]],et:"1. Bouillon : os de porc + citronnelle dans 2L eau. Frémir 30 min. Filtrer.\n2. Mixer chair de crabe + oeufs battus + pâte de crevettes en mousse.\n3. Porter bouillon à frémissement doux. Y verser la mousse de crabe. Elle coagule en morceaux flottants.\n4. Ajouter tomates en quartiers + concentré de tamarin. Frémir 10 min.\n5. Vermicelles dans les bols. Bouillon + morceaux de crabe. Pousses de soja + herbes fraîches.",vin:"Bière 333 froide ou thé oolong",notes:"La mousse de crabe coagulée est l'élément distinctif de cette soupe. La pâte de crevettes (mắm tôm) est très pungente mais indispensable."},
{id:"VN007",co:"Asie",cat:"Plat",sous:"Soupe",nom:"Pho Ga (Soupe au Poulet Vietnamien)",chef:"Tradition d'Hanoi",bp:4,prep:15,cui:120,diff:2,qual:5,ig:[["Poulet entier",1500,"g"],["Oignons",2,"pièces"],["Gingembre frais",60,"g"],["Anis étoilé",3,"pièces"],["Cannelle bâton",1,"pièce"],["Clous de girofle",3,"pièces"],["Nuoc-mâm",4,"cs"],["Sucre",1,"cc"],["Nouilles de riz (banh pho)",400,"g"],["Coriandre menthe basilic thai",1,"bouquet"],["Oignons verts citron piment",1,"qs"]],et:"1. Torréfier oignons + gingembre entiers à sec au four 220°C 15 min jusqu'à noircis.\n2. Torréfier les épices quelques secondes.\n3. Bouillir poulet + oignons + gingembre + épices dans 3L eau. Écumer. Cuire 1h30 à frémissement.\n4. Retirer le poulet. Effilocher. Filtrer le bouillon. Assaisonner nuoc-mâm + sucre.\n5. Servir sur nouilles + poulet + herbes fraîches + lime + piment.",vin:"Thé jasmin ou bière Tiger",notes:"Le pho ga est plus délicat que le pho bo. Bouillon toujours à frémissement, jamais à ébullition."},
{id:"VN008",co:"Asie",cat:"Plat",sous:"Viande",nom:"Bo Kho (Ragoût de Boeuf au Gingembre)",chef:"Tradition vietnamienne",bp:4,prep:20,cui:120,diff:2,qual:4,ig:[["Boeuf à braiser en cubes",800,"g"],["Carottes",4,"pièces"],["Oignons",2,"pièces"],["Citronnelle",3,"tiges"],["Gingembre",30,"g"],["Nuoc-mâm",3,"cs"],["Sauce soja",2,"cs"],["Tomates concassées",200,"g"],["Anis étoilé",2,"pièces"],["Cannelle bâton",1,"pièce"],["Curry en poudre",1,"cs"],["Bouillon",70,"cl"]],et:"1. Mariner le boeuf avec gingembre + citronnelle écrasée + soja + curry + poivre 2h.\n2. Saisir la viande jusqu'à bien dorée. Réserver.\n3. Suer oignons + épices entières. Ajouter tomates.\n4. Remettre boeuf + bouillon. Mijoter 1h30. Ajouter carottes.\n5. Cuire encore 30 min. Rectifier nuoc-mâm. Servir avec baguettes de pain.",vin:"Bière 33 vietnamienne ou thé jasmin",notes:"Le bo kho se mange avec des baguettes de pain — héritage de la présence française en Indochine."},
{id:"VN009",co:"Asie",cat:"Entrée",sous:"Friture",nom:"Nem Ran (Nems Frits Vietnamiens)",chef:"Tradition vietnamienne",bp:4,prep:30,cui:10,diff:2,qual:5,ig:[["Galettes de riz (banh trang)",16,"pièces"],["Porc haché",300,"g"],["Crevettes hachées",200,"g"],["Vermicelles de riz",60,"g"],["Champignons noirs",20,"g"],["Carotte râpée",1,"pièce"],["Oignons",1,"pièce"],["Oeuf",1,"pièce"],["Nuoc-mâm",2,"cs"],["Sucre",1,"cc"],["Huile pour friture",1,"L"],["Nuoc-cham laitue herbes",1,"qs"]],et:"1. Réhydrater vermicelles 10 min. Hacher champignons réhydratés.\n2. Farce : porc + crevettes + vermicelles + champignons + carotte + oignon + oeuf + nuoc-mâm + sucre.\n3. Tremper galettes dans eau tiède une par une. Étaler sur torchon humide.\n4. Poser farce, plier les côtés, rouler serré.\n5. Frire à 160°C 5 min puis 180°C 2 min pour dorer. Servir dans feuilles de laitue + herbes + nuoc-cham.",vin:"Bière Saigon ou thé vert",notes:"La double friction (basse puis haute T°) donne un résultat parfaitement croustillant."},
{id:"VN010",co:"Asie",cat:"Plat",sous:"Poisson",nom:"Ca Kho To (Poisson Caramélisé en Clay Pot)",chef:"Tradition vietnamienne",bp:4,prep:15,cui:25,diff:2,qual:5,ig:[["Filets de poisson ferme",800,"g"],["Sucre roux",4,"cs"],["Eau",2,"cs"],["Nuoc-mâm",4,"cs"],["Eau de coco",20,"cl"],["Ail",4,"gousses"],["Échalotes",3,"pièces"],["Gingembre",20,"g"],["Piment",1,"pièce"],["Oignons verts",2,"tiges"],["Poivre noir",1,"cc"]],et:"1. Caramel : cuire sucre + eau jusqu'à ambré foncé dans pot en terre ou casserole épaisse.\n2. Ajouter ail + échalotes + gingembre. Cuire 1 min.\n3. Ajouter nuoc-mâm + eau de coco + piment. Frémir.\n4. Ajouter le poisson. Couvrir. Mijoter 15 min en arrosant.\n5. Découvrir 5 min pour réduire. Oignons verts + poivre abondant.",vin:"Thé chinois ou bière Tiger",notes:"Le caramel de poisson (kho) est la signature de la cuisine du Sud Vietnam."},
{id:"VN011",co:"Asie",cat:"Plat",sous:"Nouilles",nom:"Bun Cha (Porc Grillé aux Vermicelles)",chef:"Tradition hanoienne",bp:4,prep:30,cui:15,diff:2,qual:5,ig:[["Poitrine de porc",400,"g"],["Porc haché",300,"g"],["Vermicelles de riz",400,"g"],["Nuoc-mâm",6,"cs"],["Sucre",4,"cs"],["Vinaigre de riz",3,"cs"],["Jus de citron vert",3,"cs"],["Ail haché",6,"gousses"],["Piment",2,"pièces"],["Carottes julienne",2,"pièces"],["Daikon julienne",1,"pièce"],["Herbes fraîches laitue",1,"bouquet"]],et:"1. Marinade : 2cs nuoc-mâm + 1cs sucre + ail + poivre. Mariner porc tranché + boulettes de porc haché 2h.\n2. Sauce nuoc-cham : eau chaude + sucre + nuoc-mâm + lime + ail + piment. Refroidir.\n3. Pickles : carottes + daikon marinés dans vinaigre + sucre + sel 30 min.\n4. Griller porc et boulettes sur braise jusqu'à bien caramélisés.\n5. Bols : porc chaud + sauce tiède + vermicelles froids + herbes + pickles.",vin:"Bière Hanoi ou thé au lotus",notes:"Plat emblématique d'Hanoi popularisé mondialement par Obama et Anthony Bourdain en 2016."},
{id:"VN012",co:"Asie",cat:"Entrée",sous:"Rouleau",nom:"Goi Cuon (Rouleaux de Printemps Frais)",chef:"Tradition vietnamienne",bp:4,prep:30,cui:5,diff:2,qual:5,ig:[["Galettes de riz",16,"pièces"],["Crevettes cuites décortiquées",24,"pièces"],["Poitrine de porc cuite tranchée",200,"g"],["Vermicelles de riz cuits",200,"g"],["Laitue",1,"pièce"],["Menthe vietnamienne",1,"bouquet"],["Coriandre basilic thai",1,"bouquet"],["Carottes ciboule julienne",1,"qs"],["Beurre de cacahuète",3,"cs"],["Sauce hoisin citron vert",1,"qs"]],et:"1. Tremper chaque galette de riz 10 sec dans eau tiède. Poser sur torchon humide.\n2. Disposer laitue + vermicelles + porc + herbes + carottes sur le tiers inférieur.\n3. Commencer à rouler. Ajouter 3 crevettes (côté rose vers l'extérieur).\n4. Plier les côtés vers l'intérieur. Finir de rouler serré.\n5. Sauce : beurre de cacahuète + hoisin + lime + piment + eau.",vin:"Thé jasmin ou bière 33",notes:"Les crevettes roses visibles à travers la galette transparente — c'est l'esthétique classique."},
{id:"VN013",co:"Asie",cat:"Plat",sous:"Volaille",nom:"Ga Xao Sa Ot (Poulet Sauté à la Citronnelle)",chef:"Tradition vietnamienne",bp:4,prep:15,cui:10,diff:1,qual:4,ig:[["Cuisses de poulet désossées",700,"g"],["Citronnelle",4,"tiges"],["Ail",5,"gousses"],["Oignons",1,"pièce"],["Piment rouge",2,"pièces"],["Nuoc-mâm",3,"cs"],["Sauce soja",1,"cs"],["Sucre",1,"cs"],["Huile",3,"cs"],["Coriandre cacahuètes concassées",1,"qs"]],et:"1. Couper poulet en cubes. Émincer finement le coeur blanc de la citronnelle + ail + piment.\n2. Mariner poulet avec moitié citronnelle + ail + nuoc-mâm + sucre + poivre 30 min.\n3. Chauffer huile à vif. Faire revenir oignon émincé.\n4. Ajouter poulet mariné. Sauter 6-7 min jusqu'à caramélisé.\n5. Ajouter reste citronnelle + piment + soja. Sauter 2 min. Coriandre + cacahuètes.",vin:"Bière vietnamienne ou thé glacé",notes:"Seule la partie blanche de la citronnelle est utilisée. Les parties dures parfument les bouillons."},
{id:"VN014",co:"Asie",cat:"Dessert",sous:"Entremets",nom:"Che Chuoi (Bananes au Lait de Coco)",chef:"Tradition vietnamienne",bp:4,prep:5,cui:15,diff:1,qual:4,ig:[["Bananes mûres",6,"pièces"],["Lait de coco",40,"cl"],["Perles de tapioca",60,"g"],["Sucre de coco",3,"cs"],["Sel",1,"pincée"],["Graines de sésame grillées",1,"cs"],["Cacahuètes concassées",2,"cs"]],et:"1. Cuire tapioca dans eau bouillante 10 min jusqu'à translucide. Rincer.\n2. Dans casserole : lait de coco + 20cl eau + sucre + sel. Porter à frémissement.\n3. Ajouter bananes en rondelles épaisses. Cuire 5 min sans trop mélanger.\n4. Ajouter tapioca. Cuire encore 3 min.\n5. Servir tiède ou chaud. Parsemer sésame + cacahuètes.",vin:"Café vietnamien glacé au lait concentré",notes:"Le che est la famille des desserts vietnamiens — sucrés, à base de lait de coco et féculents."},
{id:"VN015",co:"Asie",cat:"Plat",sous:"Crevettes",nom:"Tom Rang Me (Crevettes au Tamarin)",chef:"Tradition vietnamienne",bp:4,prep:15,cui:10,diff:2,qual:4,ig:[["Crevettes entières avec tête",600,"g"],["Pâte de tamarin",4,"cs"],["Eau chaude",10,"cl"],["Sucre roux",3,"cs"],["Nuoc-mâm",2,"cs"],["Ail",4,"gousses"],["Piment",1,"pièce"],["Huile",3,"cs"],["Coriandre",1,"bouquet"]],et:"1. Diluer pâte de tamarin dans eau chaude. Filtrer pour éliminer noyaux.\n2. Sauce : jus tamarin + sucre + nuoc-mâm + ail haché + piment.\n3. Chauffer huile à vif. Frire crevettes entières 2 min de chaque côté.\n4. Verser la sauce. Enrober 2 min jusqu'à caramélisation brillante.\n5. Coriandre. Manger avec les mains en suçant les têtes.",vin:"Bière vietnamienne ou limonade",notes:"Les têtes de crevettes sont la partie savoureuse — les sucer est un rituel en Vietnam."},
{id:"VN016",co:"Asie",cat:"Accompagnement",sous:"Légumes",nom:"Aubergines Sautées Vietnamiennes",chef:"Tradition vietnamienne",bp:4,prep:10,cui:20,diff:1,qual:4,ig:[["Aubergines longues asiatiques",4,"pièces"],["Tomates",3,"pièces"],["Oignons",1,"pièce"],["Ail",3,"gousses"],["Nuoc-mâm",2,"cs"],["Sucre",1,"cc"],["Huile",3,"cs"],["Coriandre basilic thai",1,"bouquet"],["Piment",1,"pièce"]],et:"1. Couper aubergines en tronçons. Saler 20 min. Presser l'eau.\n2. Saisir aubergines dans huile chaude jusqu'à dorées. Réserver.\n3. Faire revenir ail + oignon + piment. Ajouter tomates.\n4. Remettre aubergines + nuoc-mâm + sucre. Mijoter 10 min.\n5. Herbes fraîches. Servir tiède ou froid avec riz.",vin:"Accompagnement de plats grillés ou mijotés",notes:"Les aubergines longues asiatiques sont plus tendres et moins amères que les aubergines européennes."},
{id:"VN017",co:"Asie",cat:"Sauce / Base",sous:"Sauce",nom:"Nuoc Cham (Sauce Universelle Vietnamienne)",chef:"Tradition vietnamienne",bp:6,prep:5,cui:0,diff:1,qual:5,ig:[["Nuoc-mâm (sauce de poisson)",6,"cs"],["Jus de citron vert",4,"cs"],["Sucre",3,"cs"],["Eau tiède",6,"cs"],["Ail haché très fin",3,"gousses"],["Piment haché",2,"pièces"],["Carotte râpée fine",2,"cs"]],et:"1. Dissoudre le sucre dans l'eau tiède.\n2. Ajouter nuoc-mâm + jus de citron vert.\n3. Ajouter ail + piment hachés très finement.\n4. Ajouter carotte râpée.\n5. Laisser reposer 15 min. Se conserve 3 jours au froid.",vin:"Usage : nems, rouleaux de printemps, bun cha, poissons grillés",notes:"La sauce universelle vietnamienne. L'équilibre acide-sucré-salé-piquant doit être parfait."},
{id:"VN018",co:"Asie",cat:"Entrée",sous:"Soupe",nom:"Hu Tieu (Soupe de Nouilles du Sud Vietnam)",chef:"Tradition du Sud Vietnam",bp:4,prep:15,cui:60,diff:2,qual:4,ig:[["Nouilles de tapioca ou riz",400,"g"],["Porc en lamelles",200,"g"],["Crevettes",200,"g"],["Os de porc",500,"g"],["Radis daikon",300,"g"],["Calmars",150,"g"],["Nuoc-mâm",3,"cs"],["Sucre",1,"cc"],["Ciboulette pousses de soja citron vert",1,"qs"],["Échalotes frites",2,"cs"]],et:"1. Bouillon : os de porc + daikon dans 2L eau. Frémir 1h. Filtrer. Assaisonner.\n2. Cuire porc 10 min dans bouillon. Réserver. Trancher.\n3. Saisir crevettes + calmars dans bouillon. Réserver.\n4. Cuire nouilles. Égoutter.\n5. Bols : nouilles + porc + crevettes + calmars. Verser bouillon bouillant. Pousses de soja + herbes + échalotes frites.",vin:"Thé vert glacé ou bière Saigon",notes:"Le hu tieu est la version du Sud (tapioca) du pho du Nord. Plus léger, plus marin, plus sucré."}
);
